window.questionBanks = {
legendary:[
{id:9000,sourceGame:"nationalEngine",q:"GDP rises from 5000 to 5600, while real GDP rises from 5000 to 5250. Which memo best reads the signal?",options:["Output rose, but much of GDP growth came from prices","Output rose by 12%, with no price pressure","Prices rose, but output was unchanged","GDP rose only because imports increased"],a:0,tag:"real_nominal_gdp",type:"multi-step",objective:"LO2.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"real_vs_nominal_gdp",secondarySkills:["gdp_deflator_inflation"],repairSkill:"real_vs_nominal_gdp",commonError:"reads_nominal_growth_as_real_growth",feedback:"Nominal GDP rose 12%, while real GDP rose 5%, so output increased but prices explain much of the nominal gain."},
{id:9001,sourceGame:"nationalEngine",q:"A country imports 200 more consumer goods, so C rises by 200 and imports rise by 200. At the same time, domestic investment falls by 50. What happens to GDP?",options:["GDP falls by 50 because imports offset the consumption gain and investment falls","GDP rises by 150 because consumption rises more than investment falls","GDP is unchanged because imports always cancel all spending changes","GDP rises by 200 because consumption is the largest GDP component"],a:0,tag:"gdp_components",type:"multi-step",objective:"LO2.1",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"gdp_components_identity",secondarySkills:["gdp_inclusion_exclusion"],repairSkill:"gdp_components_identity",commonError:"forgets_import_offset_and_investment_change",feedback:"The imported-goods purchase raises C by 200 but lowers NX by 200, so that part cancels. Investment falls by 50, so GDP falls by 50."},
{id:9002,sourceGame:"nationalEngine",q:"An economy has 400 employed, 40 unemployed, and 160 out of the labor force. Then 20 unemployed workers stop searching. What happens to U-3?",options:["It falls from 9.1% to 4.8%","It rises from 9.1% to 10.0%","It stays at 9.1%","It falls from 6.7% to 3.3%"],a:0,tag:"unemployment_rate",type:"multi-step",objective:"LO2.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"labor_force_statistics_calculation",secondarySkills:["employment_status_classification"],repairSkill:"labor_force_statistics_calculation",commonError:"keeps_discouraged_workers_in_labor_force",feedback:"Initial U-3 is 40/440 = 9.1%. After 20 stop searching, unemployed = 20 and labor force = 420, so U-3 = 4.8%."},
{id:9003,sourceGame:"nationalEngine",q:"A CPI basket costs 240 in the base year, 300 last year, and 330 this year. If wages rose 8% this year, what happened to real wages using CPI inflation?",options:["Real wages fell because inflation was 10%","Real wages rose because inflation was 8%","Real wages were unchanged because CPI rose by 8%","Real wages fell because inflation was 37.5%"],a:0,tag:"cpi",type:"multi-step",objective:"LO2.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"cpi_inflation_calculation",secondarySkills:["real_vs_nominal_gdp"],repairSkill:"cpi_inflation_calculation",commonError:"compares_current_cost_to_base_year_or_ignores_real_wage",feedback:"Last year’s CPI was 125 and this year’s CPI is 137.5, so inflation is 10%. Nominal wages rose 8%, so real wages fell."},
{id:9004,sourceGame:"nationalEngine",q:"Nominal GDP is 9200, real GDP is 8000, and last year’s deflator was 110. If real GDP grew 2%, which memo is strongest?",options:["Output rose, but GDP-deflator inflation was about 4.5%","Output was unchanged, and inflation was about 15%","Output rose 15%, and inflation was about 4.5%","Output fell because the deflator rose from 110 to 115"],a:0,tag:"gdp_deflator",type:"multi-step",objective:"LO2.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"gdp_deflator_inflation",secondarySkills:["real_vs_nominal_gdp"],repairSkill:"gdp_deflator_inflation",commonError:"uses_deflator_level_as_inflation_rate_or_ignores_real_growth",feedback:"The current deflator is 100×9200/8000 = 115. Deflator inflation is (115 - 110)/110 = 4.5%. Real GDP growth tells us output rose."},
{id:9005,sourceGame:"nationalEngine",q:"A domestic firm produces machines, sells half to firms, stores the rest as inventory, and later sells one used machine from last year. Which treatment is right?",options:["New machines and inventory count as investment; the used-machine resale does not count as new output","Only the machines sold to firms count because inventories are not final goods","All machine sales count because every transaction happens this year","Only the used-machine resale counts because it is the current transaction"],a:0,tag:"gdp_components",type:"trap",objective:"LO2.1",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"gdp_inclusion_exclusion",secondarySkills:["gdp_components_identity"],repairSkill:"gdp_inclusion_exclusion",commonError:"excludes_inventory_or_counts_used_goods",feedback:"New capital goods count as investment, and unsold current production counts as inventory investment. Used goods were produced earlier, so their resale is not new output."},
{id:9006,sourceGame:"nationalEngine",q:"A production function is Y = A K^0.4 L^0.5. Technology rises 3%, K rises 5%, and L rises 4%. Approximate output growth is what?",options:["7.0%","9.0%","12.0%","4.5%"],a:0,tag:"production_function",type:"multi-step",objective:"LO3.1",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"production_function_output",secondarySkills:["returns_to_scale_classification"],repairSkill:"production_function_output",commonError:"adds_input_growth_without_weights",feedback:"Growth is about 3% + 0.4(5%) + 0.5(4%) = 7%."},
{id:9007,sourceGame:"nationalEngine",q:"A model has fixed K, fixed L, and fixed A. Government spending rises by 300. What should the Chapter 3 advisor say?",options:["Output stays fixed; investment is crowded out","Output rises by 300; investment is unchanged","Output falls by 300; saving rises","Output rises only if CPI rises"],a:0,tag:"production",type:"trap",objective:"LO3.1",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"production_function_output",secondarySkills:["fiscal_policy_crowding_out"],repairSkill:"production_function_output",commonError:"imports_multiplier_logic_into_fixed_output_model",feedback:"In Chapter 3, output is fixed by K, L, and A. Higher G reduces saving and crowds out investment."},
{id:9008,sourceGame:"nationalEngine",q:"A production function has Y = A K^0.7 L^0.2. If K and L both double while A is unchanged, what happens to output and why?",options:["Output rises by less than double because exponents sum to 0.9","Output exactly doubles because both inputs doubled","Output more than doubles because capital has exponent 0.7","Output does not change because technology is unchanged"],a:0,tag:"returns_to_scale",type:"multi-step",objective:"LO3.1",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"returns_to_scale_classification",secondarySkills:["production_function_output"],repairSkill:"returns_to_scale_classification",commonError:"does_not_sum_exponents_or_confuses_input_doubling",feedback:"The exponents sum to 0.9, so the function has decreasing returns to scale. Doubling both inputs raises output by less than double."},
{id:9009,sourceGame:"nationalEngine",q:"Output is fixed by production. Taxes fall, MPC is 0.8, and G is fixed. What happens to demand composition?",options:["C rises, saving falls, and investment is pressured down","C falls, saving rises, and investment rises","C rises, output rises, and investment is unchanged","C is unchanged, saving falls, and output rises"],a:0,tag:"production",type:"integration",objective:"LO3.1",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"production_function_output",secondarySkills:["mpc_disposable_income","saving_identity_calculation"],repairSkill:"production_function_output",commonError:"treats_tax_cut_as_output_expansion_in_fixed_output_model",feedback:"With output fixed, a tax cut raises consumption, lowers national saving, raises r, and pressures investment down."},
{id:9010,sourceGame:"nationalEngine",q:"A firm’s MPL schedule is 30, 24, 18, 12, 6. Price is $4 and wage is $60. How many workers are hired?",options:["3","2","4","5"],a:0,tag:"labor_demand",type:"calculation",objective:"LO3.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"uses_nominal_wage_instead_of_real_wage",feedback:"The real wage is 60/4 = 15. The first three workers have MPL above 15; the fourth has 12."},
{id:9011,sourceGame:"nationalEngine",q:"Output rises from 0 to 15 to 29 to 40 to 48 to 51. If W/P = 9, how many workers should be hired?",options:["3","4","5","2"],a:0,tag:"labor_demand",type:"multi-step",objective:"LO3.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"total_product_to_marginal_product",secondarySkills:["labor_demand_mpl_real_wage"],repairSkill:"total_product_to_marginal_product",commonError:"uses_total_product_levels_not_marginal_product",feedback:"MPL values are 15, 14, 11, 8, and 3. The firm hires the first three workers and stops before the fourth because MPL falls below W/P.",image:"totalproduct.webp"},
{id:9012,sourceGame:"nationalEngine",q:"Capital falls after a shock while labor is fixed. Which factor-price pattern is most likely?",options:["MPK rises and MPL falls","MPK falls and MPL rises","Both MPK and MPL rise","Both MPK and MPL fall"],a:0,tag:"factor_prices",type:"integration",objective:"LO3.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"diminishing_marginal_product",secondarySkills:["labor_demand_mpl_real_wage"],repairSkill:"diminishing_marginal_product",commonError:"misses_cross_factor_effect",feedback:"Scarcer capital raises MPK, but less capital per worker lowers labor productivity and MPL."},
{id:9013,sourceGame:"nationalEngine",q:"Refer to the marginal product graph. A real wage increase plus better technology affects labor demand how?",options:["Quantity effect is ambiguous because wage and MPL shift conflict","Labor demand must rise because technology improves","Labor demand must fall because wages rise","Labor demand is fixed by the CPI"],a:0,tag:"labor_demand",type:"graph_integration",objective:"LO3.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:["diminishing_marginal_product"],repairSkill:"labor_demand_mpl_real_wage",commonError:"ignores_offsetting_wage_and_productivity_effects",feedback:"Higher technology shifts MPL up, but a higher real wage moves the firm toward less labor. The net quantity effect is ambiguous.",image:"marginalproduct.webp"},
{id:9014,sourceGame:"nationalEngine",q:"A worker’s nominal wage rises 10%, output price rises 15%, and MPL is unchanged. What happens to the firm’s hiring incentive?",options:["Hiring becomes more attractive because the real wage falls","Hiring becomes less attractive because the nominal wage rises","Hiring is unchanged because MPL is unchanged","Hiring stops because inflation is positive"],a:0,tag:"factor_prices",type:"trap",objective:"LO3.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"looks_only_at_nominal_wage",feedback:"The price level rose faster than the wage, so W/P falls and hiring becomes more attractive at unchanged MPL."},
{id:9015,sourceGame:"nationalEngine",q:"Labor increases while capital is fixed. In Cobb-Douglas logic, what happens to MPL, MPK, and real wages?",options:["MPL falls, MPK rises, real wages fall","MPL rises, MPK falls, real wages rise","MPL falls, MPK falls, real wages rise","MPL rises, MPK rises, real wages fall"],a:0,tag:"factor_prices",type:"integration",objective:"LO3.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"diminishing_marginal_product",secondarySkills:["factor_income_distribution"],repairSkill:"diminishing_marginal_product",commonError:"misses_cross_productivity_effect",feedback:"More labor lowers MPL and the real wage, but raises MPK because capital is used with more labor."},
{id:9016,sourceGame:"nationalEngine",q:"If alpha = 0.35, technology grows 2%, capital grows 6%, and labor grows 2%, approximate output growth is what?",options:["5.4%","4.6%","6.0%","8.0%"],a:0,tag:"cobb_douglas",type:"multi-step",objective:"LO3.3",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:["production_function_output"],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"misweights_capital_and_labor_growth",feedback:"Growth is about 2% + 0.35(6%) + 0.65(2%) = 2 + 2.1 + 1.3 = 5.4%."},
{id:9017,sourceGame:"nationalEngine",q:"In a Cobb-Douglas economy, alpha = 0.4, total income is 9000, and output rises to 9900 with alpha unchanged. What are the initial labor income and the increase in capital income?",options:["Labor income 5400; capital income rises 360","Labor income 3600; capital income rises 540","Labor income 5400; capital income rises 900","Labor income 3600; capital income rises 360"],a:0,tag:"factor_shares",type:"multi-step",objective:"LO3.3",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:["factor_income_distribution"],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"reverses_alpha_and_one_minus_alpha_or_uses_total_output_change",feedback:"Initial labor income is 0.6×9000 = 5400. Output rises by 900, and capital receives 40%, so capital income rises by 360."},
{id:9018,sourceGame:"nationalEngine",q:"Technology raises output, but capital’s income share also rises. Which critique fits the basic Cobb-Douglas benchmark?",options:["Stable factor shares may fail when technology favors capital","Technology cannot affect income distribution","Capital share must fall when output rises","Labor always receives all productivity gains"],a:0,tag:"income_distribution",type:"policy",objective:"LO3.3",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"factor_income_distribution",secondarySkills:["cobb_douglas_factor_share_calculation"],repairSkill:"factor_income_distribution",commonError:"treats_cobb_douglas_as_literal_always_true",feedback:"Basic Cobb-Douglas gives stable shares, but capital-biased technology can push capital’s actual share upward."},
{id:9019,sourceGame:"nationalEngine",q:"Factors are paid marginal products under constant returns, but accounting profit is positive. Which explanation best preserves the theory?",options:["Accounting profit may include returns to owner-supplied capital","Economic profit must be positive because accounting profit is positive","Labor must receive less than its marginal product in every case","The GDP deflator must be rising faster than real GDP"],a:0,tag:"income_distribution",type:"trap",objective:"LO3.3",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"factor_income_distribution",secondarySkills:[],repairSkill:"factor_income_distribution",commonError:"confuses_accounting_profit_with_economic_profit",feedback:"Accounting profit can include the return to capital owned by the firm’s owners. That does not mean pure economic profit is positive."},
{id:9020,sourceGame:"nationalEngine",q:"Alpha is 0.25. Capital rises 8%, labor falls 4%, and technology rises 3%. Approximate output growth is what?",options:["2.0%","4.0%","6.0%","0.0%"],a:0,tag:"cobb_douglas",type:"multi-step",objective:"LO3.3",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:["production_function_output"],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"ignores_negative_labor_growth",feedback:"Growth is 3% + 0.25(8%) + 0.75(-4%) = 3 + 2 - 3 = 2%."},
{id:9021,sourceGame:"nationalEngine",q:"C = 400 + 0.75(Y - T), Y = 5000, T = 1000, and G = 1200. What are C and national saving?",options:["C = 3400; S = 400","C = 3400; S = 1600","C = 4150; S = -350","C = 3000; S = 800"],a:0,tag:"consumption_function",type:"multi-step",objective:"LO3.4",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"consumption_function_calculation",secondarySkills:["saving_identity_calculation"],repairSkill:"consumption_function_calculation",commonError:"mixes_private_and_national_saving",feedback:"Disposable income is 4000, so C = 400 + 0.75(4000) = 3400. National saving = Y - C - G = 400."},
{id:9022,sourceGame:"nationalEngine",q:"A tax cut of 200 occurs with MPC = 0.6, Y and G fixed. What happens to consumption and national saving?",options:["C rises 120; S falls 120","C rises 80; S falls 80","C rises 200; S unchanged","C falls 120; S rises 120"],a:0,tag:"consumption",type:"multi-step",objective:"LO3.4",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"mpc_disposable_income",secondarySkills:["saving_identity_calculation"],repairSkill:"mpc_disposable_income",commonError:"uses_mps_or_public_saving_only",feedback:"A 200 tax cut raises disposable income by 200, consumption by 120, and lowers national saving by 120."},
{id:9023,sourceGame:"nationalEngine",q:"Refer to the consumption function graph. Wealth falls while taxes also fall. What is the net effect on consumption?",options:["Ambiguous because wealth shifts down and taxes raise disposable income","Consumption must rise because taxes fall","Consumption must fall because wealth falls","Consumption is fixed because Y is fixed"],a:0,tag:"consumption_function",type:"graph_integration",objective:"LO3.4",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"consumption_movement_vs_shift",secondarySkills:["mpc_disposable_income"],repairSkill:"consumption_movement_vs_shift",commonError:"ignores_offsetting_shift_and_movement",feedback:"Lower wealth shifts consumption down, while lower taxes raise disposable income and move along the function. Net effect is ambiguous.",image:"consumptionfunction.webp"},
{id:9024,sourceGame:"nationalEngine",q:"Nominal interest is 11%, inflation is 4%, and I = 3200 - 200r. If expected profits then shift investment demand down by 300, what is investment?",options:["1500","1800","2100","1000"],a:0,tag:"investment",type:"multi-step",objective:"LO3.4",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"real_interest_investment_calculation",secondarySkills:["investment_function_movement_vs_shift"],repairSkill:"real_interest_investment_calculation",commonError:"uses_nominal_rate_or_ignores_investment_shift",feedback:"Real r = 11 - 4 = 7. Baseline investment is 3200 - 200(7) = 1800. The negative demand shift lowers investment to 1500."},
{id:9025,sourceGame:"nationalEngine",q:"Refer to the investment function graph. Expected profits rise while r rises. What must be true?",options:["The effect on investment depends on relative sizes","Investment must rise because the curve shifts right","Investment must fall because r rises","Investment must stay fixed by saving"],a:0,tag:"investment_function",type:"graph_integration",objective:"LO3.4",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"investment_function_movement_vs_shift",secondarySkills:[],repairSkill:"investment_function_movement_vs_shift",commonError:"ignores_offsetting_shift_and_movement",feedback:"Expected profits shift investment demand right, but a higher real interest rate reduces investment along the curve. Net effect is ambiguous.",image:"investmentfunction.webp"},
{id:9026,sourceGame:"nationalEngine",q:"Investment is I = 2600 - 100r. Nominal r stays 8%, inflation rises from 2% to 5%. What happens to investment?",options:["It rises by 300","It falls by 300","It rises by 600","It is unchanged"],a:0,tag:"investment",type:"multi-step",objective:"LO3.4",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"real_interest_investment_calculation",secondarySkills:[],repairSkill:"real_interest_investment_calculation",commonError:"misses_real_rate_decline",feedback:"Real r falls from 6 to 3, so investment rises from 2000 to 2300."},
{id:9027,sourceGame:"nationalEngine",q:"Refer to the investment graph. A move from I1 at high r to I2 at low r means what combined forces occurred?",options:["Investment demand rose and the real interest rate fell","Investment demand fell and the real interest rate rose","Only expected profits changed","Only the real interest rate changed"],a:0,tag:"investment_function",type:"graph_interpretation",objective:"LO3.4",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"investment_function_movement_vs_shift",secondarySkills:[],repairSkill:"investment_function_movement_vs_shift",commonError:"sees_shift_or_movement_but_not_both",feedback:"Moving from I1 to I2 means investment demand increased, while the move to lower r means borrowing costs fell.",image:"investmentfunction.webp"},
{id:9028,sourceGame:"nationalEngine",q:"Y = 8000, C = 5200, G = 2100, and T = 1800. What are private saving, public saving, and national saving?",options:["1000, -300, 700","700, -300, 1000","1000, 300, 1300","2800, -300, 2500"],a:0,tag:"national_saving",type:"multi-step",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"saving_identity_calculation",secondarySkills:[],repairSkill:"saving_identity_calculation",commonError:"reverses_private_public_saving",feedback:"Private saving = 8000 - 1800 - 5200 = 1000. Public saving = 1800 - 2100 = -300. National saving = 700."},
{id:9029,sourceGame:"nationalEngine",q:"A balanced-budget increase raises G and T by 400. MPC = 0.75 and Y is fixed. What happens to national saving?",options:["It falls by 100","It rises by 100","It is unchanged","It falls by 400"],a:0,tag:"fiscal_policy",type:"multi-step",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"fiscal_policy_crowding_out",secondarySkills:["mpc_disposable_income"],repairSkill:"fiscal_policy_crowding_out",commonError:"assumes_balanced_budget_means_no_saving_change",feedback:"Higher G lowers S by 400, while higher T lowers C by 300, raising S by 300. Net S falls by 100."},
{id:9030,sourceGame:"nationalEngine",q:"A tax cut of 500 has MPC = 0.8. What happens to private saving, public saving, and national saving?",options:["Private +100; public -500; national -400","Private +400; public -500; national -100","Private -100; public +500; national +400","Private +500; public -400; national +100"],a:0,tag:"national_saving",type:"multi-step",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"saving_identity_calculation",secondarySkills:["fiscal_policy_crowding_out"],repairSkill:"saving_identity_calculation",commonError:"looks_only_at_private_saving",feedback:"Disposable income rises 500, C rises 400, so private saving rises 100. Public saving falls 500. National saving falls 400."},
{id:9031,sourceGame:"nationalEngine",q:"Refer to loanable funds. Saving shifts left and investment demand shifts right. What is guaranteed?",options:["The real interest rate rises","Investment rises","Investment falls","The real interest rate falls"],a:0,tag:"loanable_funds",type:"graph_integration",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"loanable_funds_graph_shifts",secondarySkills:["investment_demand_vs_saving_shift"],repairSkill:"loanable_funds_graph_shifts",commonError:"claims_quantity_effect_when_ambiguous",feedback:"Both lower saving and higher investment demand push the real interest rate upward. Investment quantity is ambiguous.",image:"loanablefunds.webp"},
{id:9032,sourceGame:"nationalEngine",q:"Refer to loanable funds. Saving shifts right and investment demand shifts left. What is guaranteed?",options:["The real interest rate falls","Investment rises","Investment falls","The real interest rate rises"],a:0,tag:"loanable_funds",type:"graph_integration",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"loanable_funds_graph_shifts",secondarySkills:["investment_demand_vs_saving_shift"],repairSkill:"loanable_funds_graph_shifts",commonError:"claims_quantity_effect_when_ambiguous",feedback:"Higher saving lowers r, and lower investment demand also lowers r. Investment quantity is ambiguous.",image:"loanablefunds.webp"},
{id:9033,sourceGame:"nationalEngine",q:"Refer to loanable funds. Saving shifts right and investment demand shifts right. What is guaranteed?",options:["Investment rises","The real interest rate rises","The real interest rate falls","Investment falls"],a:0,tag:"loanable_funds",type:"graph_integration",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"loanable_funds_graph_shifts",secondarySkills:["investment_demand_vs_saving_shift"],repairSkill:"loanable_funds_graph_shifts",commonError:"claims_interest_rate_effect_when_ambiguous",feedback:"Both higher saving and higher investment demand raise equilibrium investment. The interest-rate effect is ambiguous.",image:"loanablefunds.webp"},
{id:9034,sourceGame:"nationalEngine",q:"National saving is fixed at 1000. Investment demand is I = 1800 - 100r. What is equilibrium r?",options:["8","10","6","18"],a:0,tag:"loanable_funds",type:"calculation",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"saving_investment_equilibrium",secondarySkills:["real_interest_investment_calculation"],repairSkill:"saving_investment_equilibrium",commonError:"does_not_set_s_equal_to_i",feedback:"Set 1000 = 1800 - 100r. Then 100r = 800, so r = 8."},
{id:9035,sourceGame:"nationalEngine",q:"Saving rises from 900 to 1100. Investment demand is I = 1700 - 100r. What happens to r?",options:["It falls from 8 to 6","It rises from 6 to 8","It falls from 9 to 7","It stays at 8"],a:0,tag:"loanable_funds",type:"calculation",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"saving_investment_equilibrium",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"saving_investment_equilibrium",commonError:"gets_saving_effect_on_r_backward",feedback:"At S = 900, r = 8. At S = 1100, r = 6. Higher saving lowers r."},
{id:9036,sourceGame:"nationalEngine",q:"Investment demand rises after a productivity boom, but saving is vertical and fixed. Which policy would let investment actually rise more?",options:["Raise national saving","Cut national saving","Raise consumption at every income","Increase the deficit"],a:0,tag:"loanable_funds",type:"policy",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"investment_demand_vs_saving_shift",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"investment_demand_vs_saving_shift",commonError:"misses_saving_constraint",feedback:"If saving is fixed, higher investment demand mostly raises r. More national saving shifts funds outward and allows more investment."},
{id:9037,sourceGame:"nationalEngine",q:"A deficit raises r and lowers investment. Why is the long-run concern not mainly current GDP in Chapter 3?",options:["Lower investment reduces future capital accumulation","Current GDP must fall immediately","CPI must rise faster than GDP","Unemployment must equal the natural rate"],a:0,tag:"crowding_out",type:"policy",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"fiscal_policy_crowding_out",secondarySkills:["production_function_output"],repairSkill:"fiscal_policy_crowding_out",commonError:"misses_future_capital_channel",feedback:"Output is fixed in the current Chapter 3 model, but lower investment can reduce future capital and future output."},
{id:9038,sourceGame:"nationalEngine",q:"Actual unemployment is 8.4%. Frictional is 2.1%, structural is 3.7%. A matching reform lowers frictional unemployment by 0.6 point. What is the new natural rate?",options:["5.2%","5.8%","2.0%","8.4%"],a:0,tag:"natural_rate",type:"multi-step",objective:"LO7.1",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"natural_rate_definition",secondarySkills:["sectoral_shift_matching"],repairSkill:"natural_rate_definition",commonError:"uses_actual_unemployment_or_forgets_natural_rate_components",feedback:"The original natural rate is 2.1 + 3.7 = 5.8%. Lowering frictional unemployment by 0.6 makes the new natural rate 5.2%."},
{id:9039,sourceGame:"nationalEngine",q:"Actual unemployment falls below the natural rate after a demand boom. Which claim is weakest?",options:["The natural rate has permanently fallen","The economy may be temporarily hot","Cyclical unemployment may be negative","Frictional unemployment still exists"],a:0,tag:"natural_rate",type:"trap",objective:"LO7.1",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"confuses_actual_unemployment_with_natural_rate",feedback:"Actual unemployment below the natural rate does not prove the natural rate has permanently changed."},
{id:9040,sourceGame:"nationalEngine",q:"A policy improves matching, reduces wage rigidity, and leaves aggregate demand unchanged. Which memo best explains the likely unemployment effect?",options:["The natural rate falls because frictional and structural unemployment fall","Only cyclical unemployment falls because aggregate demand is unchanged","The natural rate rises because any labor-market reform raises separations","Unemployment cannot change because GDP measurement rules are fixed"],a:0,tag:"natural_rate",type:"policy",objective:"LO7.1",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"natural_rate_definition",secondarySkills:["frictional_vs_other_unemployment"],repairSkill:"natural_rate_definition",commonError:"misses_natural_rate_components_or_confuses_demand_policy",feedback:"Better matching lowers frictional unemployment, and less wage rigidity lowers structural unemployment. Both reduce the natural rate."},
{id:9041,sourceGame:"nationalEngine",q:"If s = 0.06 and f = 0.24, steady-state unemployment is 20%. If f rises to 0.34 while s stays fixed, what happens?",options:["It falls to 15%","It rises to 25%","It stays at 20%","It falls to 6%"],a:0,tag:"steady_state_unemployment",type:"multi-step",objective:"LO7.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"steady_state_unemployment_calculation",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"steady_state_unemployment_calculation",commonError:"gets_finding_rate_effect_backward_or_uses_s_as_rate",feedback:"New steady-state unemployment is 0.06/(0.06+0.34) = 0.15, or 15%. A higher job-finding rate lowers unemployment."},
{id:9042,sourceGame:"nationalEngine",q:"Steady-state unemployment is 10% and f = 0.45. What is s?",options:["0.05","0.10","0.40","0.45"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"steady_state_unemployment_calculation",secondarySkills:[],repairSkill:"steady_state_unemployment_calculation",commonError:"cannot_solve_for_s",feedback:"Using s = uf/(1-u), s = 0.10×0.45/0.90 = 0.05."},
{id:9043,sourceGame:"nationalEngine",q:"A policy raises f from 0.20 to 0.30 and raises s from 0.04 to 0.06. What happens to steady-state unemployment?",options:["It stays at 16.7%","It rises from 16.7% to 20.0%","It falls from 20.0% to 16.7%","It rises from 4.0% to 6.0%"],a:0,tag:"steady_state_unemployment",type:"multi-step",objective:"LO7.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"job_finding_job_separation_logic",secondarySkills:["steady_state_unemployment_calculation"],repairSkill:"job_finding_job_separation_logic",commonError:"focuses_on_one_flow_rate_only",feedback:"Initial u = 0.04/0.24 = 16.7%. New u = 0.06/0.36 = 16.7%. Both rates rose proportionally."},
{id:9044,sourceGame:"nationalEngine",q:"If s falls from 0.05 to 0.03 and f falls from 0.25 to 0.15, what happens to steady-state unemployment?",options:["It stays at 16.7% but turnover slows","It falls to 10.0% and turnover slows","It rises to 20.0% and turnover speeds up","It stays at 16.7% but turnover speeds up"],a:0,tag:"steady_state_unemployment",type:"multi-step",objective:"LO7.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"job_finding_job_separation_logic",secondarySkills:["steady_state_unemployment_calculation"],repairSkill:"job_finding_job_separation_logic",commonError:"ignores_flow_speed_vs_rate_ratio",feedback:"Both rates fall proportionally, so u stays 16.7%, but flows in and out of unemployment slow."},
{id:9045,sourceGame:"nationalEngine",q:"A policy lowers s but also lowers f. Which conclusion is safest?",options:["The unemployment-rate effect is ambiguous","Unemployment must fall","Unemployment must rise","The natural rate becomes zero"],a:0,tag:"steady_state_unemployment",type:"policy",objective:"LO7.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"focuses_on_one_rate_in_two_rate_model",feedback:"Lower s reduces unemployment, but lower f raises it. The net effect depends on magnitudes."},
{id:9046,sourceGame:"nationalEngine",q:"A retraining program raises f, while experience-rated UI lowers s. What happens to steady-state unemployment?",options:["It falls through both channels","It rises through both channels","It is ambiguous because both affect u oppositely","It stays fixed because L is fixed"],a:0,tag:"steady_state_unemployment",type:"policy",objective:"LO7.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"job_finding_job_separation_logic",secondarySkills:["sectoral_shift_matching"],repairSkill:"job_finding_job_separation_logic",commonError:"misses_direction_of_f_and_s_policy",feedback:"Higher f and lower s both reduce steady-state unemployment."},
{id:9047,sourceGame:"nationalEngine",q:"Refer to the minimum wage graph. A wage floor rises above equilibrium, but firms cut hours rather than workers. What should the best answer note?",options:["Labor-cost adjustment can occur through hours, hiring, and benefits","No structural pressure exists unless headcount falls","The wage floor shifts labor demand right","The policy only changes CPI measurement"],a:0,tag:"minimum_wage",type:"policy",objective:"LO7.3",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"minimum_wage_structural_unemployment",commonError:"looks_only_at_headcount_effects",feedback:"A binding wage floor can affect hours, hiring, benefits, prices, and job availability, not only headcount.",image:"minimumwage.webp"},
{id:9048,sourceGame:"nationalEngine",q:"A firm pays above-market wages to reduce turnover and discourage shirking. What is the cleanest interpretation?",options:["Efficiency wages can improve retention and effort but may ration jobs","Efficiency wages eliminate structural unemployment","Efficiency wages only affect CPI calculation","Efficiency wages lower real wages by definition"],a:0,tag:"efficiency_wages",type:"integration",objective:"LO7.3",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"efficiency_wage_theory",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"efficiency_wage_theory",commonError:"ignores_job_rationing_tradeoff",feedback:"Efficiency wages may reduce turnover and shirking, but above-equilibrium wages can also create job rationing."},
{id:9049,sourceGame:"nationalEngine",q:"Fifty workers are unemployed for 2 weeks; ten workers are unemployed for 30 weeks. What share of unemployment weeks comes from the long-term group?",options:["75%","16.7%","60%","83.3%"],a:0,tag:"unemployment_duration",type:"calculation",objective:"LO7.3",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"unemployment_duration_calculation",secondarySkills:[],repairSkill:"unemployment_duration_calculation",commonError:"uses_headcount_share_instead_of_week_share",feedback:"Short-term weeks = 100. Long-term weeks = 300. Total = 400. Long-term share = 300/400 = 75%."},
{id:9050,sourceGame:"nationalEngine",q:"GDP is 7000, C is 4200, I is 900, G is 1600, and exports are 500. Imports then rise by 100 with no other change. What are initial imports and new GDP?",options:["Initial imports 200; new GDP 6900","Initial imports 300; new GDP 6900","Initial imports 200; new GDP 7100","Initial imports 700; new GDP 7000"],a:0,tag:"gdp_components",type:"multi-step",objective:"LO2.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"gdp_expenditure_calculation",secondarySkills:["gdp_components_identity"],repairSkill:"gdp_expenditure_calculation",commonError:"solves_for_net_exports_but_not_imports_or_adds_imports",feedback:"Initially, 7000 = 4200 + 900 + 1600 + 500 - M, so imports are 200. If imports rise by 100, NX falls by 100 and GDP falls to 6900."},
{id:9051,sourceGame:"nationalEngine",q:"A basket costs 500 in the base year, 650 last year, and 715 this year. If nominal income rose 8% this year, what happened to real income?",options:["It fell because inflation was 10%","It rose because inflation was 7%","It was unchanged because CPI rose by 8%","It fell because inflation was 43%"],a:0,tag:"cpi",type:"multi-step",objective:"LO2.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"cpi_inflation_calculation",secondarySkills:["price_index_comparison"],repairSkill:"cpi_inflation_calculation",commonError:"compares_current_basket_to_base_basket_or_ignores_real_income",feedback:"Last year’s CPI was 130 and this year’s CPI is 143, so inflation was 10%. Nominal income rose only 8%, so real income fell."},
{id:9052,sourceGame:"nationalEngine",q:"Nominal GDP rises 9%, real GDP rises 2%, and employment rises 1%. Which memo best avoids overclaiming?",options:["Output and employment rose, but most nominal GDP growth reflects prices","Real output rose 9%, and employment explains the entire gain","Inflation must be exactly 7%, and productivity must have fallen","GDP growth proves the natural rate of unemployment fell"],a:0,tag:"real_nominal_gdp",type:"interpretation",objective:"LO2.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"real_vs_nominal_gdp",secondarySkills:["gdp_deflator_inflation"],repairSkill:"real_vs_nominal_gdp",commonError:"reads_nominal_growth_as_real_growth_or_overclaims_labor_market_effect",feedback:"Real GDP rose 2%, so output rose. Nominal GDP rose much faster, so prices explain much of the nominal gain. Employment rose too, but that alone does not prove the natural rate changed."},
{id:9053,sourceGame:"nationalEngine",q:"An economy has 500 employed, 50 unemployed, and 150 out of the labor force. Then 30 people outside the labor force start searching. What is the new unemployment rate?",options:["13.8%","9.1%","11.4%","16.0%"],a:0,tag:"labor_force",type:"calculation",objective:"LO2.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"labor_force_statistics_calculation",secondarySkills:["employment_status_classification"],repairSkill:"labor_force_statistics_calculation",commonError:"adds_new_searchers_to_labor_force_but_not_unemployed",feedback:"Unemployed rises to 80 and labor force rises to 580. U-3 = 80/580 = 13.8%."},
{id:9054,sourceGame:"nationalEngine",q:"A country has Y = A K^0.3 L^0.7. Technology rises 1%, capital rises 10%, and labor falls 2%. Approximate output growth is what?",options:["2.6%","4.0%","1.6%","8.6%"],a:0,tag:"production_function",type:"multi-step",objective:"LO3.1",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"production_function_output",secondarySkills:["cobb_douglas_factor_share_calculation"],repairSkill:"production_function_output",commonError:"ignores_negative_labor_growth_or_weights",feedback:"Growth is 1% + 0.3(10%) + 0.7(-2%) = 1 + 3 - 1.4 = 2.6%."},
{id:9055,sourceGame:"nationalEngine",q:"In the fixed-output Chapter 3 model, a business tax credit raises investment demand while government spending also rises. What happens to r?",options:["It rises from both stronger investment demand and lower saving","It falls because firms want more investment","It is ambiguous because both curves shift right","It stays fixed because output is fixed"],a:0,tag:"loanable_funds",type:"integration",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"investment_demand_vs_saving_shift",secondarySkills:["fiscal_policy_crowding_out"],repairSkill:"investment_demand_vs_saving_shift",commonError:"misses_same_direction_pressure_on_real_interest_rate",feedback:"Higher investment demand pushes r up, and higher government spending lowers saving, which also pushes r up.",image:"loanablefunds.webp"},
{id:9056,sourceGame:"nationalEngine",q:"A firm’s output is 0, 18, 33, 45, 54, 60 as labor rises from 0 to 5. If W/P = 10, how many workers should it hire?",options:["3","4","5","2"],a:0,tag:"labor_demand",type:"multi-step",objective:"LO3.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"total_product_to_marginal_product",secondarySkills:["labor_demand_mpl_real_wage"],repairSkill:"total_product_to_marginal_product",commonError:"uses_total_output_instead_of_mpl",feedback:"MPL values are 18, 15, 12, 9, and 6. The firm hires three workers and stops before MPL falls below 10."},
{id:9057,sourceGame:"nationalEngine",q:"Nominal wage rises from $30 to $36, output price rises from $5 to $8, and MPL is unchanged. What happens to labor demand?",options:["It rises because the real wage falls","It falls because the nominal wage rises","It is unchanged because MPL is unchanged","It falls because output price rises"],a:0,tag:"factor_prices",type:"trap",objective:"LO3.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"looks_only_at_nominal_wage",feedback:"The real wage falls from 30/5 = 6 to 36/8 = 4.5, so firms want more labor at unchanged MPL."},
{id:9058,sourceGame:"nationalEngine",q:"A Cobb-Douglas economy has alpha = 0.45 and total income of 12,000. Output rises to 13,000, but alpha falls to 0.40. What happens to capital income?",options:["It falls by 200","It rises by 450","It stays unchanged","It rises by 1000"],a:0,tag:"factor_shares",type:"multi-step",objective:"LO3.3",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:["factor_income_distribution"],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"uses_output_change_only_and_ignores_share_change",feedback:"Initial capital income is 0.45×12000 = 5400. New capital income is 0.40×13000 = 5200. Capital income falls by 200."},
{id:9059,sourceGame:"nationalEngine",q:"If alpha = 0.3, capital grows 4%, labor grows 4%, and technology falls 1%, what is output growth?",options:["3%","4%","2%","7%"],a:0,tag:"cobb_douglas",type:"multi-step",objective:"LO3.3",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:["production_function_output"],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"ignores_technology_decline",feedback:"Input growth contributes 0.3(4%) + 0.7(4%) = 4%. Technology falls 1%, so output grows 3%."},
{id:9060,sourceGame:"nationalEngine",q:"C = 250 + 0.8(Y - T), Y = 6000, T = 1500, and G = 1600. What are consumption and national saving?",options:["C = 3850; S = 550","C = 4800; S = -400","C = 3850; S = 650","C = 3600; S = 800"],a:0,tag:"consumption_function",type:"multi-step",objective:"LO3.4",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"consumption_function_calculation",secondarySkills:["saving_identity_calculation"],repairSkill:"consumption_function_calculation",commonError:"uses_income_instead_of_disposable_income_or_private_saving",feedback:"Disposable income is 4500. C = 250 + 0.8(4500) = 3850. National saving = 6000 - 3850 - 1600 = 550."},
{id:9061,sourceGame:"nationalEngine",q:"Households become more pessimistic and consume less at every income level. What happens to saving, r, and investment in the Chapter 3 loanable funds logic?",options:["Saving rises, r falls, and investment rises","Saving falls, r rises, and investment falls","Saving rises, r rises, and investment falls","Saving falls, r falls, and investment rises"],a:0,tag:"consumption_function",type:"integration",objective:"LO3.4",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"consumption_movement_vs_shift",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"consumption_movement_vs_shift",commonError:"misses_consumption_saving_link",feedback:"Lower consumption at each income raises saving, shifts saving right, lowers r, and raises investment."},
{id:9062,sourceGame:"nationalEngine",q:"Investment is I = 4000 - 250r. Nominal r is 9%, inflation is 1%, and expected profits shift autonomous investment down by 300. What is investment?",options:["1700","2000","2300","1450"],a:0,tag:"investment",type:"multi-step",objective:"LO3.4",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"real_interest_investment_calculation",secondarySkills:["investment_function_movement_vs_shift"],repairSkill:"real_interest_investment_calculation",commonError:"uses_nominal_rate_or_ignores_shift",feedback:"Real r = 8. Baseline investment is 4000 - 250(8) = 2000. The negative demand shift lowers it to 1700."},
{id:9063,sourceGame:"nationalEngine",q:"Refer to the investment graph. A tax credit shifts investment demand right, but a deficit shifts saving left. What is guaranteed in loanable funds?",options:["The real interest rate rises","Investment rises","Investment falls","The real interest rate falls"],a:0,tag:"loanable_funds",type:"graph_integration",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"loanable_funds_graph_shifts",secondarySkills:["investment_function_movement_vs_shift"],repairSkill:"loanable_funds_graph_shifts",commonError:"claims_investment_quantity_effect_when_ambiguous",feedback:"Higher investment demand raises r, and lower saving also raises r. The quantity of investment depends on which shift dominates.",image:"loanablefunds.webp"},
{id:9064,sourceGame:"nationalEngine",q:"National saving is 1200. Investment demand is I = 2200 - 100r. A deficit lowers saving to 1000. What happens to r?",options:["It rises from 10 to 12","It falls from 12 to 10","It rises from 8 to 10","It stays at 10"],a:0,tag:"loanable_funds",type:"calculation",objective:"LO3.5",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"saving_investment_equilibrium",secondarySkills:["fiscal_policy_crowding_out"],repairSkill:"saving_investment_equilibrium",commonError:"gets_deficit_interest_rate_effect_backward",feedback:"At S = 1200, r = 10. At S = 1000, r = 12. Lower saving raises the real interest rate."},
{id:9065,sourceGame:"nationalEngine",q:"Actual unemployment is 9%, frictional is 2%, and cyclical is 3%. A policy lowers structural unemployment by 1 point. What is the new natural rate?",options:["5%","6%","4%","8%"],a:0,tag:"natural_rate",type:"multi-step",objective:"LO7.1",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"natural_rate_definition",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"natural_rate_definition",commonError:"confuses_structural_with_cyclical_or_actual_unemployment",feedback:"Structural unemployment starts at 9 - 2 - 3 = 4%. The original natural rate is 2 + 4 = 6%. Lowering structural unemployment by 1 makes the new natural rate 5%."},
{id:9066,sourceGame:"nationalEngine",q:"Steady-state unemployment is 15% and f = 0.34. If a matching reform raises f to 0.44 while s stays at its implied initial value, what is the new steady-state unemployment rate?",options:["12.0%","15.0%","10.0%","17.0%"],a:0,tag:"steady_state_unemployment",type:"multi-step",objective:"LO7.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"steady_state_unemployment_calculation",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"steady_state_unemployment_calculation",commonError:"does_not_rearrange_formula_or_gets_f_effect_backward",feedback:"Initial s = uf/(1-u) = 0.15×0.34/0.85 = 0.06. With f = 0.44, new u = 0.06/(0.06+0.44) = 12%."},
{id:9067,sourceGame:"nationalEngine",q:"A policy raises f from 0.25 to 0.35 but also raises s from 0.05 to 0.07. What happens to steady-state unemployment?",options:["It stays at 16.7%","It falls from 20.0% to 16.7%","It rises from 14.3% to 20.0%","It rises from 16.7% to 20.0%"],a:0,tag:"steady_state_unemployment",type:"multi-step",objective:"LO7.2",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"job_finding_job_separation_logic",secondarySkills:["steady_state_unemployment_calculation"],repairSkill:"job_finding_job_separation_logic",commonError:"focuses_on_only_f_or_only_s",feedback:"Initial u = 0.05/0.30 = 16.7%. New u = 0.07/0.42 = 16.7%. Both rates rise proportionally."},
{id:9068,sourceGame:"nationalEngine",q:"A city minimum wage raises pay, reduces turnover, cuts hours, and lowers new hiring. Which memo is best?",options:["The policy has mixed margins: retention improves, but job rationing can worsen","The policy clearly lowers structural unemployment for all workers","The policy affects only CPI and not labor markets","The policy removes frictional unemployment by raising wages"],a:0,tag:"minimum_wage",type:"policy",objective:"LO7.3",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:["efficiency_wage_theory"],repairSkill:"minimum_wage_structural_unemployment",commonError:"ignores_multiple_adjustment_margins",feedback:"Higher wages can reduce turnover for those employed while reducing hours or new hiring for others. That is the tradeoff."},
{id:9069,sourceGame:"nationalEngine",q:"Thirty workers are unemployed for 5 weeks, ten workers for 20 weeks, and five workers for 50 weeks. What share of unemployment weeks comes from the five longest spells?",options:["41.7%","11.1%","33.3%","55.6%"],a:0,tag:"unemployment_duration",type:"calculation",objective:"LO7.3",difficulty:"legendary",conceptCluster:"legendary_national_engine",primarySkill:"unemployment_duration_calculation",secondarySkills:[],repairSkill:"unemployment_duration_calculation",commonError:"uses_headcount_share_instead_of_week_share",feedback:"Total weeks = 30×5 + 10×20 + 5×50 = 600. Longest-spell weeks = 250. Share = 250/600 = 41.7%."}
],
	
legendaryBoss:[
{id:9100,sourceGame:"nationalEngine",q:"Base prices are A = $10 and B = $5. Current quantities are A = 110 and B = 180. Current prices are A = $12 and B = $8. What are current nominal GDP, current real GDP, and the GDP deflator?",options:["Nominal 2760; real 2000; deflator 138","Nominal 2000; real 2760; deflator 72.5","Nominal 2760; real 2200; deflator 125.5","Nominal 2480; real 2000; deflator 124"],a:0,tag:"real_nominal_gdp",type:"multi-step",objective:"LO2.2",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"real_vs_nominal_gdp",secondarySkills:["gdp_deflator_inflation"],repairSkill:"real_vs_nominal_gdp",commonError:"uses_current_prices_for_real_gdp",feedback:"Nominal GDP = 12×110 + 8×180 = 2760. Real GDP = 10×110 + 5×180 = 2000. Deflator = 100×2760/2000 = 138."},
{id:9101,sourceGame:"nationalEngine",q:"A CPI basket has 5 beef and 5 chicken. Base prices are $10 and $10. Last year prices are $12 and $13. This year prices are $16 and $25. What is this year’s CPI inflation from last year?",options:["64%","105%","80%","42.4%"],a:0,tag:"cpi",type:"multi-step",objective:"LO2.2",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"cpi_inflation_calculation",secondarySkills:["cpi_bias_limitations"],repairSkill:"cpi_inflation_calculation",commonError:"compares_current_basket_to_base_basket",feedback:"Base basket is 100, last year is 125, and this year is 205. CPI rises from 125 to 205, so inflation is 80/125 = 64%."},
{id:9102,sourceGame:"nationalEngine",q:"An economy has 800 employed, 80 unemployed, and 120 out of the labor force. Then 40 unemployed stop searching and 20 outsiders begin searching. What is the new U-3 unemployment rate?",options:["7.0%","6.7%","8.0%","10.0%"],a:0,tag:"labor_force",type:"multi-step",objective:"LO2.2",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"labor_force_statistics_calculation",secondarySkills:["employment_status_classification"],repairSkill:"labor_force_statistics_calculation",commonError:"misclassifies_searchers_and_discouraged_workers",feedback:"Unemployed becomes 80 - 40 + 20 = 60. Employed stays 800. Labor force is 860. U-3 = 60/860 = 7.0%."},
{id:9103,sourceGame:"nationalEngine",q:"A production function is Y = A K^0.35 L^0.65. A rises 2%, K rises 8%, and L falls 2%. What is approximate output growth?",options:["3.5%","5.8%","2.2%","7.1%"],a:0,tag:"production_function",type:"multi-step",objective:"LO3.1",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"production_function_output",secondarySkills:["cobb_douglas_factor_share_calculation"],repairSkill:"production_function_output",commonError:"ignores_negative_labor_growth",feedback:"Growth ≈ 2% + 0.35×8% + 0.65×(-2%) = 2 + 2.8 - 1.3 = 3.5%."},
{id:9104,sourceGame:"nationalEngine",q:"A production function has Y = A K^0.55 L^0.60. Which statement best classifies the scale property and warns against reading this as the standard Cobb-Douglas share setup?",options:["Increasing returns; the exponents sum above one","Constant returns; capital and labor shares must sum to one","Decreasing returns; each exponent is below one","Increasing returns; labor’s share must be exactly 40%"],a:0,tag:"returns_to_scale",type:"multi-step",objective:"LO3.1",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"returns_to_scale_classification",secondarySkills:["factor_income_distribution"],repairSkill:"returns_to_scale_classification",commonError:"misreads_exponents_and_factor_shares",feedback:"The exponents sum to 1.15, so the function has increasing returns to scale. Since the exponents do not sum to one, it is not the standard constant-returns Cobb-Douglas share case."},
{id:9105,sourceGame:"nationalEngine",q:"A firm’s MPL schedule is 28, 23, 18, 13, 9. The nominal wage is $72 and output price is $4. How many workers should the firm hire?",options:["3","2","4","5"],a:0,tag:"labor_demand",type:"multi-step",objective:"LO3.2",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:["diminishing_marginal_product"],repairSkill:"labor_demand_mpl_real_wage",commonError:"uses_nominal_wage_instead_of_real_wage",feedback:"The real wage is 72/4 = 18. The firm hires through the third worker, where MPL equals the real wage."},
{id:9106,sourceGame:"nationalEngine",q:"Total output is 0, 22, 40, 54, 64, 70 as labor rises from 0 to 5. If W/P = 12, how many workers should be hired?",options:["3","4","2","5"],a:0,tag:"marginal_product",type:"multi-step",objective:"LO3.2",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"total_product_to_marginal_product",secondarySkills:["labor_demand_mpl_real_wage"],repairSkill:"total_product_to_marginal_product",commonError:"uses_total_product_instead_of_mpl",feedback:"MPL values are 22, 18, 14, 10, and 6. The firm hires three workers and stops before MPL drops below 12."},
{id:9107,sourceGame:"nationalEngine",q:"Capital rises while labor is fixed. Which factor-price pattern best follows the marginal product logic?",options:["MPK falls and MPL rises","MPK rises and MPL falls","Both MPK and MPL fall","Both MPK and MPL rise"],a:0,tag:"factor_prices",type:"integration",objective:"LO3.2",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"diminishing_marginal_product",secondarySkills:["factor_income_distribution"],repairSkill:"diminishing_marginal_product",commonError:"misses_cross_marginal_product_effects",feedback:"More capital lowers MPK because capital is less scarce, but raises MPL because workers have more capital to use."},
{id:9108,sourceGame:"nationalEngine",q:"If alpha = 0.40, total income is 15,000, capital grows 5%, labor grows 2%, and technology grows 1%, which pair is correct?",options:["Capital income 6000; output growth 4.2%","Capital income 9000; output growth 4.2%","Capital income 6000; output growth 8.0%","Capital income 9000; output growth 3.0%"],a:0,tag:"cobb_douglas",type:"multi-step",objective:"LO3.3",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:["production_function_output"],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"reverses_factor_share_or_misweights_growth",feedback:"Capital income = 0.40×15000 = 6000. Growth = 1 + 0.40×5 + 0.60×2 = 4.2%."},
{id:9109,sourceGame:"nationalEngine",q:"C = 500 + 0.75(Y - T), Y = 7000, T = 1600, and G = 1800. What are consumption, private saving, and national saving?",options:["C 4550; private 850; national 650","C 4550; private 650; national 850","C 5750; private 850; national -550","C 4050; private 1350; national 1150"],a:0,tag:"consumption_function",type:"multi-step",objective:"LO3.4",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"consumption_function_calculation",secondarySkills:["saving_identity_calculation"],repairSkill:"consumption_function_calculation",commonError:"confuses_private_and_national_saving",feedback:"Disposable income is 5400. C = 500 + 0.75×5400 = 4550. Private saving = 5400 - 4550 = 850. National saving = 7000 - 4550 - 1800 = 650."},
{id:9110,sourceGame:"nationalEngine",q:"Taxes rise by 400, G rises by 400, and MPC = 0.8 with output fixed. What happens to consumption and national saving?",options:["C falls 320; S falls 80","C falls 400; S unchanged","C falls 80; S falls 320","C rises 320; S rises 80"],a:0,tag:"fiscal_policy",type:"multi-step",objective:"LO3.5",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"fiscal_policy_crowding_out",secondarySkills:["mpc_disposable_income"],repairSkill:"fiscal_policy_crowding_out",commonError:"assumes_balanced_budget_means_no_saving_effect",feedback:"Higher taxes reduce consumption by 320, which raises saving by 320, but higher G lowers saving by 400. Net national saving falls by 80."},
{id:9111,sourceGame:"nationalEngine",q:"Refer to loanable funds. Saving shifts left and investment demand shifts left at the same time. What is guaranteed?",options:["Investment falls","The real interest rate rises","The real interest rate falls","Investment rises"],a:0,tag:"loanable_funds",type:"graph_integration",objective:"LO3.5",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"loanable_funds_graph_shifts",secondarySkills:["investment_demand_vs_saving_shift"],repairSkill:"loanable_funds_graph_shifts",commonError:"claims_interest_rate_effect_when_ambiguous",feedback:"Lower saving and lower investment demand both reduce equilibrium investment. The interest-rate effect is ambiguous because the shifts push r in opposite directions.",image:"loanablefunds.webp"},
{id:9112,sourceGame:"nationalEngine",q:"National saving is 1400 and investment demand is I = 2600 - 100r. A deficit lowers saving to 1100 while investment demand shifts to I = 2800 - 100r. What happens to r?",options:["It rises from 12 to 17","It rises from 14 to 17","It falls from 12 to 11","It rises from 10 to 14"],a:0,tag:"loanable_funds",type:"multi-step",objective:"LO3.5",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"saving_investment_equilibrium",secondarySkills:["fiscal_policy_crowding_out","investment_demand_vs_saving_shift"],repairSkill:"saving_investment_equilibrium",commonError:"misses_both_saving_and_investment_shift",feedback:"Initially 1400 = 2600 - 100r, so r = 12. After shifts, 1100 = 2800 - 100r, so r = 17."},
{id:9113,sourceGame:"nationalEngine",q:"A tax cut raises consumption, a business tax credit raises investment demand, and output is fixed. What is the most defensible Chapter 3 prediction?",options:["r rises, while equilibrium investment is ambiguous","r falls, while equilibrium investment rises","r is unchanged, while output rises","r rises, while output rises"],a:0,tag:"loanable_funds",type:"integration",objective:"LO3.5",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"fiscal_policy_crowding_out",secondarySkills:["investment_demand_vs_saving_shift"],repairSkill:"fiscal_policy_crowding_out",commonError:"turns_fixed_output_model_into_multiplier_model",feedback:"The tax cut lowers saving and the credit raises investment demand, both pushing r up. Investment quantity is ambiguous because the shifts work against each other."},
{id:9114,sourceGame:"nationalEngine",q:"Investment is I = 5000 - 300r. Nominal r is 10%, inflation is 4%, and expected profits shift investment demand down by 500. What is investment?",options:["2700","3200","1500","2200"],a:0,tag:"investment",type:"multi-step",objective:"LO3.4",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"real_interest_investment_calculation",secondarySkills:["investment_function_movement_vs_shift"],repairSkill:"real_interest_investment_calculation",commonError:"uses_nominal_rate_or_ignores_shift",feedback:"Real r = 6. Baseline investment = 5000 - 300×6 = 3200. The negative demand shift lowers it to 2700."},
{id:9115,sourceGame:"nationalEngine",q:"Wealth falls, but taxes also fall. Output and government purchases are fixed. What is the safest conclusion for consumption and national saving?",options:["Both are ambiguous because consumption faces opposing forces","Consumption must rise and national saving must fall","Consumption must fall and national saving must rise","Consumption is fixed because output is fixed"],a:0,tag:"consumption_function",type:"integration",objective:"LO3.4",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"consumption_movement_vs_shift",secondarySkills:["saving_identity_calculation"],repairSkill:"consumption_movement_vs_shift",commonError:"ignores_offsetting_consumption_effects",feedback:"Lower wealth reduces consumption, while lower taxes raise disposable income and consumption. Since national saving is Y - C - G, its direction depends on the net change in consumption."},
{id:9116,sourceGame:"nationalEngine",q:"Actual unemployment is 9.5%, frictional is 2.0%, and structural is 4.5%. A matching reform lowers frictional to 1.5%. What is the new natural rate if structural is unchanged?",options:["6.0%","6.5%","8.0%","5.5%"],a:0,tag:"natural_rate",type:"multi-step",objective:"LO7.1",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"natural_rate_definition",secondarySkills:["sectoral_shift_matching"],repairSkill:"natural_rate_definition",commonError:"uses_actual_unemployment_as_natural_rate",feedback:"The new natural rate is frictional plus structural unemployment: 1.5% + 4.5% = 6.0%."},
{id:9117,sourceGame:"nationalEngine",q:"Steady-state unemployment is 18% and f = 0.41. What is the separation rate closest to?",options:["0.09","0.07","0.18","0.50"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"steady_state_unemployment_calculation",secondarySkills:[],repairSkill:"steady_state_unemployment_calculation",commonError:"cannot_rearrange_steady_state_formula",feedback:"Using s = uf/(1-u), s = 0.18×0.41/0.82 ≈ 0.09."},
{id:9118,sourceGame:"nationalEngine",q:"A reform raises f from 0.18 to 0.30 and lowers s from 0.06 to 0.04. What happens to steady-state unemployment?",options:["It falls from 25% to 11.8%","It falls from 20% to 13.3%","It rises from 11.8% to 25%","It stays fixed because both rates change"],a:0,tag:"steady_state_unemployment",type:"multi-step",objective:"LO7.2",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"steady_state_unemployment_calculation",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"steady_state_unemployment_calculation",commonError:"focuses_on_one_flow_rate_only",feedback:"Initial u = 0.06/(0.06+0.18) = 25%. New u = 0.04/(0.04+0.30) = 11.8%."},
{id:9119,sourceGame:"nationalEngine",q:"If s falls and f also falls, but s/f stays unchanged, what is the best interpretation?",options:["The unemployment rate is unchanged, but turnover slows","The unemployment rate falls, and turnover slows","The unemployment rate rises, and turnover speeds up","The unemployment rate is unchanged, but turnover speeds up"],a:0,tag:"steady_state_unemployment",type:"trap",objective:"LO7.2",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"job_finding_job_separation_logic",secondarySkills:["steady_state_unemployment_calculation"],repairSkill:"job_finding_job_separation_logic",commonError:"misses_ratio_vs_speed_difference",feedback:"The steady-state rate depends on the ratio of s to s+f, while the speed of labor-market flows depends on the size of the rates."},
{id:9120,sourceGame:"nationalEngine",q:"Refer to the minimum wage graph. A wage floor above equilibrium reduces separations among current workers but lowers new hiring. Which memo is strongest?",options:["The policy may lower turnover while worsening job rationing","The policy must lower natural unemployment for everyone","The policy affects frictional unemployment only","The policy eliminates structural unemployment"],a:0,tag:"minimum_wage",type:"policy",objective:"LO7.3",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:["efficiency_wage_theory"],repairSkill:"minimum_wage_structural_unemployment",commonError:"ignores_multiple_labor_market_margins",feedback:"A higher wage can reduce turnover among employed workers but also reduce hiring and create job rationing for others.",image:"minimumwage.webp"},
{id:9121,sourceGame:"nationalEngine",q:"A firm pays high wages to attract better applicants and prevent shirking after hiring. Which pair of information problems is most relevant?",options:["Adverse selection and moral hazard","Substitution bias and CPI drift","Crowding out and public saving","Nominal rigidity and GDP deflation"],a:0,tag:"efficiency_wages",type:"integration",objective:"LO7.3",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"efficiency_wage_theory",secondarySkills:[],repairSkill:"efficiency_wage_theory",commonError:"confuses_adverse_selection_and_moral_hazard_channels",feedback:"Attracting better applicants is adverse selection; preventing shirking after hiring is moral hazard."},
{id:9122,sourceGame:"nationalEngine",q:"U-3 falls, U-6 stays high, and part-time-for-economic-reasons remains elevated. What should the labor advisor say?",options:["Official unemployment improved, but underutilization remains","The natural rate must have fallen to zero","Discouraged workers are counted as employed","CPI inflation must be overstated"],a:0,tag:"labor_underutilization",type:"interpretation",objective:"LO7.3",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"labor_underutilization_classification",secondarySkills:["employment_status_classification"],repairSkill:"labor_underutilization_classification",commonError:"treats_u3_as_complete_labor_slack_measure",feedback:"U-3 can improve while U-6 remains high because U-6 captures marginal attachment and part-time work for economic reasons."},
{id:9123,sourceGame:"nationalEngine",q:"A recession lowers spending while a union contract also holds wages above equilibrium. Which unemployment diagnosis is most careful?",options:["Cyclical and structural forces can both be present","Only frictional unemployment can explain the case","Only cyclical unemployment can explain the case","No official unemployment can be counted"],a:0,tag:"unemployment_types",type:"integration",objective:"LO7.3",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"frictional_vs_other_unemployment",secondarySkills:["union_wage_rigidity"],repairSkill:"frictional_vs_other_unemployment",commonError:"forces_single_unemployment_type_when_multiple_apply",feedback:"Weak demand can create cyclical unemployment, while above-equilibrium union wages can create structural unemployment."},
{id:9124,sourceGame:"nationalEngine",q:"Thirty workers are unemployed for 4 weeks, twelve workers for 25 weeks, and eight workers for 50 weeks. What share of unemployment weeks comes from the eight longest spells?",options:["48.8%","16.0%","39.0%","64.0%"],a:0,tag:"unemployment_duration",type:"calculation",objective:"LO7.3",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"unemployment_duration_calculation",secondarySkills:[],repairSkill:"unemployment_duration_calculation",commonError:"uses_headcount_share_instead_of_week_share",feedback:"Total weeks = 30×4 + 12×25 + 8×50 = 820. Longest-spell weeks = 400. Share = 400/820 = 48.8%."},
{id:9125,sourceGame:"nationalEngine",q:"A policy expands UI generosity, adds strict search requirements, and funds job placement. What is the best prediction for frictional unemployment?",options:["Ambiguous because search incentives and matching move differently","It must rise because UI is more generous","It must fall because placement improves","It must become structural unemployment"],a:0,tag:"unemployment_insurance",type:"policy",objective:"LO7.3",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"ui_and_job_search_incentives",secondarySkills:["sectoral_shift_matching"],repairSkill:"ui_and_job_search_incentives",commonError:"treats_ui_policy_as_one_direction_only",feedback:"More generous UI can lengthen search, while requirements and placement can improve matching. Net effect depends on design strength."},
{id:9126,sourceGame:"nationalEngine",q:"A productivity boom raises investment demand and output capacity, but the government also runs a larger deficit. What is the loanable-funds concern?",options:["Higher r may choke off some investment despite better opportunities","Investment must rise because opportunities improved","Saving must rise because output capacity improved","The deficit lowers r and expands investment"],a:0,tag:"loanable_funds",type:"integration",objective:"LO3.5",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"investment_demand_vs_saving_shift",secondarySkills:["fiscal_policy_crowding_out"],repairSkill:"investment_demand_vs_saving_shift",commonError:"ignores_deficit_pressure_on_r",feedback:"Better investment opportunities shift investment demand right, but deficits reduce saving and raise r, limiting actual investment gains."},
{id:9127,sourceGame:"nationalEngine",q:"A country wants more future capital without raising r. Which policy mix best fits the loanable funds model?",options:["Raise national saving while supporting investment demand","Cut saving while raising investment demand","Raise consumption while cutting public saving","Increase deficits while cutting private saving"],a:0,tag:"loanable_funds",type:"policy",objective:"LO3.5",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"loanable_funds_graph_shifts",secondarySkills:["investment_demand_vs_saving_shift"],repairSkill:"loanable_funds_graph_shifts",commonError:"chooses_policy_that_raises_r",feedback:"More saving expands available funds, while stronger investment demand supports capital formation. Raising saving prevents r from doing all the rationing."},
{id:9128,sourceGame:"nationalEngine",q:"A student says, 'If investment demand shifts right, investment must rise.' What is the boss-level correction?",options:["Not if saving is fixed; r may rise instead","Yes, investment always rises fully","No, investment always falls fully","Only CPI can answer the question"],a:0,tag:"loanable_funds",type:"trap",objective:"LO3.5",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"investment_demand_vs_saving_shift",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"investment_demand_vs_saving_shift",commonError:"ignores_vertical_saving_constraint",feedback:"If saving is fixed or very inelastic, stronger investment demand mainly raises the real interest rate rather than investment quantity."},
{id:9129,sourceGame:"nationalEngine",q:"A worker leaves a job voluntarily, searches for a better match, then stops searching after benefits expire. How does the classification change?",options:["Frictional unemployed first, then out of the labor force","Structural unemployed first, then employed","Cyclical unemployed first, then structurally employed","Out of labor force first, then U-3 unemployed"],a:0,tag:"unemployment_types",type:"integration",objective:"LO7.3",difficulty:"legendaryBoss",conceptCluster:"legendary_boss_national_engine",primarySkill:"frictional_vs_other_unemployment",secondarySkills:["employment_status_classification"],repairSkill:"frictional_vs_other_unemployment",commonError:"misses_search_requirement_for_unemployment",feedback:"While actively searching, the worker is frictionally unemployed. Once search stops, the worker leaves official unemployment and the labor force."}
],
	
easyBoss:[
// --- LO2.1: GDP MEASUREMENT ---
{id:2000,sourceGame:"nationalEngine",q:"The Registrar speaks: 'Begin with the ledger.' What does GDP measure?",options:["Total spending and income from final goods and services","Only financial assets traded during the year","Only government taxes and transfers","Total population inside the economy"],a:0,tag:"gdp",type:"definition",objective:"LO2.1",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_gdp_measurement",primarySkill:"gdp_components_identity",secondarySkills:[],repairSkill:"gdp_components_identity",commonError:"confuses_gdp_with_assets_or_population",feedback:"GDP measures total spending and income from final goods and services produced in the economy."},
{id:2001,sourceGame:"nationalEngine",q:"The Registrar checks the entry: 'Do not count the same output twice.' Why are intermediate goods excluded from GDP?",options:["Their value is already included in final goods","They are always imported from abroad","They are counted only in unemployment data","They are never purchased by firms"],a:0,tag:"gdp",type:"interpretation",objective:"LO2.1",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_gdp_measurement",primarySkill:"gdp_inclusion_exclusion",secondarySkills:[],repairSkill:"gdp_inclusion_exclusion",commonError:"double_counts_intermediate_goods",feedback:"Intermediate goods are excluded because their value is already built into the final good."},
{id:2002,sourceGame:"nationalEngine",q:"The Registrar points to a shipment: 'A household buys an imported television.' How does this affect GDP accounting?",options:["Consumption rises, but imports subtract the same production","GDP rises because consumption rises","GDP falls because imports are subtracted twice","Investment rises because the good lasts several years"],a:0,tag:"gdp_components",type:"interpretation",objective:"LO2.1",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_gdp_measurement",primarySkill:"gdp_components_identity",secondarySkills:["gdp_inclusion_exclusion"],repairSkill:"gdp_components_identity",commonError:"forgets_import_offset",feedback:"The television enters consumption, but because it is imported, it is subtracted through imports in net exports."},

// --- LO2.1: PRICE INDEXES ---
{id:2003,sourceGame:"nationalEngine",q:"The Registrar opens the price archive: 'Which index follows a fixed consumer basket?'",options:["CPI","GDP deflator","Real GDP","Labor force participation rate"],a:0,tag:"cpi",type:"definition",objective:"LO2.1",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_price_indexes",primarySkill:"cpi_measurement",secondarySkills:[],repairSkill:"cpi_measurement",commonError:"confuses_cpi_with_gdp_deflator",feedback:"The CPI tracks the cost of a fixed basket of consumer goods and services."},
{id:2004,sourceGame:"nationalEngine",q:"The Registrar asks: 'Which price measure covers currently produced domestic output?'",options:["GDP deflator","CPI","Labor force participation rate","Unemployment rate"],a:0,tag:"gdp_deflator",type:"definition",objective:"LO2.1",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_price_indexes",primarySkill:"price_index_comparison",secondarySkills:["gdp_deflator_inflation"],repairSkill:"price_index_comparison",commonError:"confuses_domestic_output_index_with_consumer_basket",feedback:"The GDP deflator measures the price level of goods and services included in current GDP."},
{id:2005,sourceGame:"nationalEngine",q:"The Registrar warns: 'A fixed basket can mislead.' Which problem can cause CPI to overstate cost-of-living increases?",options:["Consumers substitute toward cheaper goods","Consumers never change what they buy","The CPI includes only exports","The CPI excludes all consumer prices"],a:0,tag:"cpi_bias",type:"interpretation",objective:"LO2.1",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_price_indexes",primarySkill:"cpi_bias_limitations",secondarySkills:[],repairSkill:"cpi_bias_limitations",commonError:"misses_substitution_bias",feedback:"The CPI can overstate cost-of-living increases when consumers substitute toward cheaper goods but the basket stays fixed."},

// --- LO2.1: LABOR STATUS ---
{id:2006,sourceGame:"nationalEngine",q:"The Registrar scans the labor rolls: 'Who is officially unemployed?'",options:["A person without a job who recently searched for work","A retired person who does not want work","A discouraged worker who stopped searching","A full-time student not seeking work"],a:0,tag:"labor_force",type:"definition",objective:"LO2.1",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_labor_status",primarySkill:"employment_status_classification",secondarySkills:[],repairSkill:"employment_status_classification",commonError:"counts_nonsearchers_as_unemployed",feedback:"Official unemployment requires being jobless and actively searching for work."},
{id:2007,sourceGame:"nationalEngine",q:"The Registrar marks a worker inactive: 'They want work but stopped searching.' How are they treated in U-3?",options:["Out of the labor force","Unemployed","Employed","Counted twice"],a:0,tag:"discouraged_workers",type:"interpretation",objective:"LO2.1",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_labor_status",primarySkill:"employment_status_classification",secondarySkills:["labor_underutilization_classification"],repairSkill:"employment_status_classification",commonError:"counts_discouraged_workers_as_u3_unemployed",feedback:"A discouraged worker who has stopped searching is not counted as unemployed in U-3."},
{id:2008,sourceGame:"nationalEngine",q:"The Registrar asks: 'What group forms the labor force?'",options:["Employed plus unemployed","Employed plus retired","Unemployed plus all adults","Adult population minus students"],a:0,tag:"labor_force",type:"definition",objective:"LO2.1",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_labor_status",primarySkill:"labor_force_statistics_calculation",secondarySkills:[],repairSkill:"labor_force_statistics_calculation",commonError:"misdefines_labor_force",feedback:"The labor force is the number employed plus the number unemployed."},

// --- LO2.2: GDP AND DEFLATOR CALCULATION ---
{id:2009,sourceGame:"nationalEngine",q:"The Registrar locks the ledger: 'C = 500, I = 120, G = 200, and NX = -40.' What is GDP?",options:["780","860","820","660"],a:0,tag:"gdp_components",type:"calculation",objective:"LO2.2",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_gdp_calculation",primarySkill:"gdp_expenditure_calculation",secondarySkills:[],repairSkill:"gdp_expenditure_calculation",commonError:"forgets_negative_net_exports",feedback:"GDP = C + I + G + NX = 500 + 120 + 200 - 40 = 780."},
{id:2010,sourceGame:"nationalEngine",q:"The Registrar removes one veil: 'GDP is 1000, C = 600, I = 150, and G = 200.' What is NX?",options:["50","250","-50","100"],a:0,tag:"gdp_components",type:"calculation",objective:"LO2.2",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_gdp_calculation",primarySkill:"gdp_expenditure_calculation",secondarySkills:[],repairSkill:"gdp_expenditure_calculation",commonError:"does_not_solve_for_net_exports",feedback:"NX = GDP - C - I - G = 1000 - 600 - 150 - 200 = 50."},
{id:2011,sourceGame:"nationalEngine",q:"The Registrar checks prices: 'Nominal GDP is 1500 and real GDP is 1200.' What is the GDP deflator?",options:["125","80","120","300"],a:0,tag:"gdp_deflator",type:"calculation",objective:"LO2.2",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_gdp_calculation",primarySkill:"gdp_deflator_inflation",secondarySkills:[],repairSkill:"gdp_deflator_inflation",commonError:"reverses_nominal_and_real_gdp",feedback:"GDP deflator = 100 × nominal GDP / real GDP = 100 × 1500 / 1200 = 125."},

// --- LO2.2: CPI AND INFLATION CALCULATION ---
{id:2012,sourceGame:"nationalEngine",q:"The Registrar opens the basket: 'The basket cost 80 in the base year and 100 this year.' What is the CPI?",options:["125","80","100","20"],a:0,tag:"cpi",type:"calculation",objective:"LO2.2",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_cpi_calculation",primarySkill:"cpi_inflation_calculation",secondarySkills:[],repairSkill:"cpi_inflation_calculation",commonError:"subtracts_instead_of_indexing",feedback:"CPI = 100 × current basket cost / base basket cost = 100 × 100 / 80 = 125."},
{id:2013,sourceGame:"nationalEngine",q:"The Registrar compares two years: 'The CPI rises from 120 to 132.' What is the inflation rate?",options:["10%","12%","8%","20%"],a:0,tag:"inflation",type:"calculation",objective:"LO2.2",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_cpi_calculation",primarySkill:"cpi_inflation_calculation",secondarySkills:[],repairSkill:"cpi_inflation_calculation",commonError:"divides_by_new_cpi_instead_of_old_cpi",feedback:"Inflation = (132 - 120) / 120 × 100 = 10%."},
{id:2014,sourceGame:"nationalEngine",q:"The Registrar narrows his eyes: 'The basket cost 200 last year and 230 this year.' What is the inflation rate?",options:["15%","13%","30%","23%"],a:0,tag:"inflation",type:"calculation",objective:"LO2.2",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_cpi_calculation",primarySkill:"cpi_inflation_calculation",secondarySkills:[],repairSkill:"cpi_inflation_calculation",commonError:"uses_current_cost_as_denominator",feedback:"Inflation = (230 - 200) / 200 × 100 = 15%."},

// --- LO2.2: LABOR STATISTICS CALCULATION ---
{id:2015,sourceGame:"nationalEngine",q:"The Registrar counts the hall: '180 are employed and 20 are unemployed.' What is the unemployment rate?",options:["10%","20%","11.1%","90%"],a:0,tag:"unemployment_rate",type:"calculation",objective:"LO2.2",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_labor_calculation",primarySkill:"labor_force_statistics_calculation",secondarySkills:[],repairSkill:"labor_force_statistics_calculation",commonError:"uses_employed_instead_of_labor_force",feedback:"Labor force = 180 + 20 = 200. Unemployment rate = 20 / 200 × 100 = 10%."},
{id:2016,sourceGame:"nationalEngine",q:"The Registrar checks participation: 'The labor force is 240 and the adult population is 300.' What is the labor force participation rate?",options:["80%","60%","20%","125%"],a:0,tag:"lfpr",type:"calculation",objective:"LO2.2",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_labor_calculation",primarySkill:"labor_force_statistics_calculation",secondarySkills:[],repairSkill:"labor_force_statistics_calculation",commonError:"confuses_lfpr_with_unemployment_rate",feedback:"Labor force participation rate = labor force / adult population × 100 = 240 / 300 × 100 = 80%."},
{id:2017,sourceGame:"nationalEngine",q:"The Registrar changes the record: '100 are employed, 10 are unemployed, and 20 are out of the labor force.' What is the unemployment rate?",options:["9.1%","10%","7.7%","20%"],a:0,tag:"unemployment_rate",type:"calculation",objective:"LO2.2",difficulty:"easyBoss",conceptCluster:"boss_chapter_2_labor_calculation",primarySkill:"labor_force_statistics_calculation",secondarySkills:["employment_status_classification"],repairSkill:"labor_force_statistics_calculation",commonError:"uses_adult_population_instead_of_labor_force",feedback:"Labor force = 100 + 10 = 110. Unemployment rate = 10 / 110 × 100 = 9.1%."}
],

mediumBoss:[
// --- LO7.1: NATURAL RATE ---
{id:3000,sourceGame:"nationalEngine",q:"The Warden speaks: 'Unemployment is never still.' What is the natural rate of unemployment?",options:["The average rate around which unemployment fluctuates","The unemployment rate when no one is jobless","The unemployment caused only by recessions","The number unemployed divided by adult population"],a:0,tag:"natural_rate",type:"definition",objective:"LO7.1",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_natural_rate",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"thinks_natural_rate_means_zero_unemployment",feedback:"The natural rate is the average unemployment rate around which actual unemployment fluctuates."},
{id:3001,sourceGame:"nationalEngine",q:"The Warden narrows the ledger: 'Actual unemployment is 8% and the natural rate is 5%.' What is cyclical unemployment?",options:["3 percentage points","5 percentage points","8 percentage points","13 percentage points"],a:0,tag:"natural_rate",type:"calculation",objective:"LO7.1",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_natural_rate",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"uses_actual_unemployment_as_cyclical_unemployment",feedback:"Cyclical unemployment is actual unemployment minus the natural rate: 8% - 5% = 3 percentage points."},
{id:3002,sourceGame:"nationalEngine",q:"The Warden warns: 'Do not confuse the cycle with the baseline.' Which unemployment is not part of the natural rate?",options:["Cyclical unemployment","Frictional unemployment","Structural unemployment","Search unemployment"],a:0,tag:"natural_rate",type:"interpretation",objective:"LO7.1",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_natural_rate",primarySkill:"natural_rate_definition",secondarySkills:["frictional_vs_other_unemployment"],repairSkill:"natural_rate_definition",commonError:"includes_cyclical_unemployment_in_natural_rate",feedback:"The natural rate includes frictional and structural unemployment, not cyclical unemployment."},

// --- LO7.1: NATURAL RATE POLICY ---
{id:3003,sourceGame:"nationalEngine",q:"The Warden asks: 'Which reform lowers the baseline, not just the cycle?' Which policy most directly lowers the natural rate?",options:["Improving job matching so workers find jobs faster","Increasing demand for one quarter only","Changing the CPI base year","Counting imports differently in GDP"],a:0,tag:"natural_rate",type:"policy",objective:"LO7.1",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_natural_rate_policy",primarySkill:"natural_rate_definition",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"natural_rate_definition",commonError:"confuses_demand_policy_with_natural_rate_policy",feedback:"Improving matching raises job finding and can lower the natural rate of unemployment."},
{id:3004,sourceGame:"nationalEngine",q:"The Warden presses: 'Actual unemployment falls below the natural rate.' What should the advisor avoid claiming?",options:["The natural rate has permanently become zero","The economy may be temporarily hot","Cyclical unemployment may be negative","Frictional unemployment can still exist"],a:0,tag:"natural_rate",type:"trap",objective:"LO7.1",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_natural_rate_policy",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"confuses_actual_unemployment_with_natural_rate",feedback:"Actual unemployment can fall below the natural rate temporarily, but that does not mean the natural rate is zero."},
{id:3005,sourceGame:"nationalEngine",q:"The Warden opens two gates: 'One reduces search time; one reduces wage rigidity.' What happens to the natural rate?",options:["It likely falls because frictional and structural unemployment fall","It rises because all policies increase job separation","It is unchanged because policy cannot affect labor markets","It becomes equal to cyclical unemployment"],a:0,tag:"natural_rate",type:"interpretation",objective:"LO7.1",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_natural_rate_policy",primarySkill:"natural_rate_definition",secondarySkills:["frictional_vs_other_unemployment"],repairSkill:"natural_rate_definition",commonError:"misses_natural_rate_components",feedback:"Reducing search time lowers frictional unemployment, and reducing wage rigidity lowers structural unemployment. Both reduce the natural rate."},

// --- LO7.2: JOB FLOWS ---
{id:3006,sourceGame:"nationalEngine",q:"The Warden points to two doors: 'One leaves work. One finds work.' What does the job separation rate measure?",options:["The fraction of employed workers who leave or lose jobs","The fraction of unemployed workers who find jobs","The fraction of adults outside the labor force","The fraction of workers paid above equilibrium"],a:0,tag:"job_separation",type:"definition",objective:"LO7.2",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_job_flows",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"reverses_separation_and_finding_rates",feedback:"The separation rate measures the fraction of employed workers who leave or lose jobs."},
{id:3007,sourceGame:"nationalEngine",q:"The Warden asks for the other door: 'What does the job finding rate measure?'",options:["The fraction of unemployed workers who find jobs","The fraction of employed workers who lose jobs","The fraction of workers covered by unions","The fraction of output paid to labor"],a:0,tag:"job_finding",type:"definition",objective:"LO7.2",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_job_flows",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"reverses_finding_and_separation_rates",feedback:"The job finding rate measures the fraction of unemployed workers who find jobs."},
{id:3008,sourceGame:"nationalEngine",q:"The Warden balances the flow: 'At steady state, what must be true?'",options:["Job losses from employment equal job findings from unemployment","Every unemployed worker finds a job immediately","The separation rate must be zero","The labor force participation rate equals GDP growth"],a:0,tag:"steady_state_unemployment",type:"interpretation",objective:"LO7.2",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_job_flows",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"misses_flow_balance_condition",feedback:"At steady state, flows into unemployment equal flows out of unemployment."},

// --- LO7.2: STEADY-STATE CALCULATION ---
{id:3009,sourceGame:"nationalEngine",q:"The Warden gives the numbers: 's = 0.02 and f = 0.18.' What is steady-state unemployment?",options:["10%","2%","18%","20%"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_steady_state",primarySkill:"steady_state_unemployment_calculation",secondarySkills:[],repairSkill:"steady_state_unemployment_calculation",commonError:"divides_s_by_f_only",feedback:"u = s/(s+f) = 0.02/(0.02+0.18) = 10%."},
{id:3010,sourceGame:"nationalEngine",q:"The Warden changes the flow: 's stays at 0.03, but f rises from 0.27 to 0.47.' What happens to steady-state unemployment?",options:["It falls","It rises","It stays fixed","It becomes equal to f"],a:0,tag:"steady_state_unemployment",type:"interpretation",objective:"LO7.2",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_steady_state",primarySkill:"job_finding_job_separation_logic",secondarySkills:["steady_state_unemployment_calculation"],repairSkill:"job_finding_job_separation_logic",commonError:"gets_finding_rate_effect_backward",feedback:"A higher job finding rate lowers steady-state unemployment because workers leave unemployment faster."},
{id:3011,sourceGame:"nationalEngine",q:"The Warden sharpens the test: 's = 0.04 and f = 0.36. Last month unemployment was 12%.' What is the steady-state rate and direction?",options:["10%, so unemployment falls","10%, so unemployment rises","11.1%, so unemployment falls","40%, so unemployment rises"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_steady_state",primarySkill:"steady_state_unemployment_calculation",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"steady_state_unemployment_calculation",commonError:"calculates_rate_but_misreads_direction",feedback:"u = 0.04/(0.04+0.36) = 10%. Since 10% is below 12%, unemployment falls toward steady state."},

// --- LO7.3: FRICTIONAL UNEMPLOYMENT ---
{id:3012,sourceGame:"nationalEngine",q:"The Warden hears movement: 'Workers are searching for better job matches.' What type of unemployment is this?",options:["Frictional unemployment","Structural unemployment","Cyclical unemployment","Measured inflation"],a:0,tag:"frictional_unemployment",type:"definition",objective:"LO7.3",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_frictional",primarySkill:"frictional_vs_other_unemployment",secondarySkills:[],repairSkill:"frictional_vs_other_unemployment",commonError:"confuses_frictional_and_structural_unemployment",feedback:"Frictional unemployment comes from job search and matching time."},
{id:3013,sourceGame:"nationalEngine",q:"The Warden shows a factory closing and a growing tech sector: 'Workers need retraining and relocation.' What does this mainly create first?",options:["Frictional unemployment from sectoral shifts","Structural unemployment from a wage floor only","Cyclical unemployment from lower spending only","No unemployment because jobs exist somewhere"],a:0,tag:"sectoral_shifts",type:"interpretation",objective:"LO7.3",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_frictional",primarySkill:"sectoral_shift_matching",secondarySkills:["frictional_vs_other_unemployment"],repairSkill:"sectoral_shift_matching",commonError:"misses_sectoral_shift_matching_problem",feedback:"Sectoral shifts create frictional unemployment because workers need time to match with new jobs."},
{id:3014,sourceGame:"nationalEngine",q:"The Warden offers a policy lever: 'Which tool best reduces frictional unemployment?'",options:["Better job information and matching services","A wage floor above equilibrium","A union contract restricting entry","A higher GDP deflator"],a:0,tag:"frictional_unemployment",type:"policy",objective:"LO7.3",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_frictional",primarySkill:"sectoral_shift_matching",secondarySkills:[],repairSkill:"sectoral_shift_matching",commonError:"chooses_structural_policy_for_frictional_problem",feedback:"Better job information and matching services reduce search time and frictional unemployment."},

// --- LO7.3: STRUCTURAL UNEMPLOYMENT ---
{id:3015,sourceGame:"nationalEngine",q:"The Warden locks the wage gate: 'The wage is held above equilibrium.' What type of unemployment can result?",options:["Structural unemployment","Frictional unemployment","Cyclical unemployment","Price-index unemployment"],a:0,tag:"structural_unemployment",type:"definition",objective:"LO7.3",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_structural",primarySkill:"wage_rigidity_structural_unemployment",secondarySkills:[],repairSkill:"wage_rigidity_structural_unemployment",commonError:"confuses_structural_with_frictional_unemployment",feedback:"Structural unemployment can result when wages are rigid above equilibrium and jobs are rationed."},
{id:3016,sourceGame:"nationalEngine",q:"The Warden points to the minimum wage graph: 'A binding wage floor sits above equilibrium.' What happens in the labor market?",options:["Labor supplied exceeds labor demanded","Labor demanded exceeds labor supplied","Labor supply and demand both disappear","The CPI basket shifts right"],a:0,tag:"minimum_wage",type:"graph_interpretation",objective:"LO7.3",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_structural",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"minimum_wage_structural_unemployment",commonError:"gets_labor_surplus_backward",feedback:"A binding wage floor creates a surplus of labor: more workers want jobs than firms want to hire.",image:"minimumwage.webp"},
{id:3017,sourceGame:"nationalEngine",q:"The Warden asks why firms might choose high wages: 'They pay above equilibrium to reduce shirking and turnover.' What theory is this?",options:["Efficiency wage theory","CPI substitution theory","GDP deflator theory","Loanable funds theory"],a:0,tag:"efficiency_wages",type:"interpretation",objective:"LO7.3",difficulty:"mediumBoss",conceptCluster:"boss_chapter_7_structural",primarySkill:"efficiency_wage_theory",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"efficiency_wage_theory",commonError:"misses_efficiency_wage_channels",feedback:"Efficiency wage theory says firms may pay above-equilibrium wages to improve effort, reduce turnover, or attract better workers."}
],

finalBoss:[
// --- LO3.1: OUTPUT AND PRODUCTION ---
{id:4000,sourceGame:"nationalEngine",q:"The Comptroller speaks: 'The engine begins with production.' In the Chapter 3 model, what determines total output?",options:["Capital, labor, and technology","Consumption, taxes, and CPI","Unemployment, inflation, and imports","Government purchases alone"],a:0,tag:"production",type:"definition",objective:"LO3.1",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_production",primarySkill:"production_function_output",secondarySkills:[],repairSkill:"production_function_output",commonError:"confuses_output_determinants_with_demand_components",feedback:"In the Chapter 3 model, output is determined by the production function using capital, labor, and technology."},
{id:4001,sourceGame:"nationalEngine",q:"The Comptroller fixes the inputs: 'K, L, and A do not move.' Government purchases rise. What happens to output and investment pressure in this model?",options:["Output stays fixed while investment is crowded out","Output rises by the full increase in government purchases","Output falls because government spending always lowers GDP","Output becomes equal to investment"],a:0,tag:"production",type:"interpretation",objective:"LO3.1",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_production",primarySkill:"production_function_output",secondarySkills:["fiscal_policy_crowding_out"],repairSkill:"production_function_output",commonError:"imports_multiplier_logic_into_fixed_output_model",feedback:"With K, L, and A fixed, output is fixed. Higher government purchases lower saving, raise r, and pressure investment down."},
{id:4002,sourceGame:"nationalEngine",q:"The Comptroller gives the function: 'Y = A K^0.4 L^0.6.' Technology rises 2%, capital rises 5%, and labor rises 1%. What is approximate output growth?",options:["4.6%","8.0%","3.0%","6.0%"],a:0,tag:"production_function",type:"calculation",objective:"LO3.1",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_production",primarySkill:"production_function_output",secondarySkills:["cobb_douglas_factor_share_calculation"],repairSkill:"production_function_output",commonError:"adds_input_growth_without_weights",feedback:"Output growth is about 2% + 0.4(5%) + 0.6(1%) = 4.6%."},

// --- LO3.2: FACTOR PRICES ---
{id:4003,sourceGame:"nationalEngine",q:"The Comptroller weighs labor: 'A firm faces a nominal wage of $80 and output price of $5.' What real wage matters for hiring?",options:["16 units of output","85 units of output","75 units of output","400 units of output"],a:0,tag:"factor_prices",type:"calculation",objective:"LO3.2",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_factor_prices",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"multiplies_nominal_wage_by_price",feedback:"The real wage is W/P = 80/5 = 16 units of output."},
{id:4004,sourceGame:"nationalEngine",q:"The Comptroller reads the MPL schedule: 'MPL = 30, 24, 18, 12, 6. The real wage is 18.' How many workers should be hired?",options:["3","2","4","5"],a:0,tag:"labor_demand",type:"calculation",objective:"LO3.2",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_factor_prices",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:["diminishing_marginal_product"],repairSkill:"labor_demand_mpl_real_wage",commonError:"hires_worker_with_mpl_below_real_wage",feedback:"The firm hires workers until MPL equals or just reaches the real wage. The first three workers have MPL at least 18."},
{id:4005,sourceGame:"nationalEngine",q:"The Comptroller breaks a machine line: 'Capital falls while labor is unchanged.' What factor-price pattern follows?",options:["MPK rises and MPL falls","MPK falls and MPL rises","Both MPK and MPL rise","Both MPK and MPL fall"],a:0,tag:"factor_prices",type:"interpretation",objective:"LO3.2",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_factor_prices",primarySkill:"diminishing_marginal_product",secondarySkills:["labor_demand_mpl_real_wage"],repairSkill:"diminishing_marginal_product",commonError:"misses_cross_factor_effects",feedback:"Capital becomes scarcer, raising MPK. Workers have less capital to use, so MPL falls."},

// --- LO3.3: INCOME DISTRIBUTION ---
{id:4006,sourceGame:"nationalEngine",q:"The Comptroller opens the income vault: 'Alpha is 0.35 and total income is 10,000.' What are capital and labor income?",options:["Capital 3500; labor 6500","Capital 6500; labor 3500","Capital 3500; labor 3500","Capital 6500; labor 6500"],a:0,tag:"factor_shares",type:"calculation",objective:"LO3.3",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_income_distribution",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:[],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"reverses_capital_and_labor_shares",feedback:"Capital receives alpha, or 35% of income. Labor receives 65%. That gives 3500 and 6500."},
{id:4007,sourceGame:"nationalEngine",q:"The Comptroller gives the growth record: 'Alpha = 0.3, capital rises 6%, labor rises 3%, and technology rises 1%.' What is approximate output growth?",options:["4.9%","10.0%","3.7%","6.3%"],a:0,tag:"cobb_douglas",type:"calculation",objective:"LO3.3",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_income_distribution",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:["production_function_output"],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"misweights_capital_and_labor_growth",feedback:"Output growth is about 1% + 0.3(6%) + 0.7(3%) = 4.9%."},
{id:4008,sourceGame:"nationalEngine",q:"The Comptroller challenges the theory: 'Workers are not paid their marginal products because bargaining power is weak.' Which assumption is being strained?",options:["Competitive factor markets pay factors their marginal products","CPI always uses a fixed basket","GDP always equals exports minus imports","The natural rate is always zero"],a:0,tag:"income_distribution",type:"interpretation",objective:"LO3.3",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_income_distribution",primarySkill:"factor_income_distribution",secondarySkills:[],repairSkill:"factor_income_distribution",commonError:"misses_marginal_product_distribution_assumption",feedback:"The neoclassical distribution story assumes factors are paid their marginal products in competitive factor markets."},

// --- LO3.4: CONSUMPTION AND INVESTMENT DEMAND ---
{id:4009,sourceGame:"nationalEngine",q:"The Comptroller unlocks demand: 'C = 300 + 0.75(Y - T), Y = 4000, and T = 800.' What is consumption?",options:["2700","3000","3300","2400"],a:0,tag:"consumption_function",type:"calculation",objective:"LO3.4",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_goods_demand",primarySkill:"consumption_function_calculation",secondarySkills:["mpc_disposable_income"],repairSkill:"consumption_function_calculation",commonError:"uses_income_instead_of_disposable_income",feedback:"Disposable income is 3200. Consumption = 300 + 0.75(3200) = 2700."},
{id:4010,sourceGame:"nationalEngine",q:"The Comptroller cuts taxes by 200: 'MPC = 0.8 and output is fixed.' What happens to consumption and national saving?",options:["Consumption rises 160; national saving falls 160","Consumption rises 40; national saving falls 40","Consumption rises 200; national saving is unchanged","Consumption falls 160; national saving rises 160"],a:0,tag:"consumption",type:"calculation",objective:"LO3.4",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_goods_demand",primarySkill:"mpc_disposable_income",secondarySkills:["saving_identity_calculation"],repairSkill:"mpc_disposable_income",commonError:"uses_mps_or_ignores_saving_effect",feedback:"A 200 tax cut raises disposable income by 200, so consumption rises by 0.8 × 200 = 160. With Y and G fixed, national saving falls by 160."},
{id:4011,sourceGame:"nationalEngine",q:"The Comptroller points to the investment function: 'Nominal r is 10%, inflation is 3%, and I = 2500 - 200r.' What is investment?",options:["1100","500","1900","1700"],a:0,tag:"investment",type:"calculation",objective:"LO3.4",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_goods_demand",primarySkill:"real_interest_investment_calculation",secondarySkills:["investment_interest_rate_relationship"],repairSkill:"real_interest_investment_calculation",commonError:"uses_nominal_rate_instead_of_real_rate",feedback:"The real interest rate is 10 - 3 = 7. Investment = 2500 - 200(7) = 1100."},

// --- LO3.5: SAVING AND FISCAL POLICY ---
{id:4012,sourceGame:"nationalEngine",q:"The Comptroller demands the saving split: 'Y = 5000, T = 1200, C = 3100, and G = 1500.' What are private, public, and national saving?",options:["Private 700; public -300; national 400","Private 400; public 300; national 700","Private 700; public 300; national 1000","Private -300; public 700; national 400"],a:0,tag:"national_saving",type:"calculation",objective:"LO3.5",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_saving_policy",primarySkill:"saving_identity_calculation",secondarySkills:[],repairSkill:"saving_identity_calculation",commonError:"reverses_private_and_public_saving",feedback:"Private saving = 5000 - 1200 - 3100 = 700. Public saving = 1200 - 1500 = -300. National saving = 400."},
{id:4013,sourceGame:"nationalEngine",q:"The Comptroller raises both taxes and spending by 500: 'MPC = 0.6 and output is fixed.' What happens to national saving?",options:["It falls by 200","It rises by 200","It is unchanged","It falls by 500"],a:0,tag:"fiscal_policy",type:"calculation",objective:"LO3.5",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_saving_policy",primarySkill:"fiscal_policy_crowding_out",secondarySkills:["mpc_disposable_income"],repairSkill:"fiscal_policy_crowding_out",commonError:"assumes_balanced_budget_change_has_no_saving_effect",feedback:"Higher taxes reduce consumption by 300, raising saving by 300. Higher G lowers saving by 500. Net national saving falls by 200."},
{id:4014,sourceGame:"nationalEngine",q:"The Comptroller sees a deficit: 'Government purchases rise while taxes and output are fixed.' What is the loanable funds chain?",options:["National saving falls, r rises, and investment falls","National saving rises, r falls, and investment rises","Investment demand shifts right, r rises, and saving rises","Consumption falls, r falls, and investment rises"],a:0,tag:"crowding_out",type:"interpretation",objective:"LO3.5",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_saving_policy",primarySkill:"fiscal_policy_crowding_out",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"fiscal_policy_crowding_out",commonError:"gets_crowding_out_chain_backward",feedback:"Higher G lowers public and national saving. In loanable funds, r rises and private investment is crowded out."},

// --- LO3.5: LOANABLE FUNDS EQUILIBRIUM ---
{id:4015,sourceGame:"nationalEngine",q:"The Comptroller sets the market: 'National saving is 900 and investment demand is I = 1500 - 100r.' What is equilibrium r?",options:["6","9","15","4"],a:0,tag:"loanable_funds",type:"calculation",objective:"LO3.5",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_loanable_funds",primarySkill:"saving_investment_equilibrium",secondarySkills:["real_interest_investment_calculation"],repairSkill:"saving_investment_equilibrium",commonError:"does_not_set_saving_equal_to_investment",feedback:"Set saving equal to investment: 900 = 1500 - 100r. Then r = 6."},
{id:4016,sourceGame:"nationalEngine",q:"The Comptroller shifts the graph: 'Saving shifts left and investment demand shifts right.' What is guaranteed?",options:["The real interest rate rises","Investment rises","Investment falls","The real interest rate falls"],a:0,tag:"loanable_funds",type:"graph_interpretation",objective:"LO3.5",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_loanable_funds",primarySkill:"loanable_funds_graph_shifts",secondarySkills:["investment_demand_vs_saving_shift"],repairSkill:"loanable_funds_graph_shifts",commonError:"claims_quantity_effect_when_ambiguous",feedback:"Both lower saving and higher investment demand push the real interest rate upward. The investment quantity effect is ambiguous.",image:"loanablefunds.webp"},
{id:4017,sourceGame:"nationalEngine",q:"The Comptroller makes the final demand: 'Investment demand rises, but saving is vertical and fixed.' What happens first in loanable funds?",options:["The real interest rate rises more than investment quantity","Investment quantity rises with no interest-rate change","Saving shifts right automatically","The CPI adjusts until investment falls"],a:0,tag:"loanable_funds",type:"graph_interpretation",objective:"LO3.5",difficulty:"finalBoss",conceptCluster:"boss_chapter_3_loanable_funds",primarySkill:"investment_demand_vs_saving_shift",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"investment_demand_vs_saving_shift",commonError:"ignores_vertical_saving_constraint",feedback:"When saving is vertical and fixed, stronger investment demand mainly bids up the real interest rate rather than greatly raising investment quantity.",image:"loanablefunds.webp"}
],
   
easy:[
{id:1,sourceGame:"nationalEngine",q:"What does GDP measure in the economy?",options:["Total income and total spending on final goods and services","Only the value of financial assets sold during the year","Only government spending and tax revenue","The total number of people employed in production"],a:0,tag:"gdp",type:"definition",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"gdp_components_identity",secondarySkills:[],repairSkill:"gdp_components_identity",commonError:"confuses_gdp_with_financial_assets",feedback:"GDP measures total income and total expenditure on final goods and services produced in the economy."},
{id:2,sourceGame:"nationalEngine",q:"Which item is counted in GDP as consumption?",options:["A household pays for a haircut","A person buys shares of stock","The government sends a Social Security check","A firm buys land from another firm"],a:0,tag:"gdp",type:"identification",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"gdp_inclusion_exclusion",secondarySkills:[],repairSkill:"gdp_inclusion_exclusion",commonError:"counts_financial_or_transfer_payment_as_gdp",feedback:"A haircut is a currently produced service purchased by a household, so it counts as consumption in GDP."},
{id:3,sourceGame:"nationalEngine",q:"Why are intermediate goods usually excluded from GDP?",options:["Counting them would double count production","They are always imported goods","They are counted only in the CPI","They are not sold by firms"],a:0,tag:"gdp",type:"definition",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"gdp_inclusion_exclusion",secondarySkills:[],repairSkill:"gdp_inclusion_exclusion",commonError:"misunderstands_final_vs_intermediate_goods",feedback:"Intermediate goods are excluded because their value is already included in the final good."},
{id:4,sourceGame:"nationalEngine",q:"Which GDP component includes purchases of new factories, machines, and inventories?",options:["Investment","Consumption","Government purchases","Net exports"],a:0,tag:"gdp_components",type:"identification",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"gdp_components_identity",secondarySkills:[],repairSkill:"gdp_components_identity",commonError:"confuses_investment_with_financial_investing",feedback:"Investment in GDP means spending on capital goods, structures, and inventories, not buying stocks or bonds."},
{id:5,sourceGame:"nationalEngine",q:"Which formula correctly states the expenditure approach to GDP?",options:["Y = C + I + G + NX","Y = C + T + G + NX","Y = W + R + P + NX","Y = C - I + G - NX"],a:0,tag:"gdp_components",type:"definition",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"gdp_expenditure_calculation",secondarySkills:[],repairSkill:"gdp_expenditure_calculation",commonError:"misstates_gdp_identity",feedback:"The expenditure approach is Y = C + I + G + NX."},
{id:6,sourceGame:"nationalEngine",q:"Net exports equal which expression?",options:["Exports minus imports","Imports minus exports","Consumption minus investment","Government purchases minus taxes"],a:0,tag:"gdp_components",type:"definition",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"gdp_components_identity",secondarySkills:[],repairSkill:"gdp_components_identity",commonError:"reverses_exports_and_imports",feedback:"Net exports are exports minus imports."},
{id:7,sourceGame:"nationalEngine",q:"Which statement best describes nominal GDP?",options:["GDP measured using current-year prices","GDP measured using base-year prices","GDP adjusted for unemployment","GDP excluding government purchases"],a:0,tag:"real_nominal_gdp",type:"definition",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"real_vs_nominal_gdp",secondarySkills:[],repairSkill:"real_vs_nominal_gdp",commonError:"confuses_nominal_and_real_gdp",feedback:"Nominal GDP values output using current-year prices."},
{id:8,sourceGame:"nationalEngine",q:"Which statement best describes real GDP?",options:["GDP measured using base-year prices","GDP measured using current-year prices","GDP that excludes investment","GDP that only counts household income"],a:0,tag:"real_nominal_gdp",type:"definition",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"real_vs_nominal_gdp",secondarySkills:[],repairSkill:"real_vs_nominal_gdp",commonError:"confuses_real_and_nominal_gdp",feedback:"Real GDP uses base-year prices so changes in output are separated from price changes."},
{id:9,sourceGame:"nationalEngine",q:"What does the GDP deflator measure?",options:["The overall price level of currently produced goods and services","The unemployment rate among discouraged workers","The total number of goods in the CPI basket","The quantity of imports in GDP"],a:0,tag:"gdp_deflator",type:"definition",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"gdp_deflator_inflation",secondarySkills:[],repairSkill:"gdp_deflator_inflation",commonError:"confuses_price_level_with_quantity",feedback:"The GDP deflator is a broad price index for goods and services included in GDP."},
{id:10,sourceGame:"nationalEngine",q:"What does the CPI measure?",options:["The cost of a typical consumer basket","The total output of all final goods","The number of people unemployed","The value of all business investment"],a:0,tag:"cpi",type:"definition",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"cpi_measurement",secondarySkills:[],repairSkill:"cpi_measurement",commonError:"confuses_cpi_with_gdp",feedback:"The CPI measures the cost of a typical basket of consumer goods and services."},
{id:11,sourceGame:"nationalEngine",q:"Why can the CPI overstate the cost of living?",options:["It uses a fixed basket and misses substitution","It excludes all consumer goods","It counts only imported goods","It ignores prices completely"],a:0,tag:"cpi_bias",type:"identification",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"cpi_bias_limitations",secondarySkills:[],repairSkill:"cpi_bias_limitations",commonError:"misses_substitution_bias",feedback:"Because the CPI uses a fixed basket, it may miss consumers substituting toward cheaper goods."},
{id:12,sourceGame:"nationalEngine",q:"Which price measure uses a fixed basket of consumer goods?",options:["CPI","GDP deflator","Real GDP","Labor force participation rate"],a:0,tag:"cpi",type:"identification",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"price_index_comparison",secondarySkills:[],repairSkill:"price_index_comparison",commonError:"confuses_cpi_with_gdp_deflator",feedback:"The CPI uses a fixed basket of consumer goods and services."},
{id:13,sourceGame:"nationalEngine",q:"Which item is included in the CPI but not the GDP deflator?",options:["An imported consumer good","A domestically produced machine bought by a firm","A newly built government office","A domestically produced export"],a:0,tag:"gdp_deflator_vs_cpi",type:"identification",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"price_index_comparison",secondarySkills:[],repairSkill:"price_index_comparison",commonError:"misses_import_treatment",feedback:"Imported consumer goods are included in the CPI but excluded from the GDP deflator."},
{id:14,sourceGame:"nationalEngine",q:"Who is counted as unemployed in the official labor force statistics?",options:["A person without a job who looked for work recently","A retired person who does not want a job","A full-time student not looking for work","A discouraged worker who stopped searching"],a:0,tag:"labor_force",type:"definition",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"employment_status_classification",secondarySkills:[],repairSkill:"employment_status_classification",commonError:"counts_nonsearchers_as_unemployed",feedback:"To be counted as unemployed, a person must be without a job and actively looking for work."},
{id:15,sourceGame:"nationalEngine",q:"The labor force equals which group?",options:["Employed plus unemployed","Employed plus retired","Unemployed plus discouraged workers","Adult population minus employed"],a:0,tag:"labor_force",type:"definition",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"labor_force_statistics_calculation",secondarySkills:[],repairSkill:"labor_force_statistics_calculation",commonError:"misdefines_labor_force",feedback:"The labor force includes the employed and the unemployed."},
{id:16,sourceGame:"nationalEngine",q:"The unemployment rate is calculated as unemployed divided by what?",options:["Labor force","Adult population","Employed workers","Total population"],a:0,tag:"unemployment_rate",type:"definition",objective:"LO2.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"labor_force_statistics_calculation",secondarySkills:[],repairSkill:"labor_force_statistics_calculation",commonError:"uses_adult_population_instead_of_labor_force",feedback:"The unemployment rate equals unemployed divided by the labor force, times 100."},
{id:17,sourceGame:"nationalEngine",q:"The labor force participation rate is labor force divided by what?",options:["Adult population","Unemployed workers","Employed workers","GDP"],a:0,tag:"lfpr",type:"definition",objective:"LO2.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"labor_force_statistics_calculation",secondarySkills:[],repairSkill:"labor_force_statistics_calculation",commonError:"confuses_lfpr_with_unemployment_rate",feedback:"The labor force participation rate equals labor force divided by adult population, times 100."},
{id:18,sourceGame:"nationalEngine",q:"Which survey can count a person with two payroll jobs twice?",options:["Establishment survey","Current Population Survey","CPI survey","GDP deflator survey"],a:0,tag:"labor_statistics",type:"identification",objective:"LO2.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"employment_status_classification",secondarySkills:[],repairSkill:"employment_status_classification",commonError:"confuses_household_and_establishment_surveys",feedback:"The establishment survey counts jobs on payrolls, so a person with two jobs may be counted twice."},
{id:19,sourceGame:"nationalEngine",q:"What determines total output in the basic Chapter 3 model?",options:["Capital, labor, and technology","Only government spending","Only the unemployment rate","Imports and exports only"],a:0,tag:"production",type:"definition",objective:"LO3.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"production_function_output",secondarySkills:[],repairSkill:"production_function_output",commonError:"misses_inputs_to_output",feedback:"In the basic model, total output is determined by capital, labor, and technology."},
{id:20,sourceGame:"nationalEngine",q:"What is a production function?",options:["A relationship showing how inputs determine output","A rule for calculating the CPI basket","A measure of unemployment duration","A policy rule for tax collection"],a:0,tag:"production_function",type:"definition",objective:"LO3.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"production_function_output",secondarySkills:[],repairSkill:"production_function_output",commonError:"misidentifies_production_function",feedback:"A production function shows how inputs like capital and labor produce output."},
{id:21,sourceGame:"nationalEngine",q:"Constant returns to scale means what?",options:["Doubling inputs doubles output","Doubling inputs less than doubles output","Doubling inputs more than doubles output","Output falls when inputs rise"],a:0,tag:"returns_to_scale",type:"definition",objective:"LO3.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"returns_to_scale_classification",secondarySkills:[],repairSkill:"returns_to_scale_classification",commonError:"confuses_returns_to_scale_types",feedback:"Constant returns to scale means doubling inputs doubles output."},
{id:22,sourceGame:"nationalEngine",q:"Diminishing marginal product means what?",options:["Each additional unit of an input adds less output than before","Total output must always fall when more labor is added","The real wage must always be zero","Capital and labor cannot be used together"],a:0,tag:"marginal_product",type:"definition",objective:"LO3.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"diminishing_marginal_product",secondarySkills:[],repairSkill:"diminishing_marginal_product",commonError:"confuses_marginal_and_total_product",feedback:"Diminishing marginal product means the extra output from another input eventually falls."},
{id:23,sourceGame:"nationalEngine",q:"A competitive firm hires labor up to the point where MPL equals what?",options:["The real wage","The nominal money supply","The CPI","The unemployment rate"],a:0,tag:"labor_demand",type:"definition",objective:"LO3.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"misses_mpl_real_wage_condition",feedback:"A competitive firm hires labor until MPL equals the real wage, W/P."},
{id:24,sourceGame:"nationalEngine",q:"The real wage is best described as what?",options:["The wage measured in units of output","The wage measured only in dollars","The wage before inflation exists","The wage paid only to capital owners"],a:0,tag:"factor_prices",type:"definition",objective:"LO3.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"confuses_nominal_and_real_wage",feedback:"The real wage is the wage measured in terms of output, not just dollars."},
{id:25,sourceGame:"nationalEngine",q:"Under the neoclassical theory of distribution, factors are paid according to what?",options:["Their marginal products","Their average tax rates","The CPI basket","The trade balance"],a:0,tag:"income_distribution",type:"definition",objective:"LO3.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"factor_income_distribution",secondarySkills:[],repairSkill:"factor_income_distribution",commonError:"misses_marginal_product_distribution",feedback:"The neoclassical theory says factors are paid according to their marginal products."},
{id:26,sourceGame:"nationalEngine",q:"In a Cobb-Douglas production function, alpha usually represents what?",options:["Capital’s share of income","The unemployment rate","The inflation rate","Government purchases"],a:0,tag:"cobb_douglas",type:"definition",objective:"LO3.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:[],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"misreads_alpha_in_cobb_douglas",feedback:"In the standard Cobb-Douglas setup, alpha represents capital’s share of income."},
{id:27,sourceGame:"nationalEngine",q:"If alpha is capital’s share, labor’s share is what?",options:["1 - alpha","alpha + 1","alpha squared","1 divided by alpha"],a:0,tag:"factor_shares",type:"definition",objective:"LO3.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:[],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"misses_labor_share_formula",feedback:"Labor’s share is 1 - alpha when alpha is capital’s share."},
{id:28,sourceGame:"nationalEngine",q:"Consumption depends most directly on what in the Chapter 3 model?",options:["Disposable income","The money multiplier","The unemployment duration table","The number of banks"],a:0,tag:"consumption",type:"definition",objective:"LO3.4",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"mpc_disposable_income",secondarySkills:[],repairSkill:"mpc_disposable_income",commonError:"misses_disposable_income_channel",feedback:"Consumption depends on disposable income, Y - T."},
{id:29,sourceGame:"nationalEngine",q:"The marginal propensity to consume measures what?",options:["How much consumption changes when disposable income rises by one dollar","How much unemployment changes when GDP rises","How much investment changes when imports rise","How much the CPI basket changes when quality improves"],a:0,tag:"mpc",type:"definition",objective:"LO3.4",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"mpc_disposable_income",secondarySkills:[],repairSkill:"mpc_disposable_income",commonError:"misdefines_mpc",feedback:"The MPC is the change in consumption from one more dollar of disposable income."},
{id:30,sourceGame:"nationalEngine",q:"Investment demand is inversely related to what?",options:["The real interest rate","The labor force participation rate","The CPI basket size","The natural rate formula"],a:0,tag:"investment",type:"definition",objective:"LO3.4",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"investment_interest_rate_relationship",secondarySkills:[],repairSkill:"investment_interest_rate_relationship",commonError:"misses_interest_rate_investment_relationship",feedback:"Investment demand falls when the real interest rate rises and rises when the real interest rate falls."},
{id:31,sourceGame:"nationalEngine",q:"A lower real interest rate usually causes what along a fixed investment function?",options:["A movement toward higher investment","A movement toward lower investment","A leftward shift of saving","A higher natural rate of unemployment"],a:0,tag:"investment_function",type:"identification",objective:"LO3.4",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"investment_function_movement_vs_shift",secondarySkills:[],repairSkill:"investment_function_movement_vs_shift",commonError:"confuses_movement_with_shift",feedback:"A lower real interest rate causes a movement along the investment function toward more investment."},
{id:32,sourceGame:"nationalEngine",q:"What does national saving equal in a closed economy equilibrium?",options:["Investment","Imports","Government purchases","The CPI"],a:0,tag:"saving_investment",type:"definition",objective:"LO3.5",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"saving_investment_equilibrium",secondarySkills:[],repairSkill:"saving_investment_equilibrium",commonError:"misses_saving_equals_investment",feedback:"In a closed economy, national saving equals investment."},
{id:33,sourceGame:"nationalEngine",q:"Private saving is best described as what?",options:["Disposable income minus consumption","Taxes minus government purchases","Exports minus imports","Nominal GDP minus real GDP"],a:0,tag:"private_saving",type:"definition",objective:"LO3.5",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"private_public_national_saving",secondarySkills:[],repairSkill:"private_public_national_saving",commonError:"confuses_private_and_public_saving",feedback:"Private saving is disposable income minus consumption, or Y - T - C."},
{id:34,sourceGame:"nationalEngine",q:"Public saving is best described as what?",options:["Taxes minus government purchases","Consumption minus taxes","Investment minus saving","Exports minus imports"],a:0,tag:"public_saving",type:"definition",objective:"LO3.5",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"private_public_national_saving",secondarySkills:[],repairSkill:"private_public_national_saving",commonError:"confuses_public_and_private_saving",feedback:"Public saving is tax revenue minus government purchases, or T - G."},
{id:35,sourceGame:"nationalEngine",q:"In the loanable funds model, what variable balances saving and investment?",options:["The real interest rate","The unemployment rate","The CPI","The nominal wage"],a:0,tag:"loanable_funds",type:"definition",objective:"LO3.5",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"saving_investment_equilibrium",secondarySkills:[],repairSkill:"saving_investment_equilibrium",commonError:"misses_interest_rate_as_equilibrating_variable",feedback:"The real interest rate adjusts to balance saving and investment."},
{id:36,sourceGame:"nationalEngine",q:"Crowding out occurs when expansionary fiscal policy raises the real interest rate and reduces what?",options:["Private investment","The CPI basket","The labor force","Nominal GDP accounting"],a:0,tag:"crowding_out",type:"definition",objective:"LO3.5",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"fiscal_policy_crowding_out",secondarySkills:[],repairSkill:"fiscal_policy_crowding_out",commonError:"misses_crowding_out_channel",feedback:"Crowding out is the reduction in private investment caused by higher real interest rates after fiscal expansion."},
{id:37,sourceGame:"nationalEngine",q:"The natural rate of unemployment is best described as what?",options:["The average unemployment rate around which the economy fluctuates","The unemployment rate that must always equal zero","Only unemployment caused by recessions","The number of unemployed divided by adult population"],a:0,tag:"natural_rate",type:"definition",objective:"LO7.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"confuses_natural_and_cyclical_unemployment",feedback:"The natural rate is the average rate of unemployment around which the economy fluctuates."},
{id:38,sourceGame:"nationalEngine",q:"Cyclical unemployment occurs when unemployment moves how relative to the natural rate?",options:["Above or below the natural rate over the business cycle","Permanently to zero","Only because of minimum wage laws","Only because of job search time"],a:0,tag:"natural_rate",type:"identification",objective:"LO7.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"confuses_cyclical_with_natural_unemployment",feedback:"Cyclical unemployment is the movement of unemployment around the natural rate over the business cycle."},
{id:39,sourceGame:"nationalEngine",q:"The job separation rate measures what?",options:["The fraction of employed workers who leave or lose jobs","The fraction of unemployed workers who find jobs","The fraction of adults not in the labor force","The fraction of output counted in investment"],a:0,tag:"job_separation",type:"definition",objective:"LO7.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"reverses_separation_and_finding_rates",feedback:"The separation rate is the fraction of employed workers who leave or lose jobs."},
{id:40,sourceGame:"nationalEngine",q:"The job finding rate measures what?",options:["The fraction of unemployed workers who find jobs","The fraction of employed workers who lose jobs","The fraction of workers paid the minimum wage","The fraction of income paid to labor"],a:0,tag:"job_finding",type:"definition",objective:"LO7.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"reverses_finding_and_separation_rates",feedback:"The job finding rate is the fraction of unemployed workers who find jobs."},
{id:41,sourceGame:"nationalEngine",q:"If job finding rises while job separation is unchanged, what happens to steady-state unemployment?",options:["It falls","It rises","It must become zero immediately","It becomes equal to GDP"],a:0,tag:"steady_state_unemployment",type:"identification",objective:"LO7.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"gets_finding_rate_effect_backward",feedback:"A higher job finding rate lowers steady-state unemployment."},
{id:42,sourceGame:"nationalEngine",q:"If job separation rises while job finding is unchanged, what happens to steady-state unemployment?",options:["It rises","It falls","It must become zero","It becomes the labor force participation rate"],a:0,tag:"steady_state_unemployment",type:"identification",objective:"LO7.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"gets_separation_rate_effect_backward",feedback:"A higher job separation rate raises steady-state unemployment."},
{id:43,sourceGame:"nationalEngine",q:"Frictional unemployment is mainly caused by what?",options:["Time spent searching and matching workers to jobs","Wages held above equilibrium by policy or institutions","A permanent collapse in all production","Financial assets being excluded from GDP"],a:0,tag:"frictional_unemployment",type:"definition",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"frictional_vs_other_unemployment",secondarySkills:[],repairSkill:"frictional_vs_other_unemployment",commonError:"confuses_frictional_and_structural_unemployment",feedback:"Frictional unemployment comes from the time it takes workers and firms to find good matches."},
{id:44,sourceGame:"nationalEngine",q:"Sectoral shifts usually increase which type of unemployment first?",options:["Frictional unemployment","Cyclical unemployment only","Measured inflation","Nominal GDP"],a:0,tag:"sectoral_shifts",type:"identification",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"sectoral_shift_matching",secondarySkills:[],repairSkill:"sectoral_shift_matching",commonError:"misses_sectoral_shift_job_search_link",feedback:"Sectoral shifts change demand across industries or regions, creating search and matching unemployment."},
{id:45,sourceGame:"nationalEngine",q:"Unemployment insurance can increase frictional unemployment because it does what?",options:["Lowers the cost of remaining unemployed while searching","Forces every firm to fire workers","Eliminates job search completely","Makes GDP impossible to calculate"],a:0,tag:"unemployment_insurance",type:"identification",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"ui_and_job_search_incentives",secondarySkills:[],repairSkill:"ui_and_job_search_incentives",commonError:"misses_ui_search_incentive",feedback:"Unemployment insurance can reduce the opportunity cost of continued job search."},
{id:46,sourceGame:"nationalEngine",q:"Structural unemployment is most directly tied to what?",options:["Real wage rigidity and job rationing","A fixed CPI basket","Current-year GDP prices","Temporary data collection error"],a:0,tag:"structural_unemployment",type:"definition",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"wage_rigidity_structural_unemployment",secondarySkills:[],repairSkill:"wage_rigidity_structural_unemployment",commonError:"confuses_structural_and_frictional_unemployment",feedback:"Structural unemployment results from real wage rigidity and job rationing."},
{id:47,sourceGame:"nationalEngine",q:"Wage rigidity means what?",options:["Wages fail to adjust to clear the labor market","Wages always fall instantly","Workers never respond to wages","Labor demand is always zero"],a:0,tag:"wage_rigidity",type:"definition",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"wage_rigidity_structural_unemployment",secondarySkills:[],repairSkill:"wage_rigidity_structural_unemployment",commonError:"misdefines_wage_rigidity",feedback:"Wage rigidity means wages do not adjust enough to bring labor supply and demand into balance."},
{id:48,sourceGame:"nationalEngine",q:"A binding minimum wage is most likely to create what?",options:["Structural unemployment among affected workers","A lower real wage for every worker","A smaller labor supply than labor demand","A higher GDP deflator by definition"],a:0,tag:"minimum_wage",type:"identification",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:[],repairSkill:"minimum_wage_structural_unemployment",commonError:"misses_minimum_wage_surplus_labor",feedback:"A binding minimum wage can hold wages above equilibrium and create structural unemployment among affected workers."},
{id:49,sourceGame:"nationalEngine",q:"Unions can create structural unemployment by doing what?",options:["Bargaining wages above equilibrium","Making workers search faster","Reducing the CPI basket","Changing nominal GDP into real GDP"],a:0,tag:"unions",type:"identification",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"union_wage_rigidity",secondarySkills:[],repairSkill:"union_wage_rigidity",commonError:"misses_union_wage_rigidity_channel",feedback:"Unions can bargain wages above equilibrium, which may create job rationing and structural unemployment."},
{id:50,sourceGame:"nationalEngine",q:"Efficiency wages are wages that firms pay above equilibrium mainly to do what?",options:["Increase productivity, effort, retention, or worker quality","Lower all prices in the CPI","Make unemployment impossible","Reduce GDP by excluding final goods"],a:0,tag:"efficiency_wages",type:"definition",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"efficiency_wage_theory",secondarySkills:[],repairSkill:"efficiency_wage_theory",commonError:"misdefines_efficiency_wages",feedback:"Efficiency wages are above-equilibrium wages paid to improve productivity, effort, retention, or worker quality."},
{id:51,sourceGame:"nationalEngine",q:"In efficiency wage theory, paying higher wages may reduce what?",options:["Worker turnover","The definition of GDP","The need for capital","The base year price level"],a:0,tag:"efficiency_wages",type:"identification",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"efficiency_wage_theory",secondarySkills:[],repairSkill:"efficiency_wage_theory",commonError:"misses_turnover_channel",feedback:"Higher wages can reduce turnover by giving workers more incentive to stay."},
{id:52,sourceGame:"nationalEngine",q:"A discouraged worker is someone who wants work but has done what?",options:["Stopped looking recently and is not counted as unemployed","Found a job and is counted as employed","Bought financial assets instead of goods","Moved from nominal GDP to real GDP"],a:0,tag:"discouraged_workers",type:"definition",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"labor_underutilization_classification",secondarySkills:[],repairSkill:"labor_underutilization_classification",commonError:"counts_discouraged_workers_as_u3_unemployed",feedback:"Discouraged workers want work but are not counted as unemployed if they have stopped actively searching."},
{id:53,sourceGame:"nationalEngine",q:"Marginally attached workers are best described as what?",options:["People outside the labor force who want work and have searched sometime recently but not in the last four weeks","People working two payroll jobs","People counted in investment spending","People who are paid their marginal product"],a:0,tag:"marginally_attached",type:"definition",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"labor_underutilization_classification",secondarySkills:[],repairSkill:"labor_underutilization_classification",commonError:"misclassifies_marginal_attachment",feedback:"Marginally attached workers want work and have searched in the past year, but not recently enough to count as unemployed."},
{id:54,sourceGame:"nationalEngine",q:"U-6 unemployment includes unemployed workers plus marginally attached workers and what else?",options:["People working part time for economic reasons","Only retired workers","Only full-time students","Only workers with two jobs"],a:0,tag:"labor_underutilization",type:"identification",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"labor_underutilization_classification",secondarySkills:[],repairSkill:"labor_underutilization_classification",commonError:"misses_part_time_for_economic_reasons",feedback:"U-6 includes unemployed workers, marginally attached workers, and people working part time for economic reasons."},
{id:55,sourceGame:"nationalEngine",q:"Why can long-term unemployment account for a large share of observed unemployment?",options:["Long spells last many weeks even if fewer people experience them","Long-term workers are never counted in labor statistics","Short unemployment spells are illegal","GDP excludes unemployed people"],a:0,tag:"unemployment_duration",type:"identification",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"unemployment_duration_calculation",secondarySkills:[],repairSkill:"unemployment_duration_calculation",commonError:"confuses_number_of_spells_with_total_weeks",feedback:"A small group with long spells can account for many total weeks of unemployment."},
{id:56,sourceGame:"nationalEngine",q:"Which statement best separates frictional from structural unemployment?",options:["Frictional comes from search time; structural comes from wage rigidity and job rationing","Frictional is always permanent; structural is always one week long","Frictional is caused only by inflation; structural is caused only by GDP","Frictional affects only capital owners; structural affects only exporters"],a:0,tag:"unemployment_types",type:"identification",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"frictional_vs_other_unemployment",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"frictional_vs_other_unemployment",commonError:"confuses_unemployment_types",feedback:"Frictional unemployment comes from search and matching; structural unemployment comes from wage rigidity and job rationing."},
{id:57,sourceGame:"nationalEngine",q:"Which policy is most directly aimed at reducing frictional unemployment?",options:["Improving job matching information","Raising wages above equilibrium","Counting used goods in GDP","Fixing the CPI basket forever"],a:0,tag:"frictional_unemployment",type:"identification",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"sectoral_shift_matching",secondarySkills:[],repairSkill:"sectoral_shift_matching",commonError:"chooses_structural_policy_for_frictional_problem",feedback:"Better job matching information can reduce frictional unemployment by shortening search time."},
{id:58,sourceGame:"nationalEngine",q:"Which policy is most directly connected to structural unemployment?",options:["A binding minimum wage","A better job-search website","A change in the base year for real GDP","A new CPI basket survey"],a:0,tag:"structural_unemployment",type:"identification",objective:"LO7.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:[],repairSkill:"minimum_wage_structural_unemployment",commonError:"chooses_frictional_policy_for_structural_problem",feedback:"A binding minimum wage can create structural unemployment by keeping wages above equilibrium."},
{id:59,sourceGame:"nationalEngine",q:"If workers are paid their marginal product, which theory is being applied?",options:["Neoclassical theory of distribution","CPI substitution theory","Steady-state unemployment theory","GDP deflator theory"],a:0,tag:"income_distribution",type:"identification",objective:"LO3.3",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"factor_income_distribution",secondarySkills:[],repairSkill:"factor_income_distribution",commonError:"confuses_distribution_with_measurement",feedback:"The neoclassical theory of distribution says factors are paid according to their marginal products."},
{id:60,sourceGame:"nationalEngine",q:"Which answer best identifies the main role of the loanable funds market in Chapter 3?",options:["It links saving and investment through the real interest rate","It measures the CPI basket","It counts discouraged workers","It determines only nominal GDP"],a:0,tag:"loanable_funds",type:"identification",objective:"LO3.5",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"saving_investment_equilibrium",secondarySkills:[],repairSkill:"saving_investment_equilibrium",commonError:"misses_loanable_funds_equilibrium_role",feedback:"The loanable funds market links saving and investment through the real interest rate."},
{id:61,sourceGame:"nationalEngine",q:"If C = 100, I = 50, G = 40, and NX = -10, what is GDP?",options:["180","200","160","220"],a:0,tag:"gdp_components",type:"calculation",objective:"LO2.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"gdp_expenditure_calculation",secondarySkills:[],repairSkill:"gdp_expenditure_calculation",commonError:"forgets_negative_net_exports",feedback:"GDP = C + I + G + NX = 100 + 50 + 40 - 10 = 180."},
{id:62,sourceGame:"nationalEngine",q:"If GDP is 500, C is 300, I is 100, and G is 80, what is NX?",options:["20","80","120","-20"],a:0,tag:"gdp_components",type:"calculation",objective:"LO2.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"gdp_expenditure_calculation",secondarySkills:[],repairSkill:"gdp_expenditure_calculation",commonError:"does_not_solve_for_net_exports",feedback:"NX = GDP - C - I - G = 500 - 300 - 100 - 80 = 20."},
{id:63,sourceGame:"nationalEngine",q:"If nominal GDP is 1200 and real GDP is 1000, what is the GDP deflator?",options:["120","100","83.3","200"],a:0,tag:"gdp_deflator",type:"calculation",objective:"LO2.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"gdp_deflator_inflation",secondarySkills:[],repairSkill:"gdp_deflator_inflation",commonError:"reverses_nominal_and_real_gdp",feedback:"GDP deflator = 100 × nominal GDP / real GDP = 100 × 1200 / 1000 = 120."},
{id:64,sourceGame:"nationalEngine",q:"If the labor force is 200 and 10 people are unemployed, what is the unemployment rate?",options:["5%","10%","20%","2%"],a:0,tag:"unemployment_rate",type:"calculation",objective:"LO2.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"labor_force_statistics_calculation",secondarySkills:[],repairSkill:"labor_force_statistics_calculation",commonError:"uses_population_instead_of_labor_force",feedback:"Unemployment rate = unemployed / labor force × 100 = 10 / 200 × 100 = 5%."},
{id:65,sourceGame:"nationalEngine",q:"In the basic production model, holding capital and labor fixed causes output to be what?",options:["Fixed by the production function","Determined only by inflation","Equal to the CPI basket","Set only by unemployment insurance"],a:0,tag:"production",type:"identification",objective:"LO3.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"production_function_output",secondarySkills:[],repairSkill:"production_function_output",commonError:"misses_fixed_inputs_fixed_output",feedback:"If capital, labor, and technology are fixed, output is fixed by the production function."},
{id:66,sourceGame:"nationalEngine",q:"Which change would most directly increase output in the production function?",options:["Better technology","A higher CPI basket cost","A lower job finding rate","A larger trade deficit by itself"],a:0,tag:"production_function",type:"identification",objective:"LO3.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"production_function_output",secondarySkills:[],repairSkill:"production_function_output",commonError:"confuses_output_determinants_with_indicators",feedback:"Better technology raises the amount of output produced from given capital and labor."},
{id:67,sourceGame:"nationalEngine",q:"If doubling capital and labor more than doubles output, the production function shows what?",options:["Increasing returns to scale","Constant returns to scale","Decreasing returns to scale","No returns to scale"],a:0,tag:"returns_to_scale",type:"definition",objective:"LO3.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"returns_to_scale_classification",secondarySkills:[],repairSkill:"returns_to_scale_classification",commonError:"confuses_increasing_and_constant_returns",feedback:"Increasing returns to scale means doubling inputs more than doubles output."},
{id:68,sourceGame:"nationalEngine",q:"If doubling capital and labor less than doubles output, the production function shows what?",options:["Decreasing returns to scale","Increasing returns to scale","Constant returns to scale","No production relationship"],a:0,tag:"returns_to_scale",type:"definition",objective:"LO3.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"returns_to_scale_classification",secondarySkills:[],repairSkill:"returns_to_scale_classification",commonError:"confuses_decreasing_and_constant_returns",feedback:"Decreasing returns to scale means doubling inputs less than doubles output."},
{id:69,sourceGame:"nationalEngine",q:"If the nominal wage is $20 and the price of output is $5, what is the real wage?",options:["4 units of output","25 units of output","15 units of output","100 units of output"],a:0,tag:"factor_prices",type:"calculation",objective:"LO3.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"multiplies_wage_by_price",feedback:"The real wage is W/P = 20/5 = 4 units of output."},
{id:70,sourceGame:"nationalEngine",q:"A firm should keep hiring workers while MPL is what relative to the real wage?",options:["Greater than the real wage","Less than the real wage","Equal to zero","Unrelated to the real wage"],a:0,tag:"labor_demand",type:"identification",objective:"LO3.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"gets_hiring_condition_backward",feedback:"A firm keeps hiring while MPL exceeds the real wage, then stops around MPL = W/P."},
{id:71,sourceGame:"nationalEngine",q:"What happens to MPL as more labor is added while other inputs are fixed?",options:["It eventually falls","It must always rise","It becomes the CPI","It becomes public saving"],a:0,tag:"marginal_product",type:"identification",objective:"LO3.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"diminishing_marginal_product",secondarySkills:[],repairSkill:"diminishing_marginal_product",commonError:"misses_diminishing_marginal_product",feedback:"With other inputs fixed, adding more labor eventually causes MPL to fall."},
{id:72,sourceGame:"nationalEngine",q:"On a total product curve, the marginal product is represented by what?",options:["The slope of the total product curve","The height of the CPI basket","The unemployment rate","The amount of public saving"],a:0,tag:"marginal_product",type:"identification",objective:"LO3.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"total_product_to_marginal_product",secondarySkills:[],repairSkill:"total_product_to_marginal_product",commonError:"confuses_total_product_level_with_marginal_product",feedback:"Marginal product is the change in output from one more input, so it is tied to the slope of the total product curve."},
{id:73,sourceGame:"nationalEngine",q:"If disposable income rises and the MPC is positive, what happens to consumption?",options:["It rises","It falls to zero","It becomes equal to public saving","It becomes unrelated to income"],a:0,tag:"consumption",type:"identification",objective:"LO3.4",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"mpc_disposable_income",secondarySkills:[],repairSkill:"mpc_disposable_income",commonError:"misses_consumption_disposable_income_link",feedback:"When disposable income rises, consumption rises by the MPC times the change in disposable income."},
{id:74,sourceGame:"nationalEngine",q:"If the real interest rate rises, what usually happens to investment demand?",options:["It falls","It rises","It becomes public saving","It becomes the labor force"],a:0,tag:"investment",type:"identification",objective:"LO3.4",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"investment_interest_rate_relationship",secondarySkills:[],repairSkill:"investment_interest_rate_relationship",commonError:"gets_interest_rate_investment_relationship_backward",feedback:"Investment demand is inversely related to the real interest rate, so higher real interest rates reduce investment."},
{id:75,sourceGame:"nationalEngine",q:"If actual unemployment is above the natural rate, the extra unemployment is best described as what?",options:["Cyclical unemployment","Frictional unemployment only","Structural unemployment only","Labor force participation"],a:0,tag:"natural_rate",type:"identification",objective:"LO7.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"confuses_cyclical_and_natural_unemployment",feedback:"When actual unemployment is above the natural rate, the difference is cyclical unemployment."},
{id:76,sourceGame:"nationalEngine",q:"The natural rate of unemployment is a long-run concept because workers are constantly doing what?",options:["Moving into and out of jobs","Buying only final goods","Changing base-year prices","Counting imports as exports"],a:0,tag:"natural_rate",type:"identification",objective:"LO7.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"misses_labor_market_flow_logic",feedback:"The natural rate reflects normal labor-market flows as workers separate from and find jobs."},
{id:77,sourceGame:"nationalEngine",q:"If the economy has no cyclical unemployment, actual unemployment is closest to what?",options:["The natural rate","Zero unemployment","The CPI rate","The investment rate"],a:0,tag:"natural_rate",type:"definition",objective:"LO7.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"thinks_natural_rate_means_zero_unemployment",feedback:"When cyclical unemployment is absent, actual unemployment is near the natural rate, not zero."},
{id:78,sourceGame:"nationalEngine",q:"Which unemployment type is part of the natural rate rather than a temporary recession effect?",options:["Frictional unemployment","Cyclical unemployment","Unexpected GDP inflation","Nominal price indexing"],a:0,tag:"natural_rate",type:"identification",objective:"LO7.1",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"natural_rate_definition",secondarySkills:["frictional_vs_other_unemployment"],repairSkill:"natural_rate_definition",commonError:"confuses_natural_components_with_cyclical_unemployment",feedback:"Frictional unemployment is part of the natural rate because job search exists even in normal times."},
{id:79,sourceGame:"nationalEngine",q:"If s is the job separation rate and f is the job finding rate, which change lowers steady-state unemployment?",options:["A higher f","A higher s","A lower f","A higher s and lower f"],a:0,tag:"steady_state_unemployment",type:"identification",objective:"LO7.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"gets_finding_rate_effect_backward",feedback:"A higher job finding rate lowers steady-state unemployment because unemployed workers leave unemployment faster."},
{id:80,sourceGame:"nationalEngine",q:"If s is the job separation rate and f is the job finding rate, which change raises steady-state unemployment?",options:["A higher s","A higher f","A lower s","A higher f and lower s"],a:0,tag:"steady_state_unemployment",type:"identification",objective:"LO7.2",difficulty:"easy",conceptCluster:"national_engine_easy",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"gets_separation_rate_effect_backward",feedback:"A higher separation rate raises steady-state unemployment because more employed workers enter unemployment."}	
],
medium:[
{id:100,sourceGame:"nationalEngine",q:"A family buys a newly built house. In GDP accounting, this purchase is classified as what?",options:["Investment","Consumption","Government purchases","Net exports"],a:0,tag:"gdp_components",type:"identification",objective:"LO2.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"gdp_components_identity",secondarySkills:["gdp_inclusion_exclusion"],repairSkill:"gdp_components_identity",commonError:"counts_new_housing_as_consumption",feedback:"New residential construction is counted as investment in GDP, even when households buy the house."},
{id:101,sourceGame:"nationalEngine",q:"A person buys a used car from a neighbor. How does that affect current GDP?",options:["Only the value of any current resale service is counted","The full used-car price is counted as consumption","The full used-car price is counted as investment","The purchase is counted as government spending"],a:0,tag:"gdp",type:"identification",objective:"LO2.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"gdp_inclusion_exclusion",secondarySkills:[],repairSkill:"gdp_inclusion_exclusion",commonError:"counts_used_goods_as_current_production",feedback:"Used goods were produced in the past, so only current services tied to the resale would count in GDP."},
{id:102,sourceGame:"nationalEngine",q:"A U.S. firm produces cars this year but does not sell all of them. How are the unsold cars treated in GDP?",options:["They are counted as inventory investment","They are excluded until sold to households","They are counted as imports","They are subtracted from government purchases"],a:0,tag:"gdp_components",type:"identification",objective:"LO2.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"gdp_inclusion_exclusion",secondarySkills:[],repairSkill:"gdp_inclusion_exclusion",commonError:"excludes_unsold_current_output",feedback:"Unsold current production is counted as inventory investment, so it is included in GDP."},
{id:103,sourceGame:"nationalEngine",q:"Which item is excluded from GDP because it is a transfer rather than a purchase of a final good or service?",options:["Social Security payment","Public school teacher salary","New highway construction","Police department equipment purchase"],a:0,tag:"gdp",type:"identification",objective:"LO2.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"gdp_inclusion_exclusion",secondarySkills:[],repairSkill:"gdp_inclusion_exclusion",commonError:"counts_transfer_payments_as_government_purchases",feedback:"Transfer payments shift income but are not government purchases of currently produced goods or services."},
{id:104,sourceGame:"nationalEngine",q:"Which statement correctly compares the CPI and the GDP deflator?",options:["The CPI uses a fixed consumer basket, while the GDP deflator uses currently produced goods and services","The CPI excludes imports, while the GDP deflator includes all imported consumer goods","The CPI measures only investment goods, while the GDP deflator measures only food prices","The CPI and GDP deflator always move by the exact same amount"],a:0,tag:"gdp_deflator_vs_cpi",type:"comparison",objective:"LO2.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"price_index_comparison",secondarySkills:[],repairSkill:"price_index_comparison",commonError:"confuses_cpi_and_gdp_deflator_baskets",feedback:"The CPI uses a fixed consumer basket; the GDP deflator reflects prices of currently produced GDP goods and services."},
{id:105,sourceGame:"nationalEngine",q:"A discouraged worker stops searching for work. What happens to the official unemployment rate, all else equal?",options:["It can fall because the person leaves the labor force","It must rise because the person is still jobless","It cannot change because discouraged workers are employed","It becomes equal to the labor force participation rate"],a:0,tag:"labor_force",type:"interpretation",objective:"LO2.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"employment_status_classification",secondarySkills:["labor_underutilization_classification"],repairSkill:"employment_status_classification",commonError:"counts_discouraged_workers_as_u3_unemployed",feedback:"A discouraged worker who stops searching is no longer counted in the labor force, so official unemployment can fall."},
{id:106,sourceGame:"nationalEngine",q:"Tacoland has C = 400, I = 120, G = 90, exports = 70, and imports = 50. What is GDP?",options:["630","680","610","730"],a:0,tag:"gdp_components",type:"calculation",objective:"LO2.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"gdp_expenditure_calculation",secondarySkills:[],repairSkill:"gdp_expenditure_calculation",commonError:"adds_imports_instead_of_subtracting_imports",feedback:"GDP = C + I + G + X - M = 400 + 120 + 90 + 70 - 50 = 630."},
{id:107,sourceGame:"nationalEngine",q:"GDP is 900, C is 500, I is 180, G is 160, and exports are 100. What are imports?",options:["40","60","80","140"],a:0,tag:"gdp_components",type:"calculation",objective:"LO2.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"gdp_expenditure_calculation",secondarySkills:[],repairSkill:"gdp_expenditure_calculation",commonError:"does_not_solve_for_imports",feedback:"900 = 500 + 180 + 160 + (100 - M), so 900 = 940 - M and imports equal 40."},
{id:108,sourceGame:"nationalEngine",q:"In 2024, nominal GDP is 1500 and real GDP is 1250. What is the GDP deflator?",options:["120","83.3","125","150"],a:0,tag:"gdp_deflator",type:"calculation",objective:"LO2.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"gdp_deflator_inflation",secondarySkills:[],repairSkill:"gdp_deflator_inflation",commonError:"reverses_real_and_nominal_gdp",feedback:"GDP deflator = 100 × nominal GDP / real GDP = 100 × 1500 / 1250 = 120."},
{id:109,sourceGame:"nationalEngine",q:"If the CPI rises from 125 to 135, what is the inflation rate?",options:["8%","10%","7.4%","13.5%"],a:0,tag:"cpi",type:"calculation",objective:"LO2.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"cpi_inflation_calculation",secondarySkills:[],repairSkill:"cpi_inflation_calculation",commonError:"divides_by_new_cpi_instead_of_old_cpi",feedback:"Inflation = (135 - 125) / 125 × 100 = 8%."},
{id:110,sourceGame:"nationalEngine",q:"A basket costs $80 in the base year and $100 this year. What is this year’s CPI?",options:["125","80","100","25"],a:0,tag:"cpi",type:"calculation",objective:"LO2.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"cpi_inflation_calculation",secondarySkills:[],repairSkill:"cpi_inflation_calculation",commonError:"subtracts_instead_of_dividing_by_base_year_cost",feedback:"CPI = 100 × current basket cost / base-year basket cost = 100 × 100 / 80 = 125."},
{id:111,sourceGame:"nationalEngine",q:"An economy has 160 employed workers, 16 unemployed workers, and 24 adults not in the labor force. What is the unemployment rate?",options:["9.1%","8%","10%","16%"],a:0,tag:"unemployment_rate",type:"calculation",objective:"LO2.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"labor_force_statistics_calculation",secondarySkills:[],repairSkill:"labor_force_statistics_calculation",commonError:"uses_adult_population_instead_of_labor_force",feedback:"Labor force = 160 + 16 = 176. Unemployment rate = 16 / 176 × 100 = 9.1%."},
{id:112,sourceGame:"nationalEngine",q:"In the Chapter 3 model, why is output fixed in the short-run setup?",options:["Capital, labor, and technology are assumed fixed","Consumption must always equal zero","The CPI fixes the amount of production","The unemployment rate determines output alone"],a:0,tag:"production",type:"interpretation",objective:"LO3.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"production_function_output",secondarySkills:[],repairSkill:"production_function_output",commonError:"misses_fixed_input_assumption",feedback:"With capital, labor, and technology fixed, the production function pins down output."},
{id:113,sourceGame:"nationalEngine",q:"Which change shifts the production function upward rather than moving along it?",options:["An improvement in technology","Adding one worker with technology unchanged","Moving from one labor quantity to another","Changing consumption with output fixed"],a:0,tag:"production_function",type:"interpretation",objective:"LO3.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"production_function_output",secondarySkills:[],repairSkill:"production_function_output",commonError:"confuses_movement_along_function_with_technology_shift",feedback:"Better technology lets the same inputs produce more output, shifting the production function upward."},
{id:114,sourceGame:"nationalEngine",q:"A production function has constant returns to scale. If capital and labor both rise by 10%, output should do what?",options:["Rise by 10%","Rise by more than 10%","Rise by less than 10%","Fall by 10%"],a:0,tag:"returns_to_scale",type:"application",objective:"LO3.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"returns_to_scale_classification",secondarySkills:[],repairSkill:"returns_to_scale_classification",commonError:"confuses_constant_with_increasing_returns",feedback:"With constant returns to scale, proportional increases in all inputs create the same proportional increase in output."},
{id:115,sourceGame:"nationalEngine",q:"Suppose output rises from 100 to 230 when both capital and labor double. What kind of returns to scale does this show?",options:["Increasing returns to scale","Constant returns to scale","Decreasing returns to scale","No production function"],a:0,tag:"returns_to_scale",type:"application",objective:"LO3.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"returns_to_scale_classification",secondarySkills:[],repairSkill:"returns_to_scale_classification",commonError:"misses_more_than_double_output",feedback:"Doubling inputs would double output to 200 under constant returns, but output rises to 230, so returns are increasing."},
{id:116,sourceGame:"nationalEngine",q:"Suppose output rises from 100 to 175 when both capital and labor double. What kind of returns to scale does this show?",options:["Decreasing returns to scale","Constant returns to scale","Increasing returns to scale","Perfect factor shares"],a:0,tag:"returns_to_scale",type:"application",objective:"LO3.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"returns_to_scale_classification",secondarySkills:[],repairSkill:"returns_to_scale_classification",commonError:"misses_less_than_double_output",feedback:"Doubling inputs would double output to 200 under constant returns, but output rises only to 175, so returns are decreasing."},
{id:117,sourceGame:"nationalEngine",q:"Which statement best explains why total income equals total expenditure in the circular flow?",options:["One person’s spending becomes another person’s income","Government forces all income to become taxes","Imports are always equal to exports","The CPI turns spending into employment"],a:0,tag:"income_expenditure",type:"interpretation",objective:"LO3.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"production_function_output",secondarySkills:["gdp_components_identity"],repairSkill:"production_function_output",commonError:"misses_circular_flow_identity",feedback:"For the economy as a whole, spending by buyers becomes income for sellers."},
{id:118,sourceGame:"nationalEngine",q:"If the nominal wage is $24 and the output price is $6, what is the real wage?",options:["4 units of output","6 units of output","18 units of output","144 units of output"],a:0,tag:"factor_prices",type:"calculation",objective:"LO3.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"multiplies_nominal_wage_by_price",feedback:"The real wage is W/P = 24/6 = 4 units of output."},
{id:119,sourceGame:"nationalEngine",q:"A firm faces a real wage of 5. It should hire the next worker if that worker’s MPL is what?",options:["Greater than 5","Less than 5","Exactly 0","Equal to the CPI"],a:0,tag:"labor_demand",type:"application",objective:"LO3.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"gets_mpl_hiring_rule_backward",feedback:"The firm hires another worker when the worker’s marginal product exceeds the real wage."},
{id:120,sourceGame:"nationalEngine",q:"Refer to the marginal product graph. As labor rises, the MPL curve generally slopes downward because of what?",options:["Diminishing marginal product","A fixed CPI basket","Higher public saving","Rising net exports"],a:0,tag:"marginal_product",type:"graph_identification",objective:"LO3.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"diminishing_marginal_product",secondarySkills:[],repairSkill:"diminishing_marginal_product",commonError:"misses_diminishing_returns_on_graph",feedback:"The downward MPL pattern reflects diminishing marginal product as more labor is added while other inputs are fixed.",image:"marginalproduct.webp"},
{id:121,sourceGame:"nationalEngine",q:"Refer to the total product graph. What does a flatter section of the total product curve imply?",options:["Marginal product is falling","Total output is negative","The real wage is rising by definition","CPI inflation is falling"],a:0,tag:"marginal_product",type:"graph_interpretation",objective:"LO3.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"total_product_to_marginal_product",secondarySkills:[],repairSkill:"total_product_to_marginal_product",commonError:"confuses_total_product_level_with_marginal_product",feedback:"A flatter total product curve means each added worker contributes less extra output, so marginal product is falling.",image:"totalproduct.webp"},
{id:122,sourceGame:"nationalEngine",q:"If the supply of labor increases in the factor market model, what happens to the real wage, all else equal?",options:["It falls","It rises","It becomes the CPI","It equals national saving"],a:0,tag:"factor_markets",type:"application",objective:"LO3.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"gets_labor_supply_effect_backward",feedback:"An increase in labor supply puts downward pressure on the real wage."},
{id:123,sourceGame:"nationalEngine",q:"If capital becomes scarcer, what should happen to the marginal product of capital?",options:["It rises","It falls","It becomes zero by definition","It becomes the unemployment rate"],a:0,tag:"factor_prices",type:"application",objective:"LO3.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"diminishing_marginal_product",secondarySkills:["factor_income_distribution"],repairSkill:"diminishing_marginal_product",commonError:"gets_scarcity_and_marginal_product_backward",feedback:"When capital is scarcer, each unit of capital tends to be more productive at the margin, raising MPK."},
{id:124,sourceGame:"nationalEngine",q:"In a Cobb-Douglas model with alpha = 0.35, what is labor’s share of income?",options:["65%","35%","135%","3.5%"],a:0,tag:"factor_shares",type:"calculation",objective:"LO3.3",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:[],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"uses_alpha_for_labor_share",feedback:"If alpha is capital’s share, labor’s share is 1 - alpha = 0.65, or 65%."},
{id:125,sourceGame:"nationalEngine",q:"In a Cobb-Douglas model with alpha = 0.4, what is capital’s share of income?",options:["40%","60%","140%","4%"],a:0,tag:"factor_shares",type:"calculation",objective:"LO3.3",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:[],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"uses_one_minus_alpha_for_capital_share",feedback:"Alpha represents capital’s share, so capital receives 40% of income."},
{id:126,sourceGame:"nationalEngine",q:"If alpha = 0.3 and the labor force rises by 10%, approximately how much does output rise in a simple Cobb-Douglas setup?",options:["7%","3%","10%","13%"],a:0,tag:"cobb_douglas",type:"calculation",objective:"LO3.3",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:[],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"uses_alpha_instead_of_labor_share",feedback:"Labor’s exponent is 1 - alpha = 0.7, so a 10% labor increase raises output by about 7%."},
{id:127,sourceGame:"nationalEngine",q:"Which statement best matches the neoclassical theory of distribution?",options:["Labor and capital are paid according to marginal productivity","Labor is paid according to CPI inflation only","Capital receives income only when unemployment is zero","Income shares are determined only by government purchases"],a:0,tag:"income_distribution",type:"interpretation",objective:"LO3.3",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"factor_income_distribution",secondarySkills:[],repairSkill:"factor_income_distribution",commonError:"misses_marginal_product_distribution_logic",feedback:"The neoclassical theory says competitive firms pay factors according to their marginal products."},
{id:128,sourceGame:"nationalEngine",q:"If technology favors automation, which factor share might rise in the real world even if basic Cobb-Douglas assumes stable shares?",options:["Capital’s share","Labor force participation","CPI basket share","Import share only"],a:0,tag:"income_distribution",type:"application",objective:"LO3.3",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"factor_income_distribution",secondarySkills:["cobb_douglas_factor_share_calculation"],repairSkill:"factor_income_distribution",commonError:"misses_capital_biased_technology_channel",feedback:"Automation can raise capital’s share by increasing the returns to machines, software, and other capital."},
{id:129,sourceGame:"nationalEngine",q:"Which statement best separates economic profit from accounting profit in the Chapter 3 discussion?",options:["Accounting profit includes the return to owner-supplied capital","Economic profit ignores all factor payments","Accounting profit excludes all capital income","Economic profit is the same as CPI inflation"],a:0,tag:"income_distribution",type:"interpretation",objective:"LO3.3",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"factor_income_distribution",secondarySkills:[],repairSkill:"factor_income_distribution",commonError:"confuses_accounting_and_economic_profit",feedback:"When firms own capital, accounting profit includes both economic profit and the return to that capital."},
{id:130,sourceGame:"nationalEngine",q:"If C = 100 + 0.8(Y - T), Y = 1000, and T = 200, what is consumption?",options:["740","800","900","640"],a:0,tag:"consumption_function",type:"calculation",objective:"LO3.4",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"consumption_function_calculation",secondarySkills:[],repairSkill:"consumption_function_calculation",commonError:"forgets_subtracting_taxes_from_income",feedback:"Disposable income is 1000 - 200 = 800. Consumption = 100 + 0.8(800) = 740."},
{id:131,sourceGame:"nationalEngine",q:"If disposable income rises by 100 and MPC = 0.75, how much does consumption rise?",options:["75","25","100","175"],a:0,tag:"mpc",type:"calculation",objective:"LO3.4",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"mpc_disposable_income",secondarySkills:["consumption_function_calculation"],repairSkill:"mpc_disposable_income",commonError:"uses_mps_instead_of_mpc",feedback:"Consumption rises by MPC × change in disposable income = 0.75 × 100 = 75."},
{id:132,sourceGame:"nationalEngine",q:"Refer to the consumption function graph. A rise in disposable income with the same consumption function causes what?",options:["A movement along the consumption function","An upward shift of the consumption function","A leftward shift of the investment function","A fall in labor force participation"],a:0,tag:"consumption_function",type:"graph_identification",objective:"LO3.4",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"consumption_movement_vs_shift",secondarySkills:[],repairSkill:"consumption_movement_vs_shift",commonError:"confuses_movement_with_shift",feedback:"Higher disposable income moves the economy along the existing consumption function.",image:"consumptionfunction.webp"},
{id:133,sourceGame:"nationalEngine",q:"Refer to the consumption function graph. A stock-market boom that increases household wealth would most likely do what?",options:["Shift the consumption function upward","Move downward along the same consumption function","Shift the labor supply curve left","Reduce nominal GDP by definition"],a:0,tag:"consumption_function",type:"graph_interpretation",objective:"LO3.4",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"consumption_movement_vs_shift",secondarySkills:[],repairSkill:"consumption_movement_vs_shift",commonError:"confuses_wealth_shift_with_income_movement",feedback:"Higher wealth increases consumption at a given disposable income, shifting the consumption function upward.",image:"consumptionfunction.webp"},
{id:134,sourceGame:"nationalEngine",q:"Refer to the investment function graph. Moving down along the same investment curve is caused by what?",options:["A lower real interest rate","A lower expected profit at every interest rate","A decrease in technology","A fall in national saving"],a:0,tag:"investment_function",type:"graph_identification",objective:"LO3.4",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"investment_function_movement_vs_shift",secondarySkills:[],repairSkill:"investment_function_movement_vs_shift",commonError:"confuses_interest_rate_movement_with_demand_shift",feedback:"A lower real interest rate causes a movement down along the investment function toward more investment.",image:"investmentfunction.webp"},
{id:135,sourceGame:"nationalEngine",q:"Refer to the investment function graph. Better expected profits would most likely cause what?",options:["A rightward shift of investment demand","A movement up along the same investment curve","A lower labor force participation rate","A smaller CPI basket by definition"],a:0,tag:"investment_function",type:"graph_interpretation",objective:"LO3.4",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"investment_function_movement_vs_shift",secondarySkills:[],repairSkill:"investment_function_movement_vs_shift",commonError:"treats_expected_profit_change_as_movement_along_curve",feedback:"Better expected profits increase investment demand at each interest rate, shifting the investment function right.",image:"investmentfunction.webp"},
{id:136,sourceGame:"nationalEngine",q:"If Y = 1000, T = 200, and C = 650, what is private saving?",options:["150","350","200","800"],a:0,tag:"private_saving",type:"calculation",objective:"LO3.5",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"saving_identity_calculation",secondarySkills:[],repairSkill:"saving_identity_calculation",commonError:"uses_total_income_instead_of_disposable_income",feedback:"Private saving = Y - T - C = 1000 - 200 - 650 = 150."},
{id:137,sourceGame:"nationalEngine",q:"If T = 300 and G = 420, what is public saving?",options:["-120","120","720","300"],a:0,tag:"public_saving",type:"calculation",objective:"LO3.5",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"saving_identity_calculation",secondarySkills:[],repairSkill:"saving_identity_calculation",commonError:"reverses_t_minus_g",feedback:"Public saving = T - G = 300 - 420 = -120, a budget deficit."},
{id:138,sourceGame:"nationalEngine",q:"If private saving is 200 and public saving is -50, what is national saving?",options:["150","250","-250","50"],a:0,tag:"national_saving",type:"calculation",objective:"LO3.5",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"saving_identity_calculation",secondarySkills:[],repairSkill:"saving_identity_calculation",commonError:"ignores_negative_public_saving",feedback:"National saving equals private saving plus public saving: 200 + (-50) = 150."},
{id:139,sourceGame:"nationalEngine",q:"Refer to the loanable funds graph. A decrease in national saving is shown as what kind of shift?",options:["A leftward shift of the saving curve","A rightward shift of the saving curve","A downward movement along investment demand","A rightward shift of the CPI basket"],a:0,tag:"loanable_funds",type:"graph_identification",objective:"LO3.5",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"loanable_funds_graph_shifts",secondarySkills:[],repairSkill:"loanable_funds_graph_shifts",commonError:"confuses_saving_shift_with_movement_along_investment",feedback:"A decrease in national saving shifts the saving curve left in the loanable funds market.",image:"loanablefunds.webp"},
{id:140,sourceGame:"nationalEngine",q:"Refer to the loanable funds graph. If government spending rises while taxes and output are fixed, what should happen?",options:["Saving shifts left, the real interest rate rises, and investment falls","Saving shifts right, the real interest rate falls, and investment rises","Investment demand shifts left, and saving stays fixed","The CPI basket shifts right"],a:0,tag:"crowding_out",type:"graph_interpretation",objective:"LO3.5",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"fiscal_policy_crowding_out",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"fiscal_policy_crowding_out",commonError:"gets_crowding_out_chain_backward",feedback:"Higher government spending lowers public saving, shifts national saving left, raises the real interest rate, and crowds out investment.",image:"loanablefunds.webp"},
{id:141,sourceGame:"nationalEngine",q:"Refer to the loanable funds graph. A rise in investment demand with fixed saving mainly causes what?",options:["A higher real interest rate with little change in investment","A lower real interest rate and lower investment","A leftward shift of national saving","A lower unemployment rate by definition"],a:0,tag:"loanable_funds",type:"graph_interpretation",objective:"LO3.5",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"investment_demand_vs_saving_shift",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"investment_demand_vs_saving_shift",commonError:"assumes_fixed_saving_allows_large_investment_increase",feedback:"With vertical fixed saving, higher investment demand mainly raises the real interest rate rather than increasing investment much.",image:"loanablefunds.webp"},
{id:142,sourceGame:"nationalEngine",q:"Which statement best describes the natural rate of unemployment?",options:["It includes normal frictional and structural unemployment","It is always zero in the long run","It equals only recession unemployment","It counts only discouraged workers"],a:0,tag:"natural_rate",type:"interpretation",objective:"LO7.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"natural_rate_definition",secondarySkills:["frictional_vs_other_unemployment"],repairSkill:"natural_rate_definition",commonError:"thinks_natural_rate_means_zero_unemployment",feedback:"The natural rate includes normal frictional and structural unemployment that exists even outside recessions."},
{id:143,sourceGame:"nationalEngine",q:"If actual unemployment is 8% and the natural rate is 5%, which part is cyclical unemployment?",options:["3 percentage points","5 percentage points","8 percentage points","13 percentage points"],a:0,tag:"natural_rate",type:"calculation",objective:"LO7.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"uses_actual_unemployment_as_cyclical_unemployment",feedback:"Cyclical unemployment is actual unemployment minus the natural rate: 8% - 5% = 3 percentage points."},
{id:144,sourceGame:"nationalEngine",q:"If actual unemployment is below the natural rate, what does that usually suggest?",options:["The economy is operating unusually hot relative to normal labor-market flows","There is no frictional unemployment","Structural unemployment has disappeared forever","The CPI must be falling"],a:0,tag:"natural_rate",type:"interpretation",objective:"LO7.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"thinks_below_natural_means_no_unemployment_problem",feedback:"Unemployment below the natural rate can occur temporarily when the economy is running unusually hot."},
{id:145,sourceGame:"nationalEngine",q:"Which change would most likely reduce the natural rate of unemployment?",options:["A faster job matching system that raises the job finding rate","A higher job separation rate with no change in finding","A fixed CPI basket","A larger GDP deflator"],a:0,tag:"natural_rate",type:"application",objective:"LO7.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"natural_rate_definition",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"natural_rate_definition",commonError:"misses_policy_link_to_natural_rate",feedback:"Raising the job finding rate reduces steady-state unemployment and can lower the natural rate."},
{id:146,sourceGame:"nationalEngine",q:"Why can the natural rate change over time?",options:["Labor-market institutions and job-flow rates can change","GDP is always counted with current prices","The CPI must always overstate inflation by the same amount","Imports are always larger than exports"],a:0,tag:"natural_rate",type:"interpretation",objective:"LO7.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"natural_rate_definition",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"natural_rate_definition",commonError:"treats_natural_rate_as_permanently_fixed",feedback:"The natural rate can change when labor-market institutions, job separation, or job finding conditions change."},
{id:147,sourceGame:"nationalEngine",q:"Which unemployment component is most clearly outside the natural rate?",options:["Cyclical unemployment","Frictional unemployment","Structural unemployment","Search unemployment"],a:0,tag:"natural_rate",type:"identification",objective:"LO7.1",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"includes_cyclical_unemployment_in_natural_rate",feedback:"Cyclical unemployment is the temporary business-cycle movement around the natural rate, not part of the natural rate itself."},
{id:148,sourceGame:"nationalEngine",q:"If s = 0.02 and f = 0.18, what is the steady-state unemployment rate using s/(s+f)?",options:["10%","2%","18%","20%"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"steady_state_unemployment_calculation",secondarySkills:[],repairSkill:"steady_state_unemployment_calculation",commonError:"divides_s_by_f_only",feedback:"Steady-state unemployment = s/(s+f) = 0.02/(0.02+0.18) = 0.10, or 10%."},
{id:149,sourceGame:"nationalEngine",q:"If s = 0.04 and f = 0.36, what is the steady-state unemployment rate?",options:["10%","4%","36%","40%"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"steady_state_unemployment_calculation",secondarySkills:[],repairSkill:"steady_state_unemployment_calculation",commonError:"uses_f_as_unemployment_rate",feedback:"Steady-state unemployment = 0.04/(0.04+0.36) = 0.04/0.40 = 10%."},
{id:150,sourceGame:"nationalEngine",q:"If f rises while s is unchanged, what happens in the steady-state unemployment model?",options:["The unemployment rate falls because workers leave unemployment faster","The unemployment rate rises because more workers lose jobs","The unemployment rate cannot change","The labor force disappears from the model"],a:0,tag:"steady_state_unemployment",type:"interpretation",objective:"LO7.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"gets_finding_rate_effect_backward",feedback:"A higher job finding rate lowers unemployment because unemployed workers find jobs more quickly."},
{id:151,sourceGame:"nationalEngine",q:"If s rises while f is unchanged, what happens in the steady-state unemployment model?",options:["The unemployment rate rises because more employed workers enter unemployment","The unemployment rate falls because more workers find jobs","The unemployment rate becomes zero","The labor force participation rate must rise"],a:0,tag:"steady_state_unemployment",type:"interpretation",objective:"LO7.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"gets_separation_rate_effect_backward",feedback:"A higher separation rate raises unemployment because more employed workers lose or leave jobs."},
{id:152,sourceGame:"nationalEngine",q:"If the job separation rate is 0.05, what is the average employment spell implied by the model?",options:["20 months","5 months","50 months","10 months"],a:0,tag:"job_separation",type:"calculation",objective:"LO7.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"steady_state_unemployment_calculation",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"steady_state_unemployment_calculation",commonError:"uses_s_instead_of_inverse_s",feedback:"Average employment spell is roughly 1/s = 1/0.05 = 20 months."},
{id:153,sourceGame:"nationalEngine",q:"If the job finding rate is 0.25, what is the average unemployment spell implied by the model?",options:["4 months","25 months","2.5 months","40 months"],a:0,tag:"job_finding",type:"calculation",objective:"LO7.2",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"steady_state_unemployment_calculation",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"steady_state_unemployment_calculation",commonError:"uses_f_instead_of_inverse_f",feedback:"Average unemployment spell is roughly 1/f = 1/0.25 = 4 months."},
{id:154,sourceGame:"nationalEngine",q:"A worker quits to search for a better job match in another city. What type of unemployment is this most likely?",options:["Frictional unemployment","Structural unemployment","Cyclical unemployment","Hidden inflation"],a:0,tag:"frictional_unemployment",type:"application",objective:"LO7.3",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"frictional_vs_other_unemployment",secondarySkills:[],repairSkill:"frictional_vs_other_unemployment",commonError:"confuses_voluntary_search_with_structural_unemployment",feedback:"Job search and matching problems create frictional unemployment."},
{id:155,sourceGame:"nationalEngine",q:"A legal minimum wage is set above equilibrium for low-skill workers. What is the likely result?",options:["Structural unemployment from job rationing","Frictional unemployment from faster matching","A lower labor supply than labor demand","A direct increase in real GDP measurement"],a:0,tag:"minimum_wage",type:"application",objective:"LO7.3",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"minimum_wage_structural_unemployment",commonError:"misses_surplus_labor_from_binding_wage_floor",feedback:"A binding minimum wage holds wages above equilibrium and can create structural unemployment."},
{id:156,sourceGame:"nationalEngine",q:"A union negotiates wages above the market-clearing wage. Who are the outsiders in the union model?",options:["Unemployed nonunion workers who would accept lower wages","Current union workers protected by the contract","Firms receiving government transfers","Workers counted twice in the establishment survey"],a:0,tag:"unions",type:"identification",objective:"LO7.3",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"union_wage_rigidity",secondarySkills:[],repairSkill:"union_wage_rigidity",commonError:"confuses_insiders_and_outsiders",feedback:"Outsiders are unemployed nonunion workers who would prefer market-clearing wages because those wages would create more jobs."},
{id:157,sourceGame:"nationalEngine",q:"A firm pays above-equilibrium wages to reduce shirking because monitoring is imperfect. Which theory is this?",options:["Efficiency wage theory","CPI substitution bias","GDP deflator theory","Loanable funds equilibrium"],a:0,tag:"efficiency_wages",type:"application",objective:"LO7.3",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"efficiency_wage_theory",secondarySkills:[],repairSkill:"efficiency_wage_theory",commonError:"misses_worker_effort_channel",feedback:"Efficiency wage theory says firms may pay high wages to increase effort when worker behavior is hard to monitor."},
{id:158,sourceGame:"nationalEngine",q:"A group of unemployed workers receives better job-opening information through an employment agency. Which unemployment problem is this most directly meant to reduce?",options:["Frictional unemployment","Structural unemployment from wage rigidity","Cyclical unemployment from a recession","Measured CPI inflation"],a:0,tag:"frictional_unemployment",type:"application",objective:"LO7.3",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"sectoral_shift_matching",secondarySkills:[],repairSkill:"sectoral_shift_matching",commonError:"chooses_structural_when_policy_targets_matching",feedback:"Better job-opening information improves matching and reduces frictional unemployment."},
{id:159,sourceGame:"nationalEngine",q:"Fifty people are unemployed for 4 weeks each, while 5 people are unemployed for 30 weeks each. Why can the long-term group matter so much in unemployment data?",options:["They account for many total unemployment weeks despite fewer people","They are always counted as employed","They remove unemployment from the labor force","They are counted only in GDP investment"],a:0,tag:"unemployment_duration",type:"interpretation",objective:"LO7.3",difficulty:"medium",conceptCluster:"national_engine_medium",primarySkill:"unemployment_duration_calculation",secondarySkills:[],repairSkill:"unemployment_duration_calculation",commonError:"confuses_number_of_people_with_total_weeks",feedback:"Long spells can contribute many total weeks of unemployment even when the number of long-term unemployed is small."}
],
	
hard:[
{id:200,sourceGame:"nationalEngine",q:"A senator claims GDP rose, so household well-being must have risen. Which response is strongest?",options:["GDP measures production, but it misses distribution, nonmarket work, and some quality-of-life issues","GDP measures only income inequality, so the claim is backward","GDP measures only unemployment, so production is irrelevant","GDP already includes happiness, so no other indicator is needed"],a:0,tag:"gdp",type:"application",objective:"LO2.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"gdp_inclusion_exclusion",secondarySkills:["gdp_components_identity"],repairSkill:"gdp_inclusion_exclusion",commonError:"treats_gdp_as_complete_welfare_measure",feedback:"GDP is useful for output, but it does not fully measure well-being, distribution, unpaid work, or broader living conditions."},
{id:201,sourceGame:"nationalEngine",q:"A country imports oil, produces cars domestically, and sells some cars abroad. Which statement about CPI and GDP deflator is correct?",options:["Imported oil affects CPI if consumers buy it, but not the GDP deflator","Imported oil affects the GDP deflator because it is purchased domestically","Exported cars affect CPI more than the GDP deflator","Neither imported oil nor exported cars can affect any price index"],a:0,tag:"gdp_deflator_vs_cpi",type:"application",objective:"LO2.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"price_index_comparison",secondarySkills:[],repairSkill:"price_index_comparison",commonError:"misses_import_export_treatment_in_price_indexes",feedback:"Imported consumer goods can enter the CPI, but imports are excluded from the GDP deflator because they are not domestically produced."},
{id:202,sourceGame:"nationalEngine",q:"A person loses a job, searches for three weeks, then stops searching because no jobs seem available. What happens in official labor statistics after the search stops?",options:["They move from unemployed to out of the labor force","They remain unemployed because they still want a job","They become employed in the establishment survey","They stay in the labor force but lower employment"],a:0,tag:"labor_force",type:"application",objective:"LO2.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"employment_status_classification",secondarySkills:["labor_underutilization_classification"],repairSkill:"employment_status_classification",commonError:"counts_discouraged_workers_as_unemployed",feedback:"Once the person stops actively searching, they are no longer counted as unemployed in the official labor force measure."},
{id:203,sourceGame:"nationalEngine",q:"A firm buys a used machine from another domestic firm and pays a broker fee for arranging the sale. What enters current GDP?",options:["Only the broker’s current service fee","The full used-machine price plus the broker fee","The full used-machine price only","Neither the machine nor the service fee"],a:0,tag:"gdp",type:"application",objective:"LO2.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"gdp_inclusion_exclusion",secondarySkills:[],repairSkill:"gdp_inclusion_exclusion",commonError:"counts_used_capital_as_current_output",feedback:"The used machine was produced in the past, but the broker’s current service is newly produced and counted."},
{id:204,sourceGame:"nationalEngine",q:"An economy has C = 900, I = 240, G = 300, exports = 180, and imports = 260. What is GDP?",options:["1360","1880","1620","1440"],a:0,tag:"gdp_components",type:"calculation",objective:"LO2.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"gdp_expenditure_calculation",secondarySkills:[],repairSkill:"gdp_expenditure_calculation",commonError:"adds_imports_instead_of_subtracting",feedback:"GDP = 900 + 240 + 300 + 180 - 260 = 1360."},
{id:205,sourceGame:"nationalEngine",q:"GDP is 2000, C is 1200, I is 350, G is 500, and imports are 180. What are exports?",options:["130","310","-50","230"],a:0,tag:"gdp_components",type:"calculation",objective:"LO2.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"gdp_expenditure_calculation",secondarySkills:[],repairSkill:"gdp_expenditure_calculation",commonError:"solves_for_nx_but_not_exports",feedback:"2000 = 1200 + 350 + 500 + (X - 180), so 2000 = 1870 + X and exports equal 130."},
{id:206,sourceGame:"nationalEngine",q:"Base-year basket cost is 250. Current basket cost is 315. What is the CPI?",options:["126","65","79.4","315"],a:0,tag:"cpi",type:"calculation",objective:"LO2.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"cpi_inflation_calculation",secondarySkills:[],repairSkill:"cpi_inflation_calculation",commonError:"subtracts_instead_of_indexing",feedback:"CPI = 100 × 315 / 250 = 126."},
{id:207,sourceGame:"nationalEngine",q:"The CPI rises from 150 to 165. The GDP deflator rises from 125 to 130. Which inflation rate is larger?",options:["CPI inflation is larger","GDP deflator inflation is larger","They are equal","Neither can be calculated"],a:0,tag:"inflation",type:"calculation",objective:"LO2.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"price_index_comparison",secondarySkills:["cpi_inflation_calculation"],repairSkill:"cpi_inflation_calculation",commonError:"compares_index_levels_instead_of_percentage_changes",feedback:"CPI inflation is 10%, while GDP deflator inflation is 4%, so CPI inflation is larger."},
{id:208,sourceGame:"nationalEngine",q:"Nominal GDP is 4400 and the GDP deflator is 110. What is real GDP?",options:["4000","4840","4510","3300"],a:0,tag:"gdp_deflator",type:"calculation",objective:"LO2.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"gdp_deflator_inflation",secondarySkills:[],repairSkill:"gdp_deflator_inflation",commonError:"multiplies_by_deflator_instead_of_dividing",feedback:"Real GDP = nominal GDP / (deflator/100) = 4400 / 1.10 = 4000."},
{id:209,sourceGame:"nationalEngine",q:"An economy has 190 employed, 10 unemployed, and 50 not in the labor force. What is the labor force participation rate?",options:["80%","5%","76%","95%"],a:0,tag:"lfpr",type:"calculation",objective:"LO2.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"labor_force_statistics_calculation",secondarySkills:[],repairSkill:"labor_force_statistics_calculation",commonError:"uses_employed_only_in_numerator",feedback:"Labor force = 190 + 10 = 200. Adult population = 250. LFPR = 200/250 × 100 = 80%."},
{id:210,sourceGame:"nationalEngine",q:"An economy has 180 employed, 20 unemployed, and 100 not in the labor force. Ten unemployed workers stop looking. What is the new unemployment rate?",options:["5.3%","10%","6.7%","3.3%"],a:0,tag:"unemployment_rate",type:"calculation",objective:"LO2.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"labor_force_statistics_calculation",secondarySkills:["employment_status_classification"],repairSkill:"labor_force_statistics_calculation",commonError:"keeps_discouraged_workers_in_labor_force",feedback:"After 10 stop searching, unemployed = 10 and labor force = 190, so unemployment = 10/190 = 5.3%."},
{id:211,sourceGame:"nationalEngine",q:"A base-year economy produces 10 units at $4 and 20 units at $3. In the current year it produces 12 units and 25 units at current prices of $5 and $4. What is real GDP using base-year prices?",options:["123","160","148","70"],a:0,tag:"real_nominal_gdp",type:"calculation",objective:"LO2.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"real_vs_nominal_gdp",secondarySkills:["gdp_deflator_inflation"],repairSkill:"real_vs_nominal_gdp",commonError:"uses_current_prices_for_real_gdp",feedback:"Real GDP uses base-year prices with current quantities: 12×4 + 25×3 = 48 + 75 = 123."},
{id:212,sourceGame:"nationalEngine",q:"In the Chapter 3 model, output is fixed but demand depends on C, I, and G. What variable adjusts to bring goods demand into line with fixed output?",options:["The real interest rate","The CPI basket","The natural unemployment rate","The nominal wage only"],a:0,tag:"goods_market_equilibrium",type:"application",objective:"LO3.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"production_function_output",secondarySkills:["saving_investment_equilibrium"],repairSkill:"production_function_output",commonError:"misses_interest_rate_adjustment_channel",feedback:"With output fixed, the real interest rate adjusts through investment and saving to balance demand with output."},
{id:213,sourceGame:"nationalEngine",q:"A production function has Y = A K^0.4 L^0.6. What returns to scale does it have?",options:["Constant returns to scale","Increasing returns to scale","Decreasing returns to scale","No returns to scale can be inferred"],a:0,tag:"returns_to_scale",type:"application",objective:"LO3.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"returns_to_scale_classification",secondarySkills:["production_function_output"],repairSkill:"returns_to_scale_classification",commonError:"does_not_add_exponents",feedback:"The exponents add to 1.0, so the production function has constant returns to scale."},
{id:214,sourceGame:"nationalEngine",q:"A production function has Y = A K^0.7 L^0.6. What returns to scale does it have?",options:["Increasing returns to scale","Constant returns to scale","Decreasing returns to scale","Diminishing inflation"],a:0,tag:"returns_to_scale",type:"application",objective:"LO3.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"returns_to_scale_classification",secondarySkills:["production_function_output"],repairSkill:"returns_to_scale_classification",commonError:"misses_exponents_sum_above_one",feedback:"The exponents add to 1.3, so doubling inputs more than doubles output."},
{id:215,sourceGame:"nationalEngine",q:"If capital and labor are fixed, which event increases output in the production function without adding inputs?",options:["A rise in total factor productivity","A higher CPI from imported goods","A lower labor force participation rate","A larger transfer payment"],a:0,tag:"production_function",type:"application",objective:"LO3.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"production_function_output",secondarySkills:[],repairSkill:"production_function_output",commonError:"confuses_productivity_with_spending_change",feedback:"Higher total factor productivity lets the same capital and labor produce more output."},
{id:216,sourceGame:"nationalEngine",q:"Why does a closed-economy Chapter 3 model need the loanable funds market after output is fixed by production?",options:["Because the interest rate must reconcile desired investment with saving","Because GDP cannot be measured without the CPI","Because unemployment must equal zero","Because imports must equal exports"],a:0,tag:"income_expenditure",type:"application",objective:"LO3.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"production_function_output",secondarySkills:["saving_investment_equilibrium"],repairSkill:"production_function_output",commonError:"misses_goods_market_balance_problem",feedback:"Once output is fixed, the real interest rate adjusts so planned demand and saving-investment conditions are consistent."},
{id:217,sourceGame:"nationalEngine",q:"If a production function shows diminishing marginal product of labor, what happens as labor rises with capital fixed?",options:["Output rises at a decreasing rate","Output must fall immediately","The real wage must become negative","CPI inflation must rise"],a:0,tag:"production_function",type:"interpretation",objective:"LO3.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"production_function_output",secondarySkills:["diminishing_marginal_product"],repairSkill:"production_function_output",commonError:"confuses_diminishing_marginal_product_with_falling_total_output",feedback:"Diminishing marginal product means total output can keep rising, but each additional worker adds less output."},
{id:218,sourceGame:"nationalEngine",q:"A model assumes capital, labor, and technology are fixed, but government spending rises. What happens to total output in the Chapter 3 setup?",options:["Output stays fixed, while demand-side components must adjust","Output rises one-for-one with government spending","Output falls because public saving rises","Output becomes equal to CPI"],a:0,tag:"production",type:"application",objective:"LO3.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"production_function_output",secondarySkills:["fiscal_policy_crowding_out"],repairSkill:"production_function_output",commonError:"treats_fixed_output_model_as_multiplier_model",feedback:"In this model, output is fixed by production inputs; higher government spending changes demand and saving, not total output directly."},
{id:219,sourceGame:"nationalEngine",q:"A firm sells output for $8 and pays a nominal wage of $40. It should hire workers until MPL is closest to what?",options:["5","40","8","320"],a:0,tag:"labor_demand",type:"calculation",objective:"LO3.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"multiplies_wage_and_price",feedback:"The real wage is W/P = 40/8 = 5, so the firm hires until MPL is about 5."},
{id:220,sourceGame:"nationalEngine",q:"A firm’s MPL values are 20, 16, 12, 8, 4. If W/P = 10, how many workers should it hire?",options:["3","4","2","5"],a:0,tag:"labor_demand",type:"calculation",objective:"LO3.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"hires_worker_with_mpl_below_real_wage",feedback:"The firm hires workers whose MPL is at least the real wage. The first three workers have MPL above 10; the fourth has 8."},
{id:221,sourceGame:"nationalEngine",q:"Refer to the marginal product graph. If the real wage rises, what happens to the amount of labor demanded?",options:["It falls as the firm moves to a lower quantity of labor on MPL","It rises because labor is now more expensive","It stays fixed because MPL is unrelated to wages","It becomes equal to national saving"],a:0,tag:"labor_demand",type:"graph_interpretation",objective:"LO3.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:["diminishing_marginal_product"],repairSkill:"labor_demand_mpl_real_wage",commonError:"gets_real_wage_labor_demand_backward",feedback:"A higher real wage means the firm hires fewer workers because fewer workers have MPL high enough to justify the wage.",image:"marginalproduct.webp"},
{id:222,sourceGame:"nationalEngine",q:"A table shows output rising from 0 to 12 to 22 to 29 as labor rises from 0 to 1 to 2 to 3. What is the MPL of the third worker?",options:["7","10","12","29"],a:0,tag:"marginal_product",type:"calculation",objective:"LO3.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"total_product_to_marginal_product",secondarySkills:[],repairSkill:"total_product_to_marginal_product",commonError:"uses_total_output_instead_of_change_in_output",feedback:"The third worker raises output from 22 to 29, so MPL = 7."},
{id:223,sourceGame:"nationalEngine",q:"If labor becomes more abundant while capital is fixed, what happens to MPL and the real wage in the competitive factor market story?",options:["MPL falls and the real wage falls","MPL rises and the real wage rises","MPL falls and the real wage rises","MPL is unchanged and the real wage must rise"],a:0,tag:"factor_markets",type:"application",objective:"LO3.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"diminishing_marginal_product",secondarySkills:["labor_demand_mpl_real_wage"],repairSkill:"diminishing_marginal_product",commonError:"misses_abundance_lower_marginal_product",feedback:"More labor with fixed capital lowers the marginal product of labor and therefore lowers the competitive real wage."},
{id:224,sourceGame:"nationalEngine",q:"If capital falls after a disaster while labor is unchanged, what happens to MPK in the factor market logic?",options:["MPK rises because remaining capital is scarcer","MPK falls because capital is less useful","MPK becomes equal to CPI","MPK becomes the unemployment rate"],a:0,tag:"factor_prices",type:"application",objective:"LO3.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"diminishing_marginal_product",secondarySkills:["factor_income_distribution"],repairSkill:"diminishing_marginal_product",commonError:"gets_scarcity_effect_on_mpk_backward",feedback:"When capital becomes scarcer, the marginal product of remaining capital rises."},
{id:225,sourceGame:"nationalEngine",q:"A worker’s nominal wage rises from $20 to $24, while the price of output rises from $4 to $6. What happens to the real wage?",options:["It falls from 5 to 4","It rises from 5 to 6","It stays at 5","It rises from 4 to 5"],a:0,tag:"factor_prices",type:"calculation",objective:"LO3.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"looks_only_at_nominal_wage",feedback:"Initial real wage is 20/4 = 5. New real wage is 24/6 = 4, so it falls."},
{id:226,sourceGame:"nationalEngine",q:"Refer to the total product graph. If total product eventually falls after too many workers are added, what does the MPL become?",options:["Negative","Constant","Equal to the real wage by definition","Equal to public saving"],a:0,tag:"marginal_product",type:"graph_interpretation",objective:"LO3.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"total_product_to_marginal_product",secondarySkills:["diminishing_marginal_product"],repairSkill:"total_product_to_marginal_product",commonError:"misses_negative_marginal_product",feedback:"If adding a worker lowers total output, that worker’s marginal product is negative.",image:"totalproduct.webp"},
{id:227,sourceGame:"nationalEngine",q:"A competitive firm will stop hiring before which worker?",options:["The first worker whose MPL is below W/P","The first worker whose MPL is above W/P","Every worker whose MPL is positive","Every worker after total output first rises"],a:0,tag:"labor_demand",type:"application",objective:"LO3.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"hires_positive_mpl_even_when_below_real_wage",feedback:"A firm should not hire a worker whose marginal product is below the real wage."},
{id:228,sourceGame:"nationalEngine",q:"In a Cobb-Douglas economy with alpha = 0.45 and total income of 2000, what is capital income?",options:["900","1100","450","1550"],a:0,tag:"factor_shares",type:"calculation",objective:"LO3.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:[],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"uses_labor_share_for_capital_income",feedback:"Capital income = alpha × Y = 0.45 × 2000 = 900."},
{id:229,sourceGame:"nationalEngine",q:"In a Cobb-Douglas economy with alpha = 0.25 and total income of 1600, what is labor income?",options:["1200","400","640","1000"],a:0,tag:"factor_shares",type:"calculation",objective:"LO3.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:[],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"uses_alpha_for_labor_income",feedback:"Labor’s share is 1 - alpha = 0.75, so labor income is 0.75 × 1600 = 1200."},
{id:230,sourceGame:"nationalEngine",q:"If alpha = 0.4 and labor rises by 6% with capital and technology fixed, Cobb-Douglas predicts output rises by about what?",options:["3.6%","2.4%","6.0%","10.0%"],a:0,tag:"cobb_douglas",type:"calculation",objective:"LO3.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:[],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"uses_alpha_instead_of_labor_exponent",feedback:"Labor’s exponent is 1 - alpha = 0.6, so output rises about 0.6 × 6% = 3.6%."},
{id:231,sourceGame:"nationalEngine",q:"If alpha = 0.3 and capital rises by 10% with labor and technology fixed, Cobb-Douglas predicts output rises by about what?",options:["3%","7%","10%","13%"],a:0,tag:"cobb_douglas",type:"calculation",objective:"LO3.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:[],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"uses_labor_share_for_capital_growth",feedback:"Capital’s exponent is alpha = 0.3, so output rises about 0.3 × 10% = 3%."},
{id:232,sourceGame:"nationalEngine",q:"If capital’s share has risen over time, why might basic Cobb-Douglas still be useful but incomplete?",options:["It gives a clear benchmark, but constant shares may not hold in reality","It proves capital shares can never change","It ignores marginal products entirely","It only applies to unemployment spells"],a:0,tag:"income_distribution",type:"application",objective:"LO3.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"factor_income_distribution",secondarySkills:["cobb_douglas_factor_share_calculation"],repairSkill:"factor_income_distribution",commonError:"treats_model_as_literal_fact",feedback:"Cobb-Douglas is a useful benchmark, but real-world factor shares can change with technology, bargaining power, and globalization."},
{id:233,sourceGame:"nationalEngine",q:"A firm owns its own capital instead of renting it from households. Why does this matter for measured profit?",options:["Accounting profit includes the return to owner-supplied capital","Economic profit becomes equal to CPI inflation","Labor income disappears from GDP","Capital no longer has a marginal product"],a:0,tag:"income_distribution",type:"application",objective:"LO3.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"factor_income_distribution",secondarySkills:[],repairSkill:"factor_income_distribution",commonError:"confuses_accounting_profit_with_economic_profit",feedback:"When firms own capital, accounting profit includes both economic profit and the return to that capital."},
{id:234,sourceGame:"nationalEngine",q:"If all factors are paid their marginal products and the production function has constant returns to scale, what happens to economic profit in the ideal model?",options:["It is driven to zero","It equals total labor income","It equals the CPI deflator","It must exceed capital income"],a:0,tag:"income_distribution",type:"interpretation",objective:"LO3.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"factor_income_distribution",secondarySkills:["returns_to_scale_classification"],repairSkill:"factor_income_distribution",commonError:"misses_exhaustion_of_output_under_crs",feedback:"With constant returns and factors paid marginal products, output is exhausted by factor payments, leaving zero economic profit in the ideal setup."},
{id:235,sourceGame:"nationalEngine",q:"A rise in automation increases output but weakens labor’s bargaining position. Which outcome is most consistent with the income distribution discussion?",options:["Capital’s share may rise while labor’s share falls","Labor’s share must rise because output rose","Factor shares cannot change under any real condition","The unemployment rate becomes equal to alpha"],a:0,tag:"income_distribution",type:"application",objective:"LO3.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"factor_income_distribution",secondarySkills:[],repairSkill:"factor_income_distribution",commonError:"assumes_output_growth_guarantees_labor_share_growth",feedback:"Technology can increase output while shifting income toward capital if it favors capital or weakens labor’s bargaining position."},
{id:236,sourceGame:"nationalEngine",q:"If C = 200 + 0.75(Y - T), Y = 2400, and T = 400, what is consumption?",options:["1700","1800","2000","1500"],a:0,tag:"consumption_function",type:"calculation",objective:"LO3.4",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"consumption_function_calculation",secondarySkills:[],repairSkill:"consumption_function_calculation",commonError:"forgets_autonomous_consumption_or_taxes",feedback:"Disposable income is 2000. Consumption = 200 + 0.75(2000) = 1700."},
{id:237,sourceGame:"nationalEngine",q:"If taxes rise by 100 and MPC = 0.8, what is the direct change in consumption?",options:["Consumption falls by 80","Consumption falls by 20","Consumption rises by 80","Consumption rises by 100"],a:0,tag:"consumption",type:"calculation",objective:"LO3.4",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"mpc_disposable_income",secondarySkills:["consumption_function_calculation"],repairSkill:"mpc_disposable_income",commonError:"uses_mps_or_wrong_sign",feedback:"A tax increase lowers disposable income, so consumption falls by MPC × tax change = 0.8 × 100 = 80."},
{id:238,sourceGame:"nationalEngine",q:"Refer to the consumption function graph. If households become more optimistic about future income, what happens at a given current disposable income?",options:["Consumption rises because the function shifts upward","Consumption falls because income moves down the same curve","Consumption stays fixed because expectations do not matter","Consumption becomes equal to public saving"],a:0,tag:"consumption_function",type:"graph_interpretation",objective:"LO3.4",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"consumption_movement_vs_shift",secondarySkills:[],repairSkill:"consumption_movement_vs_shift",commonError:"treats_expectations_as_movement_along_curve",feedback:"More optimism raises consumption at a given disposable income, shifting the consumption function upward.",image:"consumptionfunction.webp"},
{id:239,sourceGame:"nationalEngine",q:"If the nominal interest rate is 9% and inflation is 4%, what real interest rate should be used in the investment function?",options:["5%","13%","9%","4%"],a:0,tag:"investment",type:"calculation",objective:"LO3.4",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"real_interest_investment_calculation",secondarySkills:[],repairSkill:"real_interest_investment_calculation",commonError:"adds_inflation_instead_of_subtracting",feedback:"The real interest rate is nominal interest minus inflation: 9% - 4% = 5%."},
{id:240,sourceGame:"nationalEngine",q:"Investment is I = 2000 - 100r. If the nominal rate is 10% and inflation is 3%, what is investment?",options:["1300","1000","1700","700"],a:0,tag:"investment",type:"calculation",objective:"LO3.4",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"real_interest_investment_calculation",secondarySkills:["investment_interest_rate_relationship"],repairSkill:"real_interest_investment_calculation",commonError:"uses_nominal_rate_instead_of_real_rate",feedback:"The real rate is 7, so I = 2000 - 100(7) = 1300."},
{id:241,sourceGame:"nationalEngine",q:"Refer to the investment function graph. Which event moves the economy along a given investment curve rather than shifting it?",options:["A decrease in the real interest rate","A permanent rise in expected profits","A new investment tax incentive","A technology improvement that raises returns"],a:0,tag:"investment_function",type:"graph_interpretation",objective:"LO3.4",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"investment_function_movement_vs_shift",secondarySkills:[],repairSkill:"investment_function_movement_vs_shift",commonError:"confuses_interest_rate_movement_with_investment_demand_shift",feedback:"A change in the real interest rate moves along the investment curve; changes in expected profitability shift it.",image:"investmentfunction.webp"},
{id:242,sourceGame:"nationalEngine",q:"Refer to the investment function graph. If expected profits rise while the real interest rate also falls, which point movement is most consistent with higher investment from both forces?",options:["Toward the farthest right investment point","Toward the highest interest-rate point on the original curve","Toward lower investment on the shifted curve","Toward unchanged investment on the original curve"],a:0,tag:"investment_function",type:"graph_interpretation",objective:"LO3.4",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"investment_function_movement_vs_shift",secondarySkills:[],repairSkill:"investment_function_movement_vs_shift",commonError:"misses_combined_shift_and_movement",feedback:"Higher expected profits shift investment demand right, and a lower real interest rate moves down the curve, both raising investment.",image:"investmentfunction.webp"},
{id:243,sourceGame:"nationalEngine",q:"A business tax cut raises the expected return on capital projects. In the investment function, what should happen before any interest-rate adjustment?",options:["Investment demand shifts right","Investment demand shifts left","There is only movement up along the same curve","Consumption shifts downward"],a:0,tag:"investment_function",type:"application",objective:"LO3.4",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"investment_function_movement_vs_shift",secondarySkills:[],repairSkill:"investment_function_movement_vs_shift",commonError:"treats_tax_cut_as_interest_rate_movement",feedback:"A business tax cut that raises expected returns increases investment demand at each interest rate, shifting the curve right."},
{id:244,sourceGame:"nationalEngine",q:"If the MPC is 0.9, what is the marginal propensity to save?",options:["0.1","0.9","1.9","9"],a:0,tag:"consumption",type:"calculation",objective:"LO3.4",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"mpc_disposable_income",secondarySkills:[],repairSkill:"mpc_disposable_income",commonError:"does_not_use_one_minus_mpc",feedback:"The marginal propensity to save is 1 - MPC = 1 - 0.9 = 0.1."},
{id:245,sourceGame:"nationalEngine",q:"If C = 500 + 0.6(Y - T), which change shifts the consumption function rather than moving along it?",options:["A change in household wealth","A change in current disposable income","A change in Y with taxes fixed","A change in T with income fixed"],a:0,tag:"consumption_function",type:"application",objective:"LO3.4",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"consumption_movement_vs_shift",secondarySkills:[],repairSkill:"consumption_movement_vs_shift",commonError:"confuses_current_disposable_income_with_shift_factor",feedback:"A change in wealth changes consumption at each level of disposable income, so it shifts the function."},
{id:246,sourceGame:"nationalEngine",q:"If Y = 3000, T = 800, C = 1800, and G = 900, what is national saving?",options:["300","400","1200","-100"],a:0,tag:"national_saving",type:"calculation",objective:"LO3.5",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"saving_identity_calculation",secondarySkills:[],repairSkill:"saving_identity_calculation",commonError:"confuses_private_public_and_national_saving",feedback:"National saving = Y - C - G = 3000 - 1800 - 900 = 300."},
{id:247,sourceGame:"nationalEngine",q:"If Y = 2000, T = 500, C = 1200, and G = 650, what are private saving and public saving?",options:["Private saving = 300 and public saving = -150","Private saving = 800 and public saving = 150","Private saving = 150 and public saving = 300","Private saving = -150 and public saving = 300"],a:0,tag:"national_saving",type:"calculation",objective:"LO3.5",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"saving_identity_calculation",secondarySkills:[],repairSkill:"saving_identity_calculation",commonError:"reverses_private_and_public_saving",feedback:"Private saving = Y - T - C = 300. Public saving = T - G = -150."},
{id:248,sourceGame:"nationalEngine",q:"Refer to the loanable funds graph. If taxes rise and consumption falls by less than the tax increase, what happens to national saving?",options:["It rises and shifts saving right","It falls and shifts saving left","It stays fixed because taxes do not matter","It becomes equal to imports"],a:0,tag:"loanable_funds",type:"graph_interpretation",objective:"LO3.5",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"loanable_funds_graph_shifts",secondarySkills:["fiscal_policy_crowding_out"],repairSkill:"loanable_funds_graph_shifts",commonError:"misses_public_saving_effect_of_tax_increase",feedback:"A tax increase raises public saving, and if consumption falls by less than the tax increase, national saving rises.",image:"loanablefunds.webp"},
{id:249,sourceGame:"nationalEngine",q:"Refer to the loanable funds graph. If government purchases rise with output and taxes fixed, which movement is most likely?",options:["Saving shifts left, r rises, and investment falls","Saving shifts right, r falls, and investment rises","Investment demand shifts right, r rises, and saving falls","Investment demand shifts left, r falls, and G rises"],a:0,tag:"crowding_out",type:"graph_interpretation",objective:"LO3.5",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"fiscal_policy_crowding_out",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"fiscal_policy_crowding_out",commonError:"gets_crowding_out_chain_backward",feedback:"Higher government purchases lower public saving, shift national saving left, raise the real interest rate, and reduce investment.",image:"loanablefunds.webp"},
{id:250,sourceGame:"nationalEngine",q:"Refer to the loanable funds graph. If investment demand shifts right while saving is vertical, what happens first?",options:["The real interest rate rises while equilibrium investment is pinned by saving","Investment rises greatly with no interest-rate change","Saving shifts left automatically","Public saving must become negative"],a:0,tag:"loanable_funds",type:"graph_interpretation",objective:"LO3.5",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"investment_demand_vs_saving_shift",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"investment_demand_vs_saving_shift",commonError:"assumes_vertical_saving_allows_large_quantity_change",feedback:"With vertical saving, a rightward shift in investment demand mainly raises the real interest rate because saving pins the quantity.",image:"loanablefunds.webp"},
{id:251,sourceGame:"nationalEngine",q:"A government cuts taxes by 100 and MPC = 0.8. In the Chapter 3 saving logic, what is the direct change in private saving?",options:["Private saving rises by 20","Private saving falls by 80","Private saving rises by 80","Private saving is unchanged"],a:0,tag:"private_saving",type:"calculation",objective:"LO3.5",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"saving_identity_calculation",secondarySkills:["mpc_disposable_income"],repairSkill:"saving_identity_calculation",commonError:"confuses_consumption_change_with_saving_change",feedback:"A 100 tax cut raises disposable income by 100 and consumption by 80, so private saving rises by 20."},
{id:252,sourceGame:"nationalEngine",q:"A government cuts taxes by 100 and MPC = 0.8. What happens to national saving, holding Y and G fixed?",options:["It falls by 80","It rises by 20","It falls by 100","It is unchanged"],a:0,tag:"national_saving",type:"calculation",objective:"LO3.5",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"saving_identity_calculation",secondarySkills:["fiscal_policy_crowding_out"],repairSkill:"saving_identity_calculation",commonError:"looks_only_at_private_saving",feedback:"Private saving rises by 20, but public saving falls by 100, so national saving falls by 80."},
{id:253,sourceGame:"nationalEngine",q:"Refer to the loanable funds graph. A policy that increases national saving should do what to the real interest rate and investment?",options:["Lower r and raise investment","Raise r and lower investment","Raise both r and investment demand","Lower both saving and investment"],a:0,tag:"loanable_funds",type:"graph_interpretation",objective:"LO3.5",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"loanable_funds_graph_shifts",secondarySkills:[],repairSkill:"loanable_funds_graph_shifts",commonError:"gets_saving_shift_effect_backward",feedback:"Higher national saving shifts saving right, lowering the real interest rate and increasing investment.",image:"loanablefunds.webp"},
{id:254,sourceGame:"nationalEngine",q:"If investment demand rises because of new technology but national saving is fixed, why might actual investment fail to rise much?",options:["The real interest rate rises to ration the fixed saving","The CPI blocks investment from entering GDP","Government purchases automatically fall","The unemployment rate must rise one-for-one"],a:0,tag:"loanable_funds",type:"application",objective:"LO3.5",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"investment_demand_vs_saving_shift",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"investment_demand_vs_saving_shift",commonError:"misses_fixed_saving_constraint",feedback:"If saving is fixed, stronger investment demand raises the real interest rate rather than greatly increasing investment."},
{id:255,sourceGame:"nationalEngine",q:"If the real interest rate is below equilibrium in the loanable funds market, what pressure emerges?",options:["Investment demand exceeds saving, pushing the interest rate up","Saving exceeds investment demand, pushing the interest rate down","The CPI rises until investment disappears","The natural rate of unemployment falls to zero"],a:0,tag:"loanable_funds",type:"application",objective:"LO3.5",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"saving_investment_equilibrium",secondarySkills:[],repairSkill:"saving_investment_equilibrium",commonError:"gets_shortage_of_funds_adjustment_backward",feedback:"When r is too low, desired investment exceeds saving, so competition for funds pushes r upward."},
{id:256,sourceGame:"nationalEngine",q:"If the real interest rate is above equilibrium in the loanable funds market, what pressure emerges?",options:["Saving exceeds investment demand, pushing the interest rate down","Investment demand exceeds saving, pushing the interest rate up","GDP deflator falls to zero","Public saving must become negative"],a:0,tag:"loanable_funds",type:"application",objective:"LO3.5",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"saving_investment_equilibrium",secondarySkills:[],repairSkill:"saving_investment_equilibrium",commonError:"gets_surplus_of_funds_adjustment_backward",feedback:"When r is too high, desired investment is below saving, so the real interest rate tends to fall."},
{id:257,sourceGame:"nationalEngine",q:"A policy memo says, 'Deficit-financed spending raises output in Chapter 3 because output is demand-determined.' What is the best correction?",options:["In this model output is fixed by production, so the deficit mainly lowers saving and crowds out investment","In this model GDP is measured only by CPI, so deficits cannot matter","In this model taxes always raise investment demand directly","In this model imports must rise by the full deficit"],a:0,tag:"crowding_out",type:"application",objective:"LO3.5",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"fiscal_policy_crowding_out",secondarySkills:["production_function_output"],repairSkill:"fiscal_policy_crowding_out",commonError:"imports_multiplier_logic_into_fixed_output_model",feedback:"Chapter 3 treats output as fixed by production; deficit-financed spending lowers national saving and crowds out investment."},
{id:258,sourceGame:"nationalEngine",q:"Actual unemployment is 7%, frictional unemployment is 2%, structural unemployment is 3%, and cyclical unemployment is 2%. What is the natural rate?",options:["5%","7%","2%","3%"],a:0,tag:"natural_rate",type:"calculation",objective:"LO7.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"natural_rate_definition",secondarySkills:["frictional_vs_other_unemployment"],repairSkill:"natural_rate_definition",commonError:"includes_cyclical_unemployment_in_natural_rate",feedback:"The natural rate includes frictional and structural unemployment: 2% + 3% = 5%."},
{id:259,sourceGame:"nationalEngine",q:"If actual unemployment is below the natural rate, which interpretation is most careful?",options:["The economy may be temporarily overheated, but normal labor-market frictions still exist","The natural rate has become zero","Structural unemployment has disappeared forever","The CPI must be overstating inflation"],a:0,tag:"natural_rate",type:"interpretation",objective:"LO7.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"thinks_below_natural_means_no_labor_market_frictions",feedback:"Unemployment below the natural rate can happen temporarily, but frictional and structural unemployment still exist."},
{id:260,sourceGame:"nationalEngine",q:"A country improves job matching and also reduces layoffs through better experience-rated unemployment insurance. What happens to the natural rate?",options:["It likely falls because f rises and s falls","It rises because both policies increase job separation","It is unchanged because policy cannot affect labor flows","It becomes equal to cyclical unemployment"],a:0,tag:"natural_rate",type:"application",objective:"LO7.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"natural_rate_definition",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"natural_rate_definition",commonError:"misses_policy_effect_on_job_flows",feedback:"Raising job finding and lowering job separation both reduce steady-state unemployment and can lower the natural rate."},
{id:261,sourceGame:"nationalEngine",q:"Which statement is best for a policy memo about the natural rate?",options:["Reducing the natural rate requires improving matching, lowering separations, or reducing wage rigidity","Reducing the natural rate requires only raising current GDP spending","The natural rate is fixed forever by the CPI basket","The natural rate falls whenever nominal GDP rises"],a:0,tag:"natural_rate",type:"application",objective:"LO7.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"natural_rate_definition",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"natural_rate_definition",commonError:"confuses_demand_policy_with_natural_rate_policy",feedback:"The natural rate is tied to job flows and labor-market structure, not just current aggregate spending."},
{id:262,sourceGame:"nationalEngine",q:"A recession raises unemployment from 5% to 9%, but frictional and structural unemployment together remain 5%. What changed?",options:["Cyclical unemployment rose by 4 percentage points","The natural rate rose to 9%","Frictional unemployment disappeared","Structural unemployment became negative"],a:0,tag:"natural_rate",type:"calculation",objective:"LO7.1",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"treats_recession_unemployment_as_natural_rate",feedback:"The natural rate remains 5%; the increase to 9% reflects 4 percentage points of cyclical unemployment."},
{id:263,sourceGame:"nationalEngine",q:"If s = 0.03 and f = 0.27, what is steady-state unemployment?",options:["10%","3%","27%","30%"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"steady_state_unemployment_calculation",secondarySkills:[],repairSkill:"steady_state_unemployment_calculation",commonError:"uses_s_divided_by_f",feedback:"u = s/(s+f) = 0.03/(0.03+0.27) = 0.10, or 10%."},
{id:264,sourceGame:"nationalEngine",q:"If the steady-state unemployment rate is 8% and f = 0.46, which separation rate is closest?",options:["0.04","0.08","0.46","0.50"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"steady_state_unemployment_calculation",secondarySkills:[],repairSkill:"steady_state_unemployment_calculation",commonError:"does_not_solve_steady_state_formula_for_s",feedback:"Using u = s/(s+f), s = uf/(1-u) = 0.08×0.46/0.92 ≈ 0.04."},
{id:265,sourceGame:"nationalEngine",q:"If s = 0.05 and f = 0.20, what is steady-state unemployment, and how does it compare to 15% last month?",options:["20%, so it rises","20%, so it falls","15%, so it is unchanged","25%, so it rises"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"steady_state_unemployment_calculation",secondarySkills:[],repairSkill:"steady_state_unemployment_calculation",commonError:"calculates_rate_but_misreads_direction",feedback:"u = 0.05/(0.05+0.20) = 0.20, so steady-state unemployment is 20%, above 15%."},
{id:266,sourceGame:"nationalEngine",q:"A policy raises f from 0.20 to 0.30 while s remains 0.03. What happens to steady-state unemployment?",options:["It falls from about 13% to about 9%","It rises from about 9% to about 13%","It stays at 3%","It becomes 30%"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"steady_state_unemployment_calculation",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"steady_state_unemployment_calculation",commonError:"gets_f_effect_backward",feedback:"Initial u = 0.03/0.23 ≈ 13%. New u = 0.03/0.33 ≈ 9%."},
{id:267,sourceGame:"nationalEngine",q:"A recession raises job separations from 0.02 to 0.06 while f remains 0.24. What happens to steady-state unemployment?",options:["It rises from about 7.7% to 20%","It falls from 20% to 7.7%","It stays at 24%","It becomes zero"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"steady_state_unemployment_calculation",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"steady_state_unemployment_calculation",commonError:"gets_separation_effect_backward",feedback:"Initial u = 0.02/0.26 ≈ 7.7%. New u = 0.06/0.30 = 20%."},
{id:268,sourceGame:"nationalEngine",q:"If f = 0.25, what is the average unemployment spell, and what policy would shorten it?",options:["4 months; improve job matching","25 months; raise job separation","4 months; reduce job finding","2.5 months; raise wage rigidity"],a:0,tag:"job_finding",type:"application",objective:"LO7.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"steady_state_unemployment_calculation",secondarySkills:["sectoral_shift_matching"],repairSkill:"steady_state_unemployment_calculation",commonError:"uses_f_as_duration_or_picks_wrong_policy",feedback:"Average unemployment spell is 1/f = 4 months, and better matching can raise f and shorten spells."},
{id:269,sourceGame:"nationalEngine",q:"If s = 0.04, what is the average employment spell, and what policy direction would lengthen it?",options:["25 months; reduce separations","4 months; raise separations","25 months; reduce job finding","40 months; raise wage rigidity"],a:0,tag:"job_separation",type:"application",objective:"LO7.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"steady_state_unemployment_calculation",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"steady_state_unemployment_calculation",commonError:"uses_s_as_duration_or_wrong_policy",feedback:"Average employment spell is 1/s = 25 months. Lower job separation lengthens employment spells."},
{id:270,sourceGame:"nationalEngine",q:"At steady state, which flow equality must hold?",options:["sE = fU","sU = fE","sL = fL","U/L = E/L"],a:0,tag:"steady_state_unemployment",type:"interpretation",objective:"LO7.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"reverses_employment_and_unemployment_flows",feedback:"At steady state, flows into unemployment equal flows out: separations from employment sE equal job findings from unemployment fU."},
{id:271,sourceGame:"nationalEngine",q:"If job finding and job separation both rise by the same proportion, what happens to steady-state unemployment?",options:["It stays the same, but labor-market turnover is faster","It must rise because separations rose","It must fall because findings rose","It becomes equal to the labor force participation rate"],a:0,tag:"steady_state_unemployment",type:"application",objective:"LO7.2",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"focuses_on_one_rate_not_ratio",feedback:"Since u = s/(s+f), scaling both rates by the same proportion leaves the unemployment rate unchanged but increases turnover."},
{id:272,sourceGame:"nationalEngine",q:"A new technology wipes out demand for one occupation while expanding another. Workers need time to retrain and relocate. Which unemployment type dominates first?",options:["Frictional unemployment from sectoral shift and matching delays","Structural unemployment from a binding wage floor only","Cyclical unemployment from a fall in all spending","No unemployment because technology always raises employment"],a:0,tag:"frictional_unemployment",type:"application",objective:"LO7.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"sectoral_shift_matching",secondarySkills:["frictional_vs_other_unemployment"],repairSkill:"sectoral_shift_matching",commonError:"misses_sectoral_shift_matching_problem",feedback:"Sectoral shifts create frictional unemployment because workers need time and information to match with new jobs."},
{id:273,sourceGame:"nationalEngine",q:"Refer to the minimum wage graph. If the actual wage is held above equilibrium, what creates structural unemployment?",options:["Labor supplied exceeds labor demanded","Labor demanded exceeds labor supplied","The CPI basket exceeds GDP","Public saving exceeds private saving"],a:0,tag:"minimum_wage",type:"graph_interpretation",objective:"LO7.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"minimum_wage_structural_unemployment",commonError:"gets_labor_surplus_backward",feedback:"A wage above equilibrium causes more workers to want jobs than firms want to hire, creating job rationing.",image:"minimumwage.webp"},
{id:274,sourceGame:"nationalEngine",q:"A city raises the minimum wage and firms respond by cutting hours rather than headcount. What is the best interpretation?",options:["Employment effects can show up through hours and benefits, not just jobs","The policy cannot affect labor costs","Structural unemployment must be zero","The CPI must fall because wages rose"],a:0,tag:"minimum_wage",type:"application",objective:"LO7.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:[],repairSkill:"minimum_wage_structural_unemployment",commonError:"looks_only_at_headcount_effects",feedback:"Minimum wage effects may appear through reduced hours, benefits, or hiring, not only through measured job losses."},
{id:275,sourceGame:"nationalEngine",q:"A firm pays high wages to attract better applicants and reduce hidden shirking. Which two efficiency wage channels are involved?",options:["Worker quality and worker effort","Substitution bias and GDP deflator","Public saving and private saving","Job separation and CPI indexing"],a:0,tag:"efficiency_wages",type:"application",objective:"LO7.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"efficiency_wage_theory",secondarySkills:[],repairSkill:"efficiency_wage_theory",commonError:"misses_efficiency_wage_channels",feedback:"Higher wages can improve applicant quality and increase worker effort when monitoring is imperfect."},
{id:276,sourceGame:"nationalEngine",q:"A union contract raises wages for insiders but leaves some outsiders unemployed. What is the core labor-market mechanism?",options:["Wage rigidity creates job rationing","Better matching eliminates job search","CPI bias lowers real wages","Investment demand shifts right"],a:0,tag:"unions",type:"application",objective:"LO7.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"union_wage_rigidity",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"union_wage_rigidity",commonError:"misses_insider_outsider_job_rationing",feedback:"Union wages can remain above market-clearing levels, creating job rationing for outsiders."},
{id:277,sourceGame:"nationalEngine",q:"Fifty workers are unemployed for 4 weeks each, and 10 workers are unemployed for 30 weeks each. What share of total unemployment weeks comes from the long-term group?",options:["60%","20%","40%","75%"],a:0,tag:"unemployment_duration",type:"calculation",objective:"LO7.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"unemployment_duration_calculation",secondarySkills:[],repairSkill:"unemployment_duration_calculation",commonError:"uses_number_of_people_instead_of_weeks",feedback:"Short-term weeks = 50×4 = 200. Long-term weeks = 10×30 = 300. Long-term share = 300/500 = 60%."},
{id:278,sourceGame:"nationalEngine",q:"Which policy best targets frictional unemployment without directly creating wage rigidity?",options:["Better job vacancy information and retraining for displaced workers","A wage floor above equilibrium","A union contract that restricts hiring","A permanent increase in benefits with no search requirements"],a:0,tag:"frictional_unemployment",type:"policy",objective:"LO7.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"sectoral_shift_matching",secondarySkills:["ui_and_job_search_incentives"],repairSkill:"sectoral_shift_matching",commonError:"chooses_structural_policy_for_frictional_problem",feedback:"Information and retraining improve matching and reduce search time without directly holding wages above equilibrium."},
{id:279,sourceGame:"nationalEngine",q:"A person wants work, is available, searched two months ago, but did not search in the last four weeks. Where do they fit best?",options:["Marginally attached but not officially unemployed","Officially unemployed in U-3","Employed in the establishment survey","Not part of any broader unemployment measure"],a:0,tag:"labor_underutilization",type:"application",objective:"LO7.3",difficulty:"hard",conceptCluster:"national_engine_hard",primarySkill:"labor_underutilization_classification",secondarySkills:[],repairSkill:"labor_underutilization_classification",commonError:"counts_marginally_attached_as_u3_unemployed",feedback:"They are marginally attached because they want work and searched sometime recently, but not within the last four weeks."}
],

elite:[
{id:300,sourceGame:"nationalEngine",q:"A report says GDP rose because households bought more imported phones. Which warning should an advisor add?",options:["Imports enter consumption but are subtracted in net exports","Imports raise GDP because they are bought domestically","Imports count as investment if phones last over one year","Imports enter GDP only through government purchases"],a:0,tag:"gdp",type:"trap",objective:"LO2.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"gdp_components_identity",secondarySkills:["gdp_inclusion_exclusion"],repairSkill:"gdp_components_identity",commonError:"forgets_import_subtraction_in_gdp",feedback:"Imported phones may appear in consumption, but imports are subtracted through NX, so domestic GDP does not rise from foreign production."},
{id:301,sourceGame:"nationalEngine",q:"A policymaker wants a cost-of-living measure for households buying imported consumer goods. Which measure fits better than the GDP deflator?",options:["CPI","Nominal GDP","Real GDP","National saving"],a:0,tag:"gdp_deflator_vs_cpi",type:"application",objective:"LO2.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"price_index_comparison",secondarySkills:["cpi_measurement"],repairSkill:"price_index_comparison",commonError:"uses_gdp_deflator_for_imported_consumer_costs",feedback:"The CPI includes imported consumer goods, while the GDP deflator excludes imports because they are not domestically produced."},
{id:302,sourceGame:"nationalEngine",q:"A senator asks why CPI inflation can exceed the GDP deflator during an oil shock. Which answer is best?",options:["Imported oil can affect consumer prices without entering domestic output prices","Imported oil raises real GDP before it raises consumption","The GDP deflator uses only food and energy prices","The CPI excludes imported goods and services"],a:0,tag:"gdp_deflator_vs_cpi",type:"application",objective:"LO2.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"price_index_comparison",secondarySkills:[],repairSkill:"price_index_comparison",commonError:"misses_imported_goods_difference",feedback:"An imported consumer good can raise the CPI while being excluded from the GDP deflator."},
{id:303,sourceGame:"nationalEngine",q:"A worker has no job, wants one, searched six weeks ago, and is available. What is the cleanest classification?",options:["Marginally attached, not U-3 unemployed","U-3 unemployed, not marginally attached","Employed in the household survey","Outside all labor underutilization measures"],a:0,tag:"labor_force",type:"trap",objective:"LO2.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"employment_status_classification",secondarySkills:["labor_underutilization_classification"],repairSkill:"employment_status_classification",commonError:"counts_marginally_attached_as_officially_unemployed",feedback:"Because the worker did not search in the last four weeks, they are not officially unemployed, but they are marginally attached."},
{id:304,sourceGame:"nationalEngine",q:"A firm produces steel, sells some to automakers, and stores the rest as inventory. Which GDP treatment is correct?",options:["Steel sold as intermediate input is counted through final cars, while inventory counts as investment","All steel sales are excluded because steel is never final output","Only exported steel can count in GDP","Stored steel is ignored until a household buys it"],a:0,tag:"gdp",type:"application",objective:"LO2.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"gdp_inclusion_exclusion",secondarySkills:[],repairSkill:"gdp_inclusion_exclusion",commonError:"excludes_inventory_or_double_counts_intermediate_goods",feedback:"Intermediate steel is counted in final cars, while unsold current production is counted as inventory investment."},
{id:305,sourceGame:"nationalEngine",q:"GDP is 4800, C is 2900, I is 760, G is 900, and imports are 420. What are exports?",options:["660","240","1180","180"],a:0,tag:"gdp_components",type:"calculation",objective:"LO2.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"gdp_expenditure_calculation",secondarySkills:[],repairSkill:"gdp_expenditure_calculation",commonError:"solves_for_nx_but_not_exports",feedback:"4800 = 2900 + 760 + 900 + X - 420, so X = 660."},
{id:306,sourceGame:"nationalEngine",q:"An economy has C = 1400, I = 350, G = 500, exports = 220, and imports = 470. What is GDP?",options:["2000","2470","2940","1530"],a:0,tag:"gdp_components",type:"calculation",objective:"LO2.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"gdp_expenditure_calculation",secondarySkills:[],repairSkill:"gdp_expenditure_calculation",commonError:"adds_imports_instead_of_subtracting",feedback:"GDP = 1400 + 350 + 500 + 220 - 470 = 2000."},
{id:307,sourceGame:"nationalEngine",q:"Nominal GDP rises from 5000 to 5750 while real GDP rises from 5000 to 5400. Which statement is best?",options:["Output rose, and prices also rose","Only output rose","Only prices rose","Neither output nor prices changed"],a:0,tag:"real_nominal_gdp",type:"interpretation",objective:"LO2.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"real_vs_nominal_gdp",secondarySkills:["gdp_deflator_inflation"],repairSkill:"real_vs_nominal_gdp",commonError:"reads_nominal_growth_as_pure_output_growth",feedback:"Real GDP growth shows output rose, while nominal GDP rising faster than real GDP indicates price increases too."},
{id:308,sourceGame:"nationalEngine",q:"Nominal GDP is 8400 and real GDP is 7000. Last year’s deflator was 115. What is this year’s GDP-deflator inflation?",options:["4.3%","20.0%","5.0%","15.0%"],a:0,tag:"gdp_deflator",type:"calculation",objective:"LO2.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"gdp_deflator_inflation",secondarySkills:[],repairSkill:"gdp_deflator_inflation",commonError:"uses_deflator_level_as_inflation_rate",feedback:"This year’s deflator is 120. Inflation = (120 - 115)/115 × 100 ≈ 4.3%."},
{id:309,sourceGame:"nationalEngine",q:"A CPI basket costs 300 in the base year, 390 last year, and 420 this year. What is this year’s inflation rate?",options:["7.7%","40.0%","10.0%","30.0%"],a:0,tag:"cpi",type:"calculation",objective:"LO2.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"cpi_inflation_calculation",secondarySkills:[],repairSkill:"cpi_inflation_calculation",commonError:"compares_current_cost_to_base_cost_for_inflation",feedback:"CPI last year is 130 and this year is 140, so inflation is (140 - 130)/130 = 7.7%."},
{id:310,sourceGame:"nationalEngine",q:"An economy has 240 employed, 24 unemployed, and 96 not in the labor force. Ten unemployed workers find jobs. What is the new unemployment rate?",options:["5.3%","9.1%","6.7%","3.9%"],a:0,tag:"unemployment_rate",type:"calculation",objective:"LO2.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"labor_force_statistics_calculation",secondarySkills:["employment_status_classification"],repairSkill:"labor_force_statistics_calculation",commonError:"changes_labor_force_when_unemployed_find_jobs",feedback:"Employed becomes 250 and unemployed becomes 14, but labor force stays 264. The rate is 14/264 = 5.3%."},
{id:311,sourceGame:"nationalEngine",q:"An economy has 300 employed, 30 unemployed, and 70 out of the labor force. Twenty out-of-labor-force adults begin searching. What is the new unemployment rate?",options:["14.3%","9.1%","12.5%","16.7%"],a:0,tag:"labor_force",type:"calculation",objective:"LO2.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"labor_force_statistics_calculation",secondarySkills:["employment_status_classification"],repairSkill:"labor_force_statistics_calculation",commonError:"adds_searchers_to_population_but_not_unemployment",feedback:"Unemployed becomes 50 and labor force becomes 350. The unemployment rate is 50/350 = 14.3%."},
{id:312,sourceGame:"nationalEngine",q:"A basket has 4 tacos and 2 pizzas. Base prices are $3 and $8. Current prices are $5 and $10. What is the CPI?",options:["142.9","128.6","151.3","71.4"],a:0,tag:"cpi",type:"calculation",objective:"LO2.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"cpi_inflation_calculation",secondarySkills:[],repairSkill:"cpi_inflation_calculation",commonError:"uses_average_prices_instead_of_basket_costs",feedback:"Base basket cost = 4×3 + 2×8 = 28. Current basket cost = 4×5 + 2×10 = 40. CPI = 100×40/28 = 142.9."},
{id:313,sourceGame:"nationalEngine",q:"A data table shows nominal GDP rising 12% and real GDP rising 3%. What is the best reading?",options:["Most of the nominal increase reflects higher prices","All of the nominal increase reflects output growth","Real GDP must be overstated by CPI bias","Imports must have fallen by 9%"],a:0,tag:"real_nominal_gdp",type:"interpretation",objective:"LO2.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"real_vs_nominal_gdp",secondarySkills:["gdp_deflator_inflation"],repairSkill:"real_vs_nominal_gdp",commonError:"confuses_nominal_growth_with_real_growth",feedback:"When nominal GDP grows much faster than real GDP, much of the difference reflects price increases."},
{id:314,sourceGame:"nationalEngine",q:"A production function has Y = A K^0.5 L^0.3. What returns to scale does it show?",options:["Decreasing returns to scale","Constant returns to scale","Increasing returns to scale","No input relationship"],a:0,tag:"returns_to_scale",type:"calculation",objective:"LO3.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"returns_to_scale_classification",secondarySkills:[],repairSkill:"returns_to_scale_classification",commonError:"does_not_add_exponents",feedback:"The exponents add to 0.8, so doubling inputs less than doubles output."},
{id:315,sourceGame:"nationalEngine",q:"A production function has Y = A K^0.6 L^0.6. If both inputs double, what happens to output?",options:["It more than doubles","It exactly doubles","It less than doubles","It stays fixed"],a:0,tag:"returns_to_scale",type:"calculation",objective:"LO3.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"returns_to_scale_classification",secondarySkills:[],repairSkill:"returns_to_scale_classification",commonError:"misses_exponents_sum_above_one",feedback:"The exponents add to 1.2, so doubling inputs more than doubles output."},
{id:316,sourceGame:"nationalEngine",q:"In the Chapter 3 model, output is fixed by production, while investment depends on the real interest rate. Why does r matter?",options:["It adjusts demand by changing investment until spending matches fixed output","It directly changes technology in the production function","It sets the CPI basket used for inflation","It determines whether workers are counted as unemployed"],a:0,tag:"production",type:"integration",objective:"LO3.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"production_function_output",secondarySkills:["investment_interest_rate_relationship"],repairSkill:"production_function_output",commonError:"misses_role_of_interest_rate_in_fixed_output_model",feedback:"With output fixed, the real interest rate adjusts investment demand so aggregate demand matches output."},
{id:317,sourceGame:"nationalEngine",q:"A technology improvement raises output with the same K and L. In the Chapter 3 model, what else likely changes directly?",options:["Marginal products of both labor and capital rise","The CPI basket becomes fixed","The unemployment rate must become zero","Public saving must become negative"],a:0,tag:"production_function",type:"application",objective:"LO3.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"production_function_output",secondarySkills:["diminishing_marginal_product"],repairSkill:"production_function_output",commonError:"misses_productivity_effect_on_marginal_products",feedback:"Better technology raises output from given inputs and tends to raise the marginal products of labor and capital."},
{id:318,sourceGame:"nationalEngine",q:"A model has fixed K, fixed L, and fixed A. A tax cut raises consumption demand. What does the Chapter 3 model predict about output?",options:["Output stays fixed while saving and investment adjust","Output rises by the full tax cut","Output falls because consumption rises","Output equals nominal GDP by definition"],a:0,tag:"production",type:"trap",objective:"LO3.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"production_function_output",secondarySkills:["fiscal_policy_crowding_out"],repairSkill:"production_function_output",commonError:"imports_keynesian_multiplier_into_fixed_output_model",feedback:"In this model, output is fixed by K, L, and A; the tax cut changes saving and investment pressure."},
{id:319,sourceGame:"nationalEngine",q:"If total output is fixed and government purchases increase, which component must be squeezed through the loanable funds channel?",options:["Investment","Technology","Total output","Labor force size"],a:0,tag:"goods_market_equilibrium",type:"integration",objective:"LO3.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"production_function_output",secondarySkills:["fiscal_policy_crowding_out"],repairSkill:"production_function_output",commonError:"misses_crowding_out_under_fixed_output",feedback:"With output fixed, higher government purchases reduce saving and crowd out investment through a higher real interest rate."},
{id:320,sourceGame:"nationalEngine",q:"A student says, 'Higher G always means higher Y in Chapter 3.' What is the cleanest correction?",options:["Y is supply-determined here; higher G mainly reallocates demand","Y is CPI-determined here; higher G lowers prices","Y is unemployment-determined here; higher G changes f","Y is import-determined here; higher G changes NX only"],a:0,tag:"production",type:"trap",objective:"LO3.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"production_function_output",secondarySkills:["saving_investment_equilibrium"],repairSkill:"production_function_output",commonError:"misreads_chapter_3_as_short_run_demand_model",feedback:"Chapter 3 fixes output from production inputs, so fiscal changes shift demand composition rather than total output."},
{id:321,sourceGame:"nationalEngine",q:"A firm’s MPL schedule is 18, 14, 11, 7, 3. If output price is $5 and the nominal wage is $50, how many workers are hired?",options:["3","2","4","5"],a:0,tag:"labor_demand",type:"calculation",objective:"LO3.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"uses_nominal_wage_without_dividing_by_price",feedback:"The real wage is 50/5 = 10. The first three workers have MPL at least 10; the fourth has 7."},
{id:322,sourceGame:"nationalEngine",q:"A firm’s output rises from 0 to 20 to 36 to 48 to 56. If W/P = 10, how many workers should it hire?",options:["3","2","4","5"],a:0,tag:"labor_demand",type:"calculation",objective:"LO3.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"total_product_to_marginal_product",secondarySkills:["labor_demand_mpl_real_wage"],repairSkill:"total_product_to_marginal_product",commonError:"uses_total_product_instead_of_mpl",feedback:"MPL values are 20, 16, 12, and 8. The firm hires three workers, stopping before MPL falls below 10."},
{id:323,sourceGame:"nationalEngine",q:"If the nominal wage rises 20% and the output price rises 25%, what happens to the real wage?",options:["It falls","It rises","It is unchanged","It becomes zero"],a:0,tag:"factor_prices",type:"calculation",objective:"LO3.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"looks_only_at_nominal_wage_growth",feedback:"The output price rose faster than the nominal wage, so the wage measured in output falls."},
{id:324,sourceGame:"nationalEngine",q:"Refer to the marginal product graph. A fall in the real wage should move the firm toward what outcome?",options:["More labor hired along the MPL curve","Less labor hired along the MPL curve","A leftward shift of the MPL curve","A lower total product at every labor level"],a:0,tag:"labor_demand",type:"graph_interpretation",objective:"LO3.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"gets_real_wage_labor_demand_backward",feedback:"A lower real wage makes additional lower-MPL workers profitable, so labor demanded rises along the MPL curve.",image:"marginalproduct.webp"},
{id:325,sourceGame:"nationalEngine",q:"If labor supply expands sharply while capital is fixed, which factor-price result is most consistent?",options:["Real wages fall and MPK rises","Real wages rise and MPK falls","Both real wages and MPK fall","Both real wages and MPK become zero"],a:0,tag:"factor_markets",type:"integration",objective:"LO3.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"diminishing_marginal_product",secondarySkills:["factor_income_distribution"],repairSkill:"diminishing_marginal_product",commonError:"misses_cross_effect_on_capital_productivity",feedback:"More labor lowers MPL and real wages, while making capital more productive, raising MPK."},
{id:326,sourceGame:"nationalEngine",q:"If capital supply increases while labor is fixed, what happens to MPK and MPL in the Cobb-Douglas logic?",options:["MPK falls and MPL rises","MPK rises and MPL falls","Both MPK and MPL fall","Both MPK and MPL rise"],a:0,tag:"factor_prices",type:"application",objective:"LO3.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"diminishing_marginal_product",secondarySkills:["factor_income_distribution"],repairSkill:"diminishing_marginal_product",commonError:"misses_cross_marginal_product_effects",feedback:"More capital lowers the marginal product of capital but raises the marginal product of labor."},
{id:327,sourceGame:"nationalEngine",q:"A machine shortage reduces capital while labor is unchanged. Which statement is strongest?",options:["MPK rises and workers may become less productive","MPK falls and workers become more productive","MPL rises because capital is scarce","Factor prices are unrelated to marginal products"],a:0,tag:"factor_prices",type:"application",objective:"LO3.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"diminishing_marginal_product",secondarySkills:["labor_demand_mpl_real_wage"],repairSkill:"diminishing_marginal_product",commonError:"misses_capital_labor_complementarity",feedback:"Scarcer capital raises MPK, but with less capital per worker, labor’s marginal product can fall."},
{id:328,sourceGame:"nationalEngine",q:"A firm hires a worker with MPL = 9 when W/P = 11. What should happen to profit?",options:["It falls because the worker adds less output than the real wage cost","It rises because all positive MPL workers are profitable","It is unchanged because nominal wages do not matter","It rises only if CPI falls"],a:0,tag:"labor_demand",type:"trap",objective:"LO3.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"labor_demand_mpl_real_wage",secondarySkills:[],repairSkill:"labor_demand_mpl_real_wage",commonError:"hires_positive_mpl_even_when_below_real_wage",feedback:"A worker must produce at least the real wage in extra output. MPL = 9 is below W/P = 11, so profit falls."},
{id:329,sourceGame:"nationalEngine",q:"Refer to the total product graph. If the curve gets flatter but still rises, which interpretation is best?",options:["MPL is positive but falling","MPL is negative and falling","Total output is falling","The real wage must be zero"],a:0,tag:"marginal_product",type:"graph_interpretation",objective:"LO3.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"total_product_to_marginal_product",secondarySkills:["diminishing_marginal_product"],repairSkill:"total_product_to_marginal_product",commonError:"confuses_falling_mpl_with_negative_mpl",feedback:"A rising but flattening total product curve means each extra worker still adds output, but by less than before.",image:"totalproduct.webp"},
{id:330,sourceGame:"nationalEngine",q:"If alpha = 0.35 and total income is 5000, what are capital and labor income?",options:["Capital 1750; labor 3250","Capital 3250; labor 1750","Capital 3500; labor 1500","Capital 1500; labor 3500"],a:0,tag:"factor_shares",type:"calculation",objective:"LO3.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:[],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"reverses_capital_and_labor_shares",feedback:"Capital income = 0.35×5000 = 1750; labor income = 0.65×5000 = 3250."},
{id:331,sourceGame:"nationalEngine",q:"If alpha = 0.4, capital rises by 5%, and labor rises by 10%, what is approximate output growth?",options:["8%","6%","10%","15%"],a:0,tag:"cobb_douglas",type:"calculation",objective:"LO3.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:[],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"adds_input_growth_without_weights",feedback:"Output growth ≈ 0.4×5% + 0.6×10% = 2% + 6% = 8%."},
{id:332,sourceGame:"nationalEngine",q:"If alpha = 0.25, technology rises by 2%, capital rises by 4%, and labor rises by 8%, what is approximate output growth?",options:["9%","7%","14%","6%"],a:0,tag:"cobb_douglas",type:"calculation",objective:"LO3.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"cobb_douglas_factor_share_calculation",secondarySkills:["production_function_output"],repairSkill:"cobb_douglas_factor_share_calculation",commonError:"omits_technology_or_misweights_inputs",feedback:"Growth ≈ 2% + 0.25×4% + 0.75×8% = 2% + 1% + 6% = 9%."},
{id:333,sourceGame:"nationalEngine",q:"A Cobb-Douglas model predicts stable factor shares, but labor’s share falls. Which explanation fits the caveat best?",options:["Technology and bargaining shifts can change real-world shares","The model says labor’s share must be zero","The CPI basket determines factor shares","The unemployment rate directly sets alpha"],a:0,tag:"income_distribution",type:"application",objective:"LO3.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"factor_income_distribution",secondarySkills:["cobb_douglas_factor_share_calculation"],repairSkill:"factor_income_distribution",commonError:"treats_benchmark_model_as_literal_fact",feedback:"Cobb-Douglas is a benchmark; real factor shares can move when technology, union power, or globalization changes."},
{id:334,sourceGame:"nationalEngine",q:"If labor is paid less than its marginal product because bargaining power weakens, what assumption is being strained?",options:["Factors are paid their marginal products","The CPI uses a fixed basket","The labor force equals employed plus unemployed","Imports are subtracted from GDP"],a:0,tag:"income_distribution",type:"application",objective:"LO3.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"factor_income_distribution",secondarySkills:[],repairSkill:"factor_income_distribution",commonError:"misses_distribution_assumption",feedback:"The neoclassical distribution result depends on factors receiving their marginal products in competitive markets."},
{id:335,sourceGame:"nationalEngine",q:"If capital owners also own the firm, why can accounting profit exceed economic profit?",options:["It includes the return to owner-supplied capital","It excludes depreciation from every account","It counts transfer payments as profit","It measures CPI overstatement"],a:0,tag:"income_distribution",type:"interpretation",objective:"LO3.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"factor_income_distribution",secondarySkills:[],repairSkill:"factor_income_distribution",commonError:"confuses_accounting_profit_and_capital_return",feedback:"Accounting profit includes both economic profit and the return to capital owned by the firm’s owners."},
{id:336,sourceGame:"nationalEngine",q:"If output is exhausted by payments to labor and capital under constant returns, what is the implication?",options:["Economic profit is zero in the ideal model","Accounting profit must be zero in all records","Labor receives all income","Capital receives all income"],a:0,tag:"income_distribution",type:"interpretation",objective:"LO3.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"factor_income_distribution",secondarySkills:["returns_to_scale_classification"],repairSkill:"factor_income_distribution",commonError:"misses_output_exhaustion_logic",feedback:"With constant returns and factors paid marginal products, total output is exhausted by factor payments, leaving zero economic profit."},
{id:337,sourceGame:"nationalEngine",q:"A country’s capital share rises while average labor productivity also rises. Which policy concern follows most directly?",options:["Productivity gains may not translate fully into labor income","Real GDP must be falling","The GDP deflator must equal CPI","The job finding rate must be zero"],a:0,tag:"income_distribution",type:"application",objective:"LO3.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"factor_income_distribution",secondarySkills:[],repairSkill:"factor_income_distribution",commonError:"assumes_productivity_growth_guarantees_wage_share_growth",feedback:"If capital’s share rises, labor may not capture productivity gains as wages to the same degree."},
{id:338,sourceGame:"nationalEngine",q:"If C = 300 + 0.7(Y - T), Y = 5000, and T = 1200, what is consumption and private saving?",options:["C = 2960; private saving = 840","C = 3800; private saving = 0","C = 2960; private saving = 2040","C = 3500; private saving = 300"],a:0,tag:"consumption_function",type:"calculation",objective:"LO3.4",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"consumption_function_calculation",secondarySkills:["saving_identity_calculation"],repairSkill:"consumption_function_calculation",commonError:"forgets_disposable_income_or_saving_identity",feedback:"Disposable income = 3800. C = 300 + 0.7×3800 = 2960. Private saving = 3800 - 2960 = 840."},
{id:339,sourceGame:"nationalEngine",q:"Taxes rise by 200, MPC = 0.75, and output is fixed. What is the direct effect on consumption and private saving?",options:["Consumption falls 150; private saving falls 50","Consumption falls 200; private saving unchanged","Consumption falls 50; private saving falls 150","Consumption rises 150; private saving rises 50"],a:0,tag:"consumption",type:"calculation",objective:"LO3.4",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"mpc_disposable_income",secondarySkills:["saving_identity_calculation"],repairSkill:"mpc_disposable_income",commonError:"confuses_consumption_change_with_saving_change",feedback:"Disposable income falls 200. Consumption falls 150, while private saving falls by the remaining 50."},
{id:340,sourceGame:"nationalEngine",q:"Refer to the consumption function graph. Which pair correctly separates movement from shift?",options:["Higher Y-T moves along; higher wealth shifts up","Higher wealth moves along; higher Y-T shifts up","Higher taxes always shift up; higher wealth moves down","Higher CPI always moves along; higher income shifts down"],a:0,tag:"consumption_function",type:"graph_interpretation",objective:"LO3.4",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"consumption_movement_vs_shift",secondarySkills:[],repairSkill:"consumption_movement_vs_shift",commonError:"reverses_movement_and_shift",feedback:"A change in disposable income moves along the function; a wealth change shifts consumption at each income level.",image:"consumptionfunction.webp"},
{id:341,sourceGame:"nationalEngine",q:"If nominal interest is 12%, inflation is 5%, and I = 3000 - 150r, what is investment?",options:["1950","1200","2250","2550"],a:0,tag:"investment",type:"calculation",objective:"LO3.4",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"real_interest_investment_calculation",secondarySkills:[],repairSkill:"real_interest_investment_calculation",commonError:"uses_nominal_rate_or_adds_inflation",feedback:"Real interest rate is 7. Investment = 3000 - 150×7 = 1950."},
{id:342,sourceGame:"nationalEngine",q:"Investment is I = 2500 - 200r. Inflation rises from 2% to 5% while the nominal rate stays 9%. What happens to investment?",options:["It rises by 600","It falls by 600","It rises by 300","It does not change"],a:0,tag:"investment",type:"calculation",objective:"LO3.4",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"real_interest_investment_calculation",secondarySkills:["investment_interest_rate_relationship"],repairSkill:"real_interest_investment_calculation",commonError:"misses_real_rate_fall_when_inflation_rises",feedback:"Real r falls from 7 to 4. Investment rises from 1100 to 1700, an increase of 600."},
{id:343,sourceGame:"nationalEngine",q:"Refer to the investment function graph. Expected profits rise while the real interest rate rises. What is the careful answer?",options:["Investment effect is ambiguous without shift size and rate change","Investment must rise because profits rose","Investment must fall because r rose","Investment cannot change because both forces cancel exactly"],a:0,tag:"investment_function",type:"graph_interpretation",objective:"LO3.4",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"investment_function_movement_vs_shift",secondarySkills:[],repairSkill:"investment_function_movement_vs_shift",commonError:"ignores_offsetting_shift_and_movement",feedback:"Higher expected profits shift investment right, but a higher real interest rate moves up the curve; the net effect depends on magnitudes.",image:"investmentfunction.webp"},
{id:344,sourceGame:"nationalEngine",q:"Refer to the investment function graph. A move from a low-r point on I1 to a high-r point on I2 means what likely happened?",options:["Investment demand rose while the real interest rate also rose","Investment demand fell while the real interest rate fell","Only the real interest rate changed","Only the CPI basket changed"],a:0,tag:"investment_function",type:"graph_interpretation",objective:"LO3.4",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"investment_function_movement_vs_shift",secondarySkills:[],repairSkill:"investment_function_movement_vs_shift",commonError:"sees_only_shift_or_only_movement",feedback:"Moving from I1 to I2 indicates higher investment demand, while moving to a higher-r point means the real interest rate rose.",image:"investmentfunction.webp"},
{id:345,sourceGame:"nationalEngine",q:"A tax credit raises expected capital returns, but the loanable funds market later raises r. What is the best sequence?",options:["Investment demand shifts right, then higher r limits the quantity response","Saving shifts left, then lower r raises investment","Consumption shifts down, then CPI lowers investment","Labor supply rises, then MPL lowers investment"],a:0,tag:"investment_function",type:"integration",objective:"LO3.4",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"investment_function_movement_vs_shift",secondarySkills:["investment_demand_vs_saving_shift"],repairSkill:"investment_function_movement_vs_shift",commonError:"misses_market_feedback_on_investment_demand_shift",feedback:"The tax credit shifts investment demand right, but the resulting higher real interest rate can limit the increase in equilibrium investment."},
{id:346,sourceGame:"nationalEngine",q:"Suppose C = 100 + 0.8(Y - T), Y is fixed at 2000, and T falls by 100. What happens to consumption and national saving if G is fixed?",options:["Consumption rises 80; national saving falls 80","Consumption rises 100; national saving stays fixed","Consumption rises 20; national saving falls 20","Consumption falls 80; national saving rises 80"],a:0,tag:"consumption",type:"integration",objective:"LO3.4",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"mpc_disposable_income",secondarySkills:["saving_identity_calculation"],repairSkill:"mpc_disposable_income",commonError:"looks_only_at_private_saving_after_tax_cut",feedback:"The tax cut raises consumption by 80. With Y and G fixed, higher C lowers national saving by 80."},
{id:347,sourceGame:"nationalEngine",q:"If a wealth boom shifts consumption upward while Y and G are fixed, what must happen to national saving?",options:["It falls because consumption rises","It rises because wealth rises","It stays fixed because Y is fixed","It becomes equal to investment demand"],a:0,tag:"consumption_function",type:"application",objective:"LO3.4",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"consumption_movement_vs_shift",secondarySkills:["saving_identity_calculation"],repairSkill:"consumption_movement_vs_shift",commonError:"confuses_household_wealth_with_national_saving",feedback:"National saving is Y - C - G. If C rises while Y and G are fixed, national saving falls."},
{id:348,sourceGame:"nationalEngine",q:"If households save more at every income level, which graph changes are most consistent?",options:["Consumption shifts down and saving shifts right","Consumption shifts up and saving shifts left","Investment shifts left and CPI shifts up","Labor demand shifts right and MPL shifts down"],a:0,tag:"consumption_function",type:"integration",objective:"LO3.4",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"consumption_movement_vs_shift",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"consumption_movement_vs_shift",commonError:"misses_consumption_saving_link",feedback:"More saving at each income means less consumption and higher national saving, shifting saving right in loanable funds."},
{id:349,sourceGame:"nationalEngine",q:"If real r falls but investment does not rise much, which explanation fits the investment function best?",options:["Investment demand may have shifted left at the same time","The law of investment demand is impossible","Lower r always shifts investment demand left","CPI bias cancels investment by definition"],a:0,tag:"investment_function",type:"trap",objective:"LO3.4",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"investment_function_movement_vs_shift",secondarySkills:[],repairSkill:"investment_function_movement_vs_shift",commonError:"ignores_simultaneous_curve_shift",feedback:"A lower r raises investment along a curve, but a leftward shift in investment demand can offset that movement."},
{id:350,sourceGame:"nationalEngine",q:"Y = 6000, C = 3900, G = 1400, and T = 1200. What are national saving, private saving, and public saving?",options:["S = 700; private = 900; public = -200","S = 900; private = 700; public = 200","S = 2100; private = 900; public = 1200","S = -200; private = 700; public = 900"],a:0,tag:"national_saving",type:"calculation",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"saving_identity_calculation",secondarySkills:[],repairSkill:"saving_identity_calculation",commonError:"mixes_up_private_public_national_saving",feedback:"S = Y - C - G = 700. Private saving = Y - T - C = 900. Public saving = T - G = -200."},
{id:351,sourceGame:"nationalEngine",q:"A tax increase of 300 occurs with MPC = 0.6, holding Y and G fixed. What happens to national saving?",options:["It rises by 180","It rises by 120","It falls by 180","It falls by 300"],a:0,tag:"national_saving",type:"calculation",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"saving_identity_calculation",secondarySkills:["mpc_disposable_income"],repairSkill:"saving_identity_calculation",commonError:"looks_only_at_public_saving",feedback:"Consumption falls by 180. Since S = Y - C - G, national saving rises by 180."},
{id:352,sourceGame:"nationalEngine",q:"A tax cut of 500 occurs with MPC = 0.8, holding Y and G fixed. What happens to national saving?",options:["It falls by 400","It falls by 100","It rises by 100","It rises by 500"],a:0,tag:"national_saving",type:"calculation",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"saving_identity_calculation",secondarySkills:["mpc_disposable_income"],repairSkill:"saving_identity_calculation",commonError:"focuses_on_private_saving_only",feedback:"Consumption rises by 400. Since S = Y - C - G, national saving falls by 400."},
{id:353,sourceGame:"nationalEngine",q:"Refer to the loanable funds graph. If public saving falls, which point movement is most consistent?",options:["From higher saving/lower r toward lower saving/higher r","From lower saving/higher r toward higher saving/lower r","From I1 to I2 with saving unchanged","From lower r to lower investment on the same saving curve"],a:0,tag:"loanable_funds",type:"graph_interpretation",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"loanable_funds_graph_shifts",secondarySkills:["fiscal_policy_crowding_out"],repairSkill:"loanable_funds_graph_shifts",commonError:"gets_saving_shift_direction_backward",feedback:"Lower public saving reduces national saving, shifting saving left, raising r, and lowering investment.",image:"loanablefunds.webp"},
{id:354,sourceGame:"nationalEngine",q:"Refer to the loanable funds graph. Investment demand shifts right and saving shifts left at the same time. What is unambiguous?",options:["The real interest rate rises","Investment definitely rises","Investment definitely falls","The real interest rate falls"],a:0,tag:"loanable_funds",type:"graph_interpretation",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"loanable_funds_graph_shifts",secondarySkills:["investment_demand_vs_saving_shift"],repairSkill:"loanable_funds_graph_shifts",commonError:"claims_quantity_effect_when_ambiguous",feedback:"Higher investment demand raises r, and lower saving also raises r. The quantity of investment depends on relative shifts.",image:"loanablefunds.webp"},
{id:355,sourceGame:"nationalEngine",q:"Refer to the loanable funds graph. Saving shifts right and investment demand shifts right at the same time. What is unambiguous?",options:["Investment rises","The real interest rate rises","The real interest rate falls","Investment falls"],a:0,tag:"loanable_funds",type:"graph_interpretation",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"loanable_funds_graph_shifts",secondarySkills:["investment_demand_vs_saving_shift"],repairSkill:"loanable_funds_graph_shifts",commonError:"claims_interest_rate_effect_when_ambiguous",feedback:"Both higher saving and higher investment demand raise equilibrium investment, but their effects on r move in opposite directions.",image:"loanablefunds.webp"},
{id:356,sourceGame:"nationalEngine",q:"Refer to the loanable funds graph. Saving shifts right while investment demand shifts left. What is unambiguous?",options:["The real interest rate falls","Investment rises","Investment falls","The real interest rate rises"],a:0,tag:"loanable_funds",type:"graph_interpretation",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"loanable_funds_graph_shifts",secondarySkills:["investment_demand_vs_saving_shift"],repairSkill:"loanable_funds_graph_shifts",commonError:"claims_quantity_effect_when_ambiguous",feedback:"Higher saving lowers r, and lower investment demand also lowers r. Investment quantity depends on relative shifts.",image:"loanablefunds.webp"},
{id:357,sourceGame:"nationalEngine",q:"A policy raises government purchases but also raises taxes by the same amount. With MPC below 1, what happens to national saving?",options:["It falls because G rises more than C falls","It rises because taxes fully offset spending","It is unchanged because the budget is balanced","It falls only if imports rise"],a:0,tag:"fiscal_policy",type:"integration",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"fiscal_policy_crowding_out",secondarySkills:["mpc_disposable_income"],repairSkill:"fiscal_policy_crowding_out",commonError:"assumes_balanced_budget_means_no_saving_effect",feedback:"Higher G lowers saving by the full increase, while higher T lowers C only by MPC times the increase, so national saving falls."},
{id:358,sourceGame:"nationalEngine",q:"A policy cuts taxes and investment demand rises because firms expect stronger sales. What happens to r in loanable funds?",options:["It rises from lower saving and higher investment demand","It falls from lower saving and higher investment demand","It stays fixed because both curves shift right","It becomes equal to the CPI inflation rate"],a:0,tag:"loanable_funds",type:"integration",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"fiscal_policy_crowding_out",secondarySkills:["investment_demand_vs_saving_shift"],repairSkill:"fiscal_policy_crowding_out",commonError:"misses_same_direction_pressure_on_interest_rate",feedback:"A tax cut lowers national saving, pushing r up, and higher investment demand also pushes r up."},
{id:359,sourceGame:"nationalEngine",q:"If investment demand rises but the government wants to prevent r from rising, what policy direction best fits the loanable funds model?",options:["Increase national saving","Reduce job finding","Raise consumption at every income","Lower public saving"],a:0,tag:"loanable_funds",type:"policy",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"investment_demand_vs_saving_shift",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"investment_demand_vs_saving_shift",commonError:"chooses_policy_that_reduces_saving",feedback:"Higher national saving shifts saving right, offsetting upward pressure on r from stronger investment demand."},
{id:360,sourceGame:"nationalEngine",q:"A deficit raises r and lowers investment. Why does this matter in the Chapter 3 long-run model?",options:["Lower investment can reduce future capital accumulation","Lower investment raises current CPI by definition","Lower investment increases current labor force size","Lower investment raises current output immediately"],a:0,tag:"crowding_out",type:"policy",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"fiscal_policy_crowding_out",secondarySkills:[],repairSkill:"fiscal_policy_crowding_out",commonError:"misses_long_run_capital_accumulation_channel",feedback:"Crowding out matters because less investment today can mean less capital accumulation and lower future productive capacity."},
{id:361,sourceGame:"nationalEngine",q:"If national saving is fixed at 800 and investment demand is I = 1200 - 50r, what is equilibrium r?",options:["8","6","10","4"],a:0,tag:"loanable_funds",type:"calculation",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"saving_investment_equilibrium",secondarySkills:["real_interest_investment_calculation"],repairSkill:"saving_investment_equilibrium",commonError:"does_not_set_saving_equal_to_investment",feedback:"Set 800 = 1200 - 50r. Then 50r = 400, so r = 8."},
{id:362,sourceGame:"nationalEngine",q:"National saving rises from 700 to 900. Investment demand is I = 1300 - 100r. What happens to r?",options:["It falls from 6 to 4","It rises from 4 to 6","It falls from 7 to 9","It stays at 6"],a:0,tag:"loanable_funds",type:"calculation",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"saving_investment_equilibrium",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"saving_investment_equilibrium",commonError:"gets_saving_interest_rate_effect_backward",feedback:"At S=700, r=6. At S=900, r=4. Higher saving lowers r."},
{id:363,sourceGame:"nationalEngine",q:"Refer to the loanable funds graph. If saving is vertical, why does a rightward investment demand shift mainly raise r instead of investment?",options:["Saving fixes the quantity of funds available","Investment demand fixes the price level","The CPI basket fixes investment","Labor force participation fixes r"],a:0,tag:"loanable_funds",type:"graph_interpretation",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"investment_demand_vs_saving_shift",secondarySkills:[],repairSkill:"investment_demand_vs_saving_shift",commonError:"misses_vertical_saving_constraint",feedback:"When saving is vertical and fixed, stronger investment demand bids up r instead of greatly raising investment.",image:"loanablefunds.webp"},
{id:364,sourceGame:"nationalEngine",q:"A fiscal hawk argues that cutting G raises investment. In the Chapter 3 model, what is the chain?",options:["G falls, public saving rises, national saving rises, r falls, investment rises","G falls, public saving falls, r rises, investment falls","G falls, consumption rises automatically, investment falls","G falls, GDP rises immediately, investment is unchanged"],a:0,tag:"fiscal_policy",type:"policy",objective:"LO3.5",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"fiscal_policy_crowding_out",secondarySkills:["loanable_funds_graph_shifts"],repairSkill:"fiscal_policy_crowding_out",commonError:"gets_fiscal_saving_chain_backward",feedback:"Lower government purchases raise public and national saving, lower the real interest rate, and increase investment."},
{id:365,sourceGame:"nationalEngine",q:"Actual unemployment is 6.5%, frictional is 1.8%, structural is 3.2%. What is cyclical unemployment?",options:["1.5%","5.0%","3.3%","6.5%"],a:0,tag:"natural_rate",type:"calculation",objective:"LO7.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"natural_rate_definition",secondarySkills:["frictional_vs_other_unemployment"],repairSkill:"natural_rate_definition",commonError:"includes_natural_rate_as_cyclical",feedback:"Natural unemployment is 1.8 + 3.2 = 5.0%. Cyclical unemployment is 6.5 - 5.0 = 1.5%."},
{id:366,sourceGame:"nationalEngine",q:"A policy lowers structural unemployment but leaves frictional unemployment unchanged. What happens to the natural rate?",options:["It falls","It rises","It becomes zero","It becomes cyclical unemployment"],a:0,tag:"natural_rate",type:"application",objective:"LO7.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"natural_rate_definition",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"natural_rate_definition",commonError:"thinks_frictional_only_defines_natural_rate",feedback:"The natural rate includes frictional plus structural unemployment, so lowering structural unemployment lowers the natural rate."},
{id:367,sourceGame:"nationalEngine",q:"A central bank boosts demand and unemployment temporarily falls below the natural rate. What should an advisor avoid claiming?",options:["That the natural rate has permanently fallen","That actual unemployment can move below natural temporarily","That cyclical unemployment can be negative","That labor-market frictions still exist"],a:0,tag:"natural_rate",type:"trap",objective:"LO7.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"natural_rate_definition",secondarySkills:[],repairSkill:"natural_rate_definition",commonError:"confuses_actual_unemployment_with_natural_rate",feedback:"Actual unemployment can fall below the natural rate temporarily, but that does not prove the natural rate permanently changed."},
{id:368,sourceGame:"nationalEngine",q:"A country reduces wage rigidity and improves matching. Which unemployment components are targeted?",options:["Structural and frictional","Cyclical and nominal","GDP and CPI","Investment and saving"],a:0,tag:"natural_rate",type:"policy",objective:"LO7.1",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"natural_rate_definition",secondarySkills:["frictional_vs_other_unemployment"],repairSkill:"natural_rate_definition",commonError:"misses_components_of_natural_rate",feedback:"Wage rigidity is structural; matching problems are frictional. Both are part of the natural rate."},
{id:369,sourceGame:"nationalEngine",q:"If s = 0.04 and f = 0.16, what is steady-state unemployment?",options:["20%","4%","16%","25%"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"steady_state_unemployment_calculation",secondarySkills:[],repairSkill:"steady_state_unemployment_calculation",commonError:"uses_s_or_f_as_unemployment_rate",feedback:"u = s/(s+f) = 0.04/(0.20) = 20%."},
{id:370,sourceGame:"nationalEngine",q:"If steady-state unemployment is 12% and f = 0.44, what is s closest to?",options:["0.06","0.12","0.44","0.50"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"steady_state_unemployment_calculation",secondarySkills:[],repairSkill:"steady_state_unemployment_calculation",commonError:"does_not_solve_for_separation_rate",feedback:"s = uf/(1-u) = 0.12×0.44/0.88 = 0.06."},
{id:371,sourceGame:"nationalEngine",q:"If s rises from 0.02 to 0.04 and f rises from 0.18 to 0.36, what happens to steady-state unemployment?",options:["It stays at 10%","It rises to 20%","It falls to 5%","It becomes 40%"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"job_finding_job_separation_logic",secondarySkills:["steady_state_unemployment_calculation"],repairSkill:"job_finding_job_separation_logic",commonError:"focuses_on_one_flow_rate_only",feedback:"Initial u = 0.02/0.20 = 10%. New u = 0.04/0.40 = 10%. Both rates doubled."},
{id:372,sourceGame:"nationalEngine",q:"A policy reduces s from 0.06 to 0.03 while f stays at 0.27. What happens to steady-state unemployment?",options:["It falls from about 18% to 10%","It rises from 10% to about 18%","It stays at 27%","It becomes 3%"],a:0,tag:"steady_state_unemployment",type:"calculation",objective:"LO7.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"steady_state_unemployment_calculation",secondarySkills:["job_finding_job_separation_logic"],repairSkill:"steady_state_unemployment_calculation",commonError:"gets_separation_policy_effect_backward",feedback:"Initial u = 0.06/0.33 ≈ 18%. New u = 0.03/0.30 = 10%."},
{id:373,sourceGame:"nationalEngine",q:"At steady state, sE = fU. If separations exceed findings for a period, what happens before a new steady state?",options:["Unemployment rises","Unemployment falls","Labor force becomes zero","Inflation becomes negative"],a:0,tag:"steady_state_unemployment",type:"interpretation",objective:"LO7.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"misreads_flow_imbalance",feedback:"If more workers enter unemployment than leave it, unemployment rises."},
{id:374,sourceGame:"nationalEngine",q:"If f = 0.20, what is the average unemployment spell, and what happens if f doubles?",options:["5 months; it falls to 2.5 months","20 months; it falls to 10 months","5 months; it rises to 10 months","2 months; it falls to 1 month"],a:0,tag:"job_finding",type:"calculation",objective:"LO7.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"steady_state_unemployment_calculation",secondarySkills:[],repairSkill:"steady_state_unemployment_calculation",commonError:"uses_f_as_duration_not_inverse",feedback:"Average unemployment spell is 1/f = 5 months. If f doubles to 0.40, duration falls to 2.5 months."},
{id:375,sourceGame:"nationalEngine",q:"If s = 0.025, what is the average employment spell, and what happens if s rises to 0.05?",options:["40 months; it falls to 20 months","25 months; it rises to 50 months","4 months; it falls to 2 months","20 months; it rises to 40 months"],a:0,tag:"job_separation",type:"calculation",objective:"LO7.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"steady_state_unemployment_calculation",secondarySkills:[],repairSkill:"steady_state_unemployment_calculation",commonError:"uses_s_as_spell_length",feedback:"Average employment spell is 1/s = 40 months. If s rises to 0.05, it falls to 20 months."},
{id:376,sourceGame:"nationalEngine",q:"A policy raises f but also raises s. What is the careful steady-state conclusion?",options:["The effect on unemployment is ambiguous without magnitudes","Unemployment must fall because f rose","Unemployment must rise because s rose","Unemployment must remain unchanged"],a:0,tag:"steady_state_unemployment",type:"trap",objective:"LO7.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"focuses_on_one_rate_in_two_rate_model",feedback:"Higher f lowers unemployment, while higher s raises it; the net effect depends on the size of each change."},
{id:377,sourceGame:"nationalEngine",q:"If u = s/(s+f), which policy pair most directly lowers u?",options:["Lower s and raise f","Raise s and lower f","Raise both s and f equally","Lower both s and f equally"],a:0,tag:"steady_state_unemployment",type:"policy",objective:"LO7.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"misses_direction_of_flow_policy",feedback:"Lower job separation and higher job finding both reduce steady-state unemployment."},
{id:378,sourceGame:"nationalEngine",q:"A retraining program shortens job search for displaced workers but does not affect layoffs. Which parameter changes first?",options:["f rises","s rises","s falls","L falls"],a:0,tag:"job_finding",type:"policy",objective:"LO7.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"job_finding_job_separation_logic",secondarySkills:["sectoral_shift_matching"],repairSkill:"job_finding_job_separation_logic",commonError:"confuses_finding_rate_with_separation_rate",feedback:"Retraining and matching programs help unemployed workers find jobs faster, raising f."},
{id:379,sourceGame:"nationalEngine",q:"A 100% experience-rated unemployment insurance system makes firms bear more layoff costs. Which parameter is targeted?",options:["s falls","f falls","u rises by formula","L becomes fixed"],a:0,tag:"job_separation",type:"policy",objective:"LO7.2",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"job_finding_job_separation_logic",secondarySkills:[],repairSkill:"job_finding_job_separation_logic",commonError:"confuses_layoff_incentive_with_job_finding",feedback:"Experience rating raises the cost of layoffs for firms, targeting a lower separation rate s."},
{id:380,sourceGame:"nationalEngine",q:"A laid-off worker rejects the first available job to search for a better match. Which interpretation is strongest?",options:["This can raise frictional unemployment but may improve match quality","This is structural unemployment caused by a wage floor","This is always cyclical unemployment from low spending","This removes the worker from the labor force immediately"],a:0,tag:"frictional_unemployment",type:"application",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"ui_and_job_search_incentives",secondarySkills:["frictional_vs_other_unemployment"],repairSkill:"ui_and_job_search_incentives",commonError:"treats_search_as_purely_bad_or_structural",feedback:"Search can increase frictional unemployment duration, but it can also help workers find better matches."},
{id:381,sourceGame:"nationalEngine",q:"Refer to the minimum wage graph. If a wage floor is below equilibrium, what is the likely unemployment effect in that market?",options:["No binding structural unemployment from the floor","A labor surplus from the wage floor","A labor shortage from the wage floor","Immediate elimination of frictional unemployment"],a:0,tag:"minimum_wage",type:"graph_interpretation",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:[],repairSkill:"minimum_wage_structural_unemployment",commonError:"treats_all_minimum_wages_as_binding",feedback:"A wage floor below equilibrium is not binding and does not create structural unemployment in that market.",image:"minimumwage.webp"},
{id:382,sourceGame:"nationalEngine",q:"A wage floor is above equilibrium. Which group is most directly rationed out of jobs?",options:["Workers willing to work at the equilibrium wage but unable to get hired","Firms willing to hire more at the higher wage","Consumers buying imported goods","Capital owners receiving rental income"],a:0,tag:"minimum_wage",type:"application",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"minimum_wage_structural_unemployment",commonError:"confuses_labor_supply_surplus_with_labor_demand_shortage",feedback:"When wages are held above equilibrium, more workers want jobs than firms want to hire, so some workers are rationed out."},
{id:383,sourceGame:"nationalEngine",q:"A union wage premium benefits insiders but reduces job openings for outsiders. What policy tradeoff should be noted?",options:["Higher wages for some can reduce access for others","Higher wages always increase employment","Union wages only affect CPI measurement","Outsiders are protected by the same wage premium"],a:0,tag:"unions",type:"policy",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"union_wage_rigidity",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"union_wage_rigidity",commonError:"ignores_insider_outsider_tradeoff",feedback:"Union wage gains for insiders can come with fewer jobs available to outsiders when wages exceed market-clearing levels."},
{id:384,sourceGame:"nationalEngine",q:"A firm pays above-market wages because replacing trained workers is expensive. Which efficiency wage channel is this?",options:["Lower turnover","Better nutrition","Higher CPI accuracy","Public saving"],a:0,tag:"efficiency_wages",type:"application",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"efficiency_wage_theory",secondarySkills:[],repairSkill:"efficiency_wage_theory",commonError:"misses_turnover_channel",feedback:"Paying higher wages can reduce turnover when hiring and training replacements is costly."},
{id:385,sourceGame:"nationalEngine",q:"A firm pays above-market wages because workers cannot be perfectly monitored. Which problem is the firm addressing?",options:["Moral hazard","Substitution bias","Crowding out","GDP double counting"],a:0,tag:"efficiency_wages",type:"application",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"efficiency_wage_theory",secondarySkills:[],repairSkill:"efficiency_wage_theory",commonError:"confuses_moral_hazard_with_adverse_selection",feedback:"When effort cannot be perfectly monitored, workers may shirk; higher wages can reduce that moral hazard."},
{id:386,sourceGame:"nationalEngine",q:"A firm pays high wages to attract better applicants before observing worker quality. Which problem is closest?",options:["Adverse selection","Moral hazard","CPI bias","Public deficit"],a:0,tag:"efficiency_wages",type:"application",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"efficiency_wage_theory",secondarySkills:[],repairSkill:"efficiency_wage_theory",commonError:"confuses_adverse_selection_with_moral_hazard",feedback:"When worker quality is hard to observe before hiring, high wages can attract better applicants, addressing adverse selection."},
{id:387,sourceGame:"nationalEngine",q:"Fifty short-term workers are unemployed for 3 weeks each; five long-term workers are unemployed for 45 weeks each. What share of unemployment weeks is long-term?",options:["60%","10%","40%","75%"],a:0,tag:"unemployment_duration",type:"calculation",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"unemployment_duration_calculation",secondarySkills:[],repairSkill:"unemployment_duration_calculation",commonError:"uses_people_share_instead_of_weeks_share",feedback:"Short-term weeks = 150. Long-term weeks = 225. Long-term share = 225/375 = 60%."},
{id:388,sourceGame:"nationalEngine",q:"A policy expands UI benefits but also requires verified job search and provides placement services. What is the best assessment?",options:["The net effect on frictional unemployment depends on search incentives and matching gains","Frictional unemployment must rise because UI exists","Frictional unemployment must fall because placement exists","Structural unemployment must become zero"],a:0,tag:"unemployment_insurance",type:"policy",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"ui_and_job_search_incentives",secondarySkills:["sectoral_shift_matching"],repairSkill:"ui_and_job_search_incentives",commonError:"treats_ui_effect_as_one_direction_only",feedback:"UI can reduce urgency to accept jobs, but search requirements and placement services can improve matching, so the net effect depends on design."},
{id:389,sourceGame:"nationalEngine",q:"Which case is structural rather than frictional unemployment?",options:["A wage set above equilibrium leaves qualified workers unable to get jobs","A worker searches two weeks for a better job match","A new graduate compares offers across cities","A worker relocates after a sectoral shift"],a:0,tag:"structural_unemployment",type:"trap",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"frictional_vs_other_unemployment",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"frictional_vs_other_unemployment",commonError:"confuses_search_with_wage_rigidity",feedback:"Structural unemployment comes from wage rigidity and job rationing, not ordinary search and matching time."},
{id:390,sourceGame:"nationalEngine",q:"A city raises the minimum wage and firms reduce nonwage benefits. What does this show?",options:["Adjustment can occur through compensation margins besides headcount","The wage floor was not binding by definition","Structural unemployment must disappear","The CPI excludes labor costs"],a:0,tag:"minimum_wage",type:"policy",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:[],repairSkill:"minimum_wage_structural_unemployment",commonError:"looks_only_at_job_count_effect",feedback:"Labor-cost policy effects can show up through hours, hiring, benefits, prices, and job availability."},
{id:391,sourceGame:"nationalEngine",q:"An advisor wants to reduce frictional unemployment from sectoral shifts. Which package fits best?",options:["Job information, retraining, and relocation support","Higher wage floors and stricter union entry","Lower CPI weights and higher GDP deflator","Higher public deficits and lower saving"],a:0,tag:"frictional_unemployment",type:"policy",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"sectoral_shift_matching",secondarySkills:[],repairSkill:"sectoral_shift_matching",commonError:"chooses_structural_policy_for_matching_problem",feedback:"Frictional unemployment from sectoral shifts is reduced by improving worker-job matching and mobility."},
{id:392,sourceGame:"nationalEngine",q:"A worker is part time because full-time work is unavailable. Which broader measure captures this better than U-3?",options:["U-6","GDP deflator","CPI-U only","Natural rate formula"],a:0,tag:"labor_underutilization",type:"identification",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"labor_underutilization_classification",secondarySkills:[],repairSkill:"labor_underutilization_classification",commonError:"misses_part_time_for_economic_reasons_in_u6",feedback:"U-6 includes unemployed, marginally attached workers, and those working part time for economic reasons."},
{id:393,sourceGame:"nationalEngine",q:"If discouraged workers begin searching again before finding jobs, what happens to U-3 unemployment at first?",options:["It rises because they reenter unemployment","It falls because they are optimistic","It is unchanged because they are still jobless","It becomes U-6 automatically"],a:0,tag:"discouraged_workers",type:"application",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"labor_underutilization_classification",secondarySkills:["employment_status_classification"],repairSkill:"labor_underutilization_classification",commonError:"misses_reentry_into_labor_force",feedback:"When discouraged workers resume searching, they reenter the labor force as unemployed, raising U-3 initially."},
{id:394,sourceGame:"nationalEngine",q:"A policy raises wages above equilibrium to reduce turnover, but some applicants cannot get jobs. What tradeoff is present?",options:["Efficiency gains may come with structural unemployment","CPI accuracy may come with lower GDP","Higher imports may come with lower exports","Real GDP may come with nominal GDP"],a:0,tag:"efficiency_wages",type:"policy",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"efficiency_wage_theory",secondarySkills:["wage_rigidity_structural_unemployment"],repairSkill:"efficiency_wage_theory",commonError:"ignores_job_rationing_from_above_equilibrium_wages",feedback:"Efficiency wages can improve productivity or retention, but above-equilibrium wages can also ration jobs."},
{id:395,sourceGame:"nationalEngine",q:"Which explanation best links sectoral shifts and unemployment duration?",options:["Repeated shifts can lengthen search when skills and locations no longer match openings","Repeated shifts eliminate job search because workers move instantly","Repeated shifts create only CPI inflation","Repeated shifts lower unemployment by raising wage rigidity"],a:0,tag:"sectoral_shifts",type:"application",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"sectoral_shift_matching",secondarySkills:["unemployment_duration_calculation"],repairSkill:"sectoral_shift_matching",commonError:"misses_skill_location_matching_delay",feedback:"Sectoral shifts change where and what jobs exist, creating matching problems that can lengthen unemployment spells."},
{id:396,sourceGame:"nationalEngine",q:"A worker loses a job in a recession, but the wage in their industry is also held above equilibrium by contract. Which answer is most careful?",options:["Both cyclical and structural forces may be present","Only frictional unemployment can be present","The worker cannot be unemployed officially","The case belongs only to CPI bias"],a:0,tag:"unemployment_types",type:"integration",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"frictional_vs_other_unemployment",secondarySkills:["union_wage_rigidity"],repairSkill:"frictional_vs_other_unemployment",commonError:"forces_single_unemployment_type_when_multiple_apply",feedback:"A recession can create cyclical unemployment, while wage rigidity can create structural unemployment at the same time."},
{id:397,sourceGame:"nationalEngine",q:"Which policy could reduce separations without mainly raising job finding?",options:["Experience-rated UI that makes layoffs more costly for firms","A job board that improves vacancy information","Relocation support for displaced workers","A faster application matching platform"],a:0,tag:"job_separation",type:"policy",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"job_finding_job_separation_logic",secondarySkills:["ui_and_job_search_incentives"],repairSkill:"job_finding_job_separation_logic",commonError:"confuses_f_policy_with_s_policy",feedback:"Experience rating changes firms’ incentives to lay off workers, targeting the separation rate."},
{id:398,sourceGame:"nationalEngine",q:"A minimum wage hike reduces turnover among employed workers but reduces hiring of new workers. What is the best assessment?",options:["The policy can improve retention while worsening job rationing","The policy must reduce all structural unemployment","The policy has no labor-market tradeoffs","The policy affects only the CPI basket"],a:0,tag:"minimum_wage",type:"policy",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"minimum_wage_structural_unemployment",secondarySkills:["efficiency_wage_theory"],repairSkill:"minimum_wage_structural_unemployment",commonError:"ignores_multiple_labor_market_margins",feedback:"Higher wages can reduce turnover for employed workers while reducing hiring opportunities for others."},
{id:399,sourceGame:"nationalEngine",q:"A labor-market dashboard shows U-3 falling while U-6 stays high. What is the best warning?",options:["Official unemployment may miss underemployment and marginal attachment","GDP must be overstating output","CPI must be understating imports","Investment demand must be vertical"],a:0,tag:"labor_underutilization",type:"interpretation",objective:"LO7.3",difficulty:"elite",conceptCluster:"national_engine_elite",primarySkill:"labor_underutilization_classification",secondarySkills:["employment_status_classification"],repairSkill:"labor_underutilization_classification",commonError:"treats_u3_as_complete_labor_slack_measure",feedback:"U-3 can improve while broader labor underutilization remains elevated through marginal attachment or part-time work for economic reasons."}
]	
};

