    { id:6059, sourceGame:"nationalEngine", q:"A sectoral shift creates available jobs, but workers lack the needed skills. Why can unemployment still persist?", options:["Matching takes time when skills and jobs differ","Jobs existing somewhere instantly ends unemployment","The CPI excludes workers","GDP must fall by the number unemployed"], a:0, tag:"sectoral_shifts", type:"diagnostic", objective:"LO7.3", difficulty:"bridge", conceptCluster:"bridge_chapter_7", primarySkill:"sectoral_shift_matching", repairSkill:"sectoral_shift_matching", commonError:"misses_matching_delay", feedback:"Workers and jobs may not match by skill, location, or timing." }
